-- Schema for Domain: event | Business: Sports Entertainment | Version: v1_ecm
-- Generated on: 2026-05-09 01:42:55

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `sports_entertainment_ecm`.`event` COMMENT 'Core operational domain managing the full lifecycle of live sports and entertainment events — planning, scheduling, production logistics, competition governance, and game-day execution. Owns event identity, fixture calendars, match results, season structures, tournament brackets, and event lifecycle from announcement through post-event reconciliation. Serves as SSOT for all event-related master data across leagues, concerts, and live experiences.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`fixture` (
    `fixture_id` BIGINT COMMENT 'Unique surrogate identifier for the fixture record. Primary key for the event.fixture data product and anchor reference for all downstream domains including ticketing, broadcast, sponsorship, and content.',
    `away_team_franchise_id` BIGINT COMMENT 'Reference to the visiting team or secondary performing entity for this fixture. Nullable for non-competitive events such as concerts or award ceremonies.',
    `broadcast_channel_id` BIGINT COMMENT 'Reference to the primary broadcast network or OTT platform assigned to carry this fixture under media rights agreements. Links to broadcast domain for RSN, national network, and streaming rights activation.',
    `channel_id` BIGINT COMMENT 'Reference to the primary broadcast network or OTT platform assigned to carry this fixture under media rights agreements. Links to broadcast domain for RSN, national network, and streaming rights activation.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Fixtures incur direct operational costs (staffing, security, production) allocated to cost centers. Finance teams require fixture-to-cost-center linkage for operational cost tracking, budget variance ',
    `event_type_id` BIGINT COMMENT 'Foreign key linking to event.event_type. Business justification: Fixture currently has event_type as STRING column. The event_type reference table exists with event_type_id PK and contains code, name, description, category, format attributes. This is a classic refe',
    `fixture_away_team_franchise_id` BIGINT COMMENT 'Reference to the visiting team or secondary performing entity for this fixture. Nullable for non-competitive events such as concerts or award ceremonies.',
    `fixture_franchise_id` BIGINT COMMENT 'Reference to the home team or primary performing entity for this fixture. Used for scheduling, standings calculation, and home/away revenue split logic in SAP S/4HANA FI/CO.',
    `franchise_id` BIGINT COMMENT 'Reference to the home team or primary performing entity for this fixture. Used for scheduling, standings calculation, and home/away revenue split logic in SAP S/4HANA FI/CO.',
    `league_id` BIGINT COMMENT 'Reference to the league or governing competition body responsible for this fixture (e.g., NFL, NBA, MLS, FIFA). Drives compliance reporting to governing bodies and broadcast rights distribution rules.',
    `league_schedule_id` BIGINT COMMENT 'Foreign key linking to league.schedule. Business justification: Fixture-to-schedule mapping is fundamental for game-day operations, broadcast slot allocation, and schedule compliance reporting. League operations teams must reconcile official schedule entries again',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Finance teams classify each fixture against a primary revenue stream (gate, broadcast, PPV) for revenue forecasting, actuals tracking, and ARR reporting. Role-prefixed primary_ because fixtures gene',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Fixtures are the primary profit-generating events in sports entertainment. Finance teams track per-fixture P&L through profit centers for event-level profitability reporting, management accounts, and ',
    `regulatory_license_id` BIGINT COMMENT 'Foreign key linking to legal.regulatory_license. Business justification: Each fixture must be conducted under a valid regulatory license (venue operating permit, broadcast license). Compliance teams verify license validity per fixture before event day. A sports-entertainme',
    `season_id` BIGINT COMMENT 'Reference to the season or competition year to which this fixture belongs. Links the fixture to its governing season structure for standings, scheduling, and league governance reporting.',
    `sla_policy_id` BIGINT COMMENT 'Foreign key linking to platform.sla_policy. Business justification: Broadcast-critical fixtures (is_broadcast_eligible, is_ppv) require a designated platform SLA policy governing uptime and CDN failover during live events. Platform ops teams assign SLA policies per fi',
    `tax_jurisdiction_id` BIGINT COMMENT 'Foreign key linking to finance.tax_jurisdiction. Business justification: Fixtures occur in specific jurisdictions subject to entertainment taxes, jock taxes, and ticket sales taxes. Finance teams apply jurisdiction-specific rates (entertainment_tax_rate_pct, jock_tax_rate_',
    `tournament_id` BIGINT COMMENT 'Reference to the tournament or bracket structure this fixture belongs to, if applicable (e.g., FIFA World Cup knockout bracket, NBA Playoffs bracket). Nullable for regular season fixtures.',
    `venue_id` BIGINT COMMENT 'Reference to the primary venue where the fixture is scheduled to take place. Links to venue master data for capacity, seating inventory (Archtics), ADA compliance, OSHA safety checks, and HVAC/BMS operational readiness.',
    `wbs_element_id` BIGINT COMMENT 'Foreign key linking to finance.wbs_element. Business justification: Each fixture is tracked as a WBS element in SAP project accounting for production cost capture, post-event financial reconciliation, and budget variance reporting. Sports entertainment finance teams r',
    `actual_attendance` STRING COMMENT 'Verified count of attendees who physically entered the venue for this fixture, reconciled from gate scan data in Ticketmaster/AXS. Used for KPI reporting, revenue reconciliation, and league governance submissions.',
    `actual_end_timestamp` TIMESTAMP COMMENT 'The real-world date and time the fixture actually concluded. Used for broadcast rights window compliance, overtime/extra-time tracking, and venue operations post-event reconciliation.',
    `actual_start_timestamp` TIMESTAMP COMMENT 'The real-world date and time the fixture actually commenced. Populated post-event for reconciliation, broadcast rights compliance reporting, and performance analytics in SportsCode/Hudl.',
    `announced_timestamp` TIMESTAMP COMMENT 'Date and time when the fixture was officially announced to the public. Marks the start of the fixture lifecycle and triggers fan engagement and ticketing on-sale countdown workflows in Adobe Experience Platform.',
    `attendance_capacity` STRING COMMENT 'Maximum approved attendance capacity for this specific fixture, which may differ from the venues total capacity due to configuration, safety restrictions, or event-specific setup. Used for ticketing inventory management in Archtics and ADA compliance reporting.',
    `away_score` STRING COMMENT 'Final score or result for the away team or secondary competitor at the conclusion of the fixture. Populated post-event. Nullable for non-competitive events.',
    `cancelled_timestamp` TIMESTAMP COMMENT 'Date and time when the fixture was officially cancelled or abandoned. Triggers refund processing workflows in Ticketmaster/AXS and revenue reversal entries in SAP S/4HANA FI.',
    `confirmed_timestamp` TIMESTAMP COMMENT 'Date and time when the fixture was confirmed by the governing body or event organizer, transitioning from announced to confirmed status. Triggers ticketing on-sale activation in Ticketmaster/AXS and broadcast rights activation.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when the fixture record was first created in the data platform. Audit trail field for data governance, SOX (Sarbanes-Oxley Act) financial controls, and GDPR data lineage compliance.',
    `doors_open_timestamp` TIMESTAMP COMMENT 'Scheduled date and time when venue gates open to ticket holders. Critical for access control configuration in Ticketmaster/AXS gate scan systems and fan arrival experience planning.',
    `event_classification` STRING COMMENT 'Competition or programming classification of the fixture indicating its governing framework (e.g., league regular season match, cup knockout tie, friendly/exhibition, touring concert). Used for league governance reporting and CBA compliance.. Valid values are `league|cup|friendly|touring|invitational|charity`',
    `event_date` DATE COMMENT 'Calendar date of the fixture in the local venue timezone, stored as a DATE for day-level planning, fixture calendar display, and season schedule reporting. Distinct from the precise scheduled_start_timestamp used for operational systems.',
    `event_tier` STRING COMMENT 'Competitive tier or significance level of the fixture within its season or tournament structure. Determines pricing strategy, broadcast rights activation, and sponsorship inventory allocation. Drives dynamic pricing rules in Ticketmaster/AXS.. Valid values are `regular_season|playoff|championship|special_event|preseason|postseason`',
    `extra_time_played` BOOLEAN COMMENT 'Indicates whether the fixture required extra time or overtime periods beyond regulation. Affects broadcast window compliance, venue operations scheduling, and revenue reconciliation for extended event durations.',
    `fixture_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the fixture, used in operational systems such as Ticketmaster/AXS, Archtics, and SAP S/4HANA SD. Serves as the cross-system reference key for event scheduling and revenue management workflows.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `fixture_name` STRING COMMENT 'Official human-readable name of the fixture as published to fans, broadcasters, and sponsors (e.g., NBA Finals Game 7, UFC 300, FIFA World Cup Final). Used in ticketing, broadcast schedules, and fan engagement platforms.',
    `home_score` STRING COMMENT 'Final score or result for the home team or primary competitor at the conclusion of the fixture. Populated post-event. Used for standings calculation, WAR (Wins Above Replacement) analytics, and league governance reporting.',
    `is_broadcast_eligible` BOOLEAN COMMENT 'Indicates whether this fixture is eligible for broadcast distribution under existing media rights agreements. Drives activation of broadcast workflows in Dalet Galaxy and content rights management.',
    `is_neutral_site` BOOLEAN COMMENT 'Indicates whether the fixture is played at a neutral venue with no designated home team advantage. Affects revenue sharing agreements, ticketing allocation rules, and broadcast designation.',
    `is_ppv` BOOLEAN COMMENT 'Indicates whether this fixture is designated as a Pay-Per-View (PPV) event requiring individual purchase for broadcast access. Triggers PPV pricing and DTC distribution workflows in OTT platforms.',
    `leg_number` STRING COMMENT 'Leg sequence number for two-legged ties or multi-game series (e.g., Leg 1, Leg 2 of a UEFA tie; Game 3 of an NBA playoff series). Nullable for single-leg fixtures.',
    `lifecycle_status` STRING COMMENT 'Current operational state of the fixture within its lifecycle workflow from initial announcement through post-event reconciliation. Governs downstream system activations: ticketing goes on-sale at confirmed, broadcast feeds activate at in_progress, revenue reconciliation triggers at completed.. Valid values are `announced|confirmed|in_progress|completed|cancelled|postponed`',
    `local_timezone` STRING COMMENT 'IANA timezone identifier for the venues local timezone (e.g., America/New_York, Europe/London). Required for accurate local time display in fan-facing platforms, broadcast scheduling, and ticket delivery.. Valid values are `^[A-Za-z]+/[A-Za-z_]+$`',
    `matchday_number` STRING COMMENT 'Sequential matchday or game week number within the season or competition phase (e.g., Matchday 1, Week 12). Used for fixture calendar display, standings calculation, and broadcast scheduling.',
    `penalty_shootout` BOOLEAN COMMENT 'Indicates whether the fixture was decided by a penalty shootout or tiebreaker procedure. Used for competition result reporting and broadcast content tagging in Dalet Galaxy.',
    `result_status` STRING COMMENT 'Official outcome classification of the fixture as determined by the governing body. Distinct from lifecycle_status — this captures the competitive result rather than the operational state. Used for standings, CAS (Court of Arbitration for Sport) appeals, and league governance.. Valid values are `home_win|away_win|draw|void|awarded|abandoned`',
    `round_name` STRING COMMENT 'Descriptive name of the competition round or stage for this fixture (e.g., Quarter-Final, Semi-Final, Wild Card Round, Conference Championship). Used in fan-facing communications and broadcast graphics.',
    `scheduled_end_timestamp` TIMESTAMP COMMENT 'Planned end date and time of the fixture in UTC. Used for broadcast window allocation, venue turnaround scheduling, and post-event reconciliation triggers in SAP S/4HANA.',
    `scheduled_start_timestamp` TIMESTAMP COMMENT 'The principal real-world scheduled date and time when the fixture is planned to begin, stored in UTC with timezone offset. Used as the primary business event timestamp for broadcast scheduling, ticketing on-sale windows, and fan engagement notifications via Adobe Experience Platform.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this fixture record originated (e.g., Ticketmaster/AXS, Archtics, SAP S/4HANA SD, or league data feed). Supports data lineage tracking and Silver Layer reconciliation in the Databricks Lakehouse.. Valid values are `TICKETMASTER|ARCHTICS|SAP_SD|MANUAL|LEAGUE_FEED`',
    `surface_type` STRING COMMENT 'Type of playing surface used for this fixture. Relevant for athlete injury risk management, CBA (Collective Bargaining Agreement) surface compliance requirements, and performance analytics. [ENUM-REF-CANDIDATE: natural_grass|artificial_turf|hardwood|ice|clay|grass|carpet — 7 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp when the fixture record was last modified. Required for incremental data pipeline processing in the Databricks Silver Layer and audit trail compliance under SOX.',
    `var_used` BOOLEAN COMMENT 'Indicates whether Video Assistant Referee (VAR) or equivalent video review technology (e.g., TMO in rugby) was deployed during this fixture. Required for competition governance reporting and broadcast production metadata.',
    `weather_condition` STRING COMMENT 'Recorded weather condition at the venue during the fixture. Used for performance analytics in SportsCode/Hudl, insurance claims, and post-event operational reporting. indoor applies to enclosed venues. [ENUM-REF-CANDIDATE: clear|cloudy|rain|snow|fog|extreme_heat|indoor — 7 candidates stripped; promote to reference product]',
    CONSTRAINT pk_fixture PRIMARY KEY(`fixture_id`)
) COMMENT 'Core master entity and SSOT for event identity — any scheduled live sports or entertainment event. Captures event name, type (match, concert, PPV, exhibition, all-star, draft, awards), status (announced → confirmed → in-progress → completed/cancelled), scheduled date/time with timezone, doors-open time, event tier (regular season, playoff, championship, special event), home/away designation, neutral site flag, broadcast eligibility flag, classification (league, cup, friendly, touring), and lifecycle timestamps. Anchor entity referenced by all downstream domains.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`calendar` (
    `calendar_id` BIGINT COMMENT 'Unique surrogate identifier for the event calendar / season record. Primary key for this entity in the Silver Layer lakehouse.',
    `calendar_governing_body_id` BIGINT COMMENT 'Reference to the sanctioning or governing body (e.g., FIFA, NFL, NBA, IOC) that has jurisdiction over this season and its fixture calendar.',
    `calendar_scheduling_authority_governing_body_id` BIGINT COMMENT 'Reference to the organisational unit or external body responsible for publishing and maintaining the official fixture schedule for this season.',
    `cba_agreement_id` BIGINT COMMENT 'Foreign key linking to league.cba_agreement. Business justification: Season event calendars are governed by CBA provisions on scheduling, international windows, and player rest. Normalizing cba_reference_code to a proper FK enables CBA compliance reporting at the calen',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: Season calendars are governed by CBA obligations, WADA compliance requirements, and broadcast regulatory obligations. event_calendar has cba_applicable and wada_compliance_required flags. This FK link',
    `governance_document_id` BIGINT COMMENT 'Foreign key linking to legal.governance_document. Business justification: Season calendars are published under CBA and league constitution authority. event_calendar has cba_applicable and cba_reference_code fields indicating this relationship. Legal teams need direct tracea',
    `governing_body_id` BIGINT COMMENT 'Reference to the organisational unit or external body responsible for publishing and maintaining the official fixture schedule for this season.',
    `league_id` BIGINT COMMENT 'Reference to the league or entertainment series that owns this season calendar. Links to the league master entity.',
    `blackout_dates` STRING COMMENT 'Comma-separated list of specific dates on which no fixtures may be scheduled due to regulatory, contractual, or operational constraints (e.g., broadcast blackout windows, public holidays, conflicting major events). Enforced by the scheduling authority.',
    `broadcast_rights_region` STRING COMMENT 'Primary geographic region or market for which broadcast rights have been assigned for this season (e.g., USA, GBR, GLOBAL). Drives RSN, OTT, and IPTV distribution logic in Dalet Galaxy and content rights management.',
    `bye_weeks` STRING COMMENT 'Comma-separated list of round/week numbers designated as bye weeks (no fixtures scheduled). Relevant primarily for NFL and similar league formats. Used by broadcast schedulers in Dalet Galaxy to fill programming gaps and by venue operations for maintenance windows.',
    `calendar_status` STRING COMMENT 'Current publication status of the fixture calendar. Controls downstream visibility and consumption: draft is internal only; published is the official release to broadcast, ticketing, and venue operations; amended indicates a post-publication revision; suspended indicates a temporary halt; archived is end-of-life.. Valid values are `draft|published|amended|suspended|archived`',
    `cba_applicable` BOOLEAN COMMENT 'Indicates whether the season schedule is governed by an active Collective Bargaining Agreement (CBA) between the league and players association. When true, CBA constraints on game counts, rest days, and travel windows must be validated against the fixture calendar.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this event calendar record was first created in the Silver Layer lakehouse. Supports audit trail, data lineage, and SOX financial controls compliance.',
    `gdpr_applicable` BOOLEAN COMMENT 'Indicates whether GDPR data privacy obligations apply to fan and participant data collected during this season, based on the host country and market reach. When true, data processing activities must comply with GDPR Articles 5-7 and fan consent management in Adobe Experience Platform.',
    `has_playoff_structure` BOOLEAN COMMENT 'Indicates whether this season includes a post-season playoff or knockout tournament phase beyond the regular season. When true, playoff-specific broadcast rights, ticketing tiers, and venue contracts are activated.',
    `host_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the primary host nation for this season (e.g., USA, GBR, FRA). Determines applicable regulatory frameworks (GDPR, CCPA, local tax), venue safety standards (OSHA, ADA), and broadcast licensing requirements (FCC).. Valid values are `^[A-Z]{3}$`',
    `international_window_dates` STRING COMMENT 'Comma-separated list of date ranges reserved for international competition windows (e.g., FIFA international breaks, Olympic qualifying periods) during which domestic league fixtures are suspended. Critical for fixture scheduling compliance with FIFA and IOC calendars.',
    `is_international_season` BOOLEAN COMMENT 'Indicates whether this season includes fixtures played in multiple countries or international markets. When true, multi-jurisdiction regulatory compliance (GDPR, local broadcast licensing, visa/work permit requirements) is triggered.',
    `notes` STRING COMMENT 'Free-text field for operational notes, scheduling caveats, or amendment reasons associated with this season calendar record (e.g., Schedule amended due to venue unavailability in Week 7, Shortened season per CBA force majeure clause). Supports audit trail and change management.',
    `number_of_participating_teams` STRING COMMENT 'Total count of teams, clubs, or acts participating in this season. Used for fixture generation, venue capacity planning in Archtics, and broadcast slot allocation. For concert series, represents the number of performing acts.',
    `playoff_format_description` STRING COMMENT 'Narrative description of the playoff bracket or knockout structure (e.g., Single-elimination 12-team bracket, Best-of-7 series, 16 teams). Supports broadcast production planning and fan engagement content in Adobe Experience Platform.',
    `playoff_start_date` DATE COMMENT 'Scheduled start date of the post-season playoff phase. Null if has_playoff_structure is false. Used to define the playoff broadcast rights window and premium ticketing on-sale dates in Ticketmaster/AXS.',
    `publication_date` DATE COMMENT 'The official date on which the fixture calendar was publicly released by the scheduling authority. Triggers downstream on-sale windows in Ticketmaster/AXS and broadcast scheduling in Dalet Galaxy.',
    `season_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this season within the league or series (e.g., NFL-2024-REG, NBA-2024-25). Used as the business key in integrations with SAP S/4HANA, Ticketmaster/AXS, and Archtics.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `season_end_date` DATE COMMENT 'Official end date of the competitive or programming season, inclusive of any playoff or championship rounds. Defines the effective-until boundary for broadcast rights, venue contracts, and sponsorship activation periods.',
    `season_format` STRING COMMENT 'Structural format of the season indicating whether it follows the standard schedule length or a modified format (e.g., shortened due to CBA disputes or COVID, expanded due to league growth). Critical for CBA compliance tracking and broadcast rights valuation.. Valid values are `regular|shortened|expanded|exhibition|special`',
    `season_name` STRING COMMENT 'Human-readable name of the season or programming series (e.g., NFL 2024-25 Regular Season, UEFA Champions League 2024-25, Summer Concert Series 2025). Serves as the primary display label for downstream broadcast, ticketing, and fan-facing systems.',
    `season_phase` STRING COMMENT 'Current active phase of the season lifecycle. Drives phase-specific business rules across ticketing (Ticketmaster/AXS), broadcast (Dalet Galaxy), and venue operations. pre_season = warm-up fixtures; regular_season = main competition; post_season = playoffs/finals; off_season = between seasons.. Valid values are `pre_season|regular_season|post_season|off_season`',
    `season_start_date` DATE COMMENT 'Official start date of the competitive or programming season as published by the governing body. Used as the effective-from boundary for broadcast rights windows, ticketing on-sale periods, and venue booking calendars.',
    `season_status` STRING COMMENT 'Operational lifecycle state of the season itself (distinct from calendar publication status). planning = pre-season setup; active = season in progress; completed = all fixtures concluded; cancelled = season abandoned; suspended = temporarily halted (e.g., force majeure, labour dispute).. Valid values are `planning|active|completed|cancelled|suspended`',
    `season_year` STRING COMMENT 'The primary calendar year associated with this season (e.g., 2025). For multi-year seasons (e.g., 2024-25), this represents the start year. Used for year-over-year reporting and financial period alignment in SAP S/4HANA FI/CO.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this season calendar record was ingested (e.g., SAP_S4HANA for SAP S/4HANA SD module, TICKETMASTER for Ticketmaster/AXS, ARCHTICS for Archtics venue seating). Supports data lineage and Silver Layer provenance tracking.. Valid values are `SAP_S4HANA|TICKETMASTER|ARCHTICS|MANUAL|OTHER`',
    `source_system_record_reference` STRING COMMENT 'The native primary key or record identifier of this season calendar record in the originating operational system (e.g., SAP S/4HANA season object ID, Archtics season ID). Enables reconciliation and bi-directional traceability between the lakehouse Silver Layer and source systems.',
    `sport_discipline` STRING COMMENT 'Specific sport or entertainment discipline for this season (e.g., American Football, Basketball, Soccer, Ice Hockey, Tennis, Concert Tour). Aligns with FIFA, NFL, NBA, NHL, MLS, ATP governing body classifications.',
    `sport_entertainment_type` STRING COMMENT 'High-level classification of the season content type, distinguishing competitive sports leagues from entertainment programming series (e.g., concerts, esports). Drives downstream routing to broadcast, ticketing, and venue operations workflows.. Valid values are `sport|concert|esports|mixed|other`',
    `sustainability_standard` STRING COMMENT 'Environmental sustainability standard applied to the management of this seasons events (e.g., ISO_20121 for ISO 20121 Event Sustainability Management Systems). Supports ESG reporting and venue operations compliance.. Valid values are `ISO_20121|none|other`',
    `tiebreaker_rules_reference` STRING COMMENT 'Reference code or document identifier for the official tiebreaker rules applicable to this seasons standings and playoff qualification (e.g., NFL-2024-TIEBREAK-v2, FIFA-RANKING-2024). Ensures consistent application of competition governance rules.',
    `total_scheduled_fixtures` STRING COMMENT 'Total number of individual fixtures (games, matches, events, shows) planned across the entire season. Drives capacity planning for ticketing inventory in Archtics and broadcast slot allocation in Dalet Galaxy.',
    `total_scheduled_rounds` STRING COMMENT 'Total number of competitive rounds, match weeks, or programming weeks planned for this season. For NFL this represents weeks; for soccer it represents match rounds; for concert series it represents show dates. Used for broadcast slot planning and revenue forecasting in Workday Adaptive Planning.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this event calendar record was most recently modified. Used to detect calendar amendments and trigger downstream notifications to broadcast, ticketing, and venue operations consumers.',
    `var_technology_enabled` BOOLEAN COMMENT 'Indicates whether Video Assistant Referee (VAR) or Television Match Official (TMO) technology is deployed for fixtures in this season. Affects broadcast production requirements, OB (Outside Broadcast) unit specifications, and officiating governance.',
    `version` STRING COMMENT 'Version identifier of the fixture calendar (e.g., v1.0, v2.3). Incremented each time the calendar is amended post-publication. Enables downstream consumers (broadcast, ticketing, venue) to detect and reconcile schedule changes.. Valid values are `^vd+.d+$`',
    `wada_compliance_required` BOOLEAN COMMENT 'Indicates whether WADA anti-doping testing protocols are mandated for this season. When true, athlete testing schedules and PED (Performance Enhancing Drug) compliance reporting obligations are activated for all participating athletes.',
    CONSTRAINT pk_calendar PRIMARY KEY(`calendar_id`)
) COMMENT 'Master entity defining a competitive or programming season within a league or entertainment series. Serves as the SSOT for season identity AND the official published fixture calendar/schedule. Captures season name, year, sport/entertainment type, start/end dates, number of scheduled rounds/weeks, playoff structure flag, season status (planning, active, completed), governing body reference, CBA applicability flag, season format (regular, shortened, expanded), calendar publication date, calendar version, scheduling authority, blackout dates, bye weeks, international window dates, and calendar status (draft, published, amended). Owns the official release of fixture schedules to downstream consumers including broadcast, ticketing, and venue operations.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`tournament` (
    `tournament_id` BIGINT COMMENT 'Unique surrogate identifier for the tournament record within the Sports Entertainment data platform. Primary key for the tournament master entity.',
    `budget_id` BIGINT COMMENT 'Foreign key linking this allocation record to the specific budget planning line in Workday Adaptive Planning / SAP CO. Enables budget-level tracking of which tournaments consume each budget line.',
    `calendar_id` BIGINT COMMENT 'Foreign key linking to event.event_calendar. Business justification: tournament is a master entity representing a structured competition format. While it already has a cross-domain season_id (league.season), the event_calendar is the event domains SSOT for the competi',
    `governance_document_id` BIGINT COMMENT 'Foreign key linking to legal.governance_document. Business justification: Tournament rules, eligibility criteria, and prize structures are defined in governance documents (tournament charters, league constitutions). Dispute resolution and eligibility challenges reference th',
    `governing_body_id` BIGINT COMMENT 'Foreign key linking to compliance.governing_body. Business justification: Tournaments are sanctioned and governed by specific governing bodies (FIFA, IOC, NBA, etc.). tournament.governing_body is a plain text denormalization of compliance.governing_body. This FK normalizes ',
    `league_id` BIGINT COMMENT 'Reference to the league or governing body that owns and sanctions this tournament (e.g., NBA, NFL, FIFA, UFC). Links to the league master entity.',
    `regulatory_license_id` BIGINT COMMENT 'Foreign key linking to legal.regulatory_license. Business justification: Tournaments require specific regulatory licenses (wagering, broadcast, venue operating). Tournament operations teams verify license coverage before scheduling and registration. Legal compliance requir',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Tournaments generate distinct revenue streams (broadcast rights, prize pool sponsorship, ticket sales). Finance teams track tournament-level revenue against specific revenue stream classifications for',
    `season_id` BIGINT COMMENT 'Reference to the competitive season within which this tournament is held. Enables association of tournament results to the broader season calendar.',
    `venue_id` BIGINT COMMENT 'Reference to the primary host venue for the tournament. For multi-venue tournaments, this represents the primary or final-stage venue.',
    `wbs_element_id` BIGINT COMMENT 'Foreign key linking to finance.wbs_element. Business justification: Tournaments are multi-event projects requiring dedicated WBS elements for prize pool management, production cost allocation, and sponsor activation cost tracking. Finance teams create tournament-level',
    `actuals_amount` DECIMAL(18,2) COMMENT 'Actual expenditure or revenue posted against this tournament from this budget line year-to-date. Sourced from detection phase relationship data. Enables tournament-level actuals tracking within the broader budget line.',
    `ada_compliance_status` STRING COMMENT 'ADA (Americans with Disabilities Act) accessibility compliance status for the tournaments venues and event operations. Required for US-hosted events and venue certification.. Valid values are `compliant|partial|non_compliant|under_review`',
    `age_category` STRING COMMENT 'Age classification bracket for tournament eligibility (e.g., Senior, Under-23, Under-18, Masters). Governs participant eligibility per CBA and governing body regulations. [ENUM-REF-CANDIDATE: senior|under_23|under_21|under_18|youth|masters|open — 7 candidates stripped; promote to reference product]',
    `announcement_date` DATE COMMENT 'Date on which the tournament was officially announced to the public and media. Marks the start of the tournament lifecycle for marketing, sponsorship, and fan engagement planning.',
    `broadcast_rights_type` STRING COMMENT 'Classification of broadcast rights arrangement for the tournament. Determines distribution channels, geo-restrictions, and revenue sharing models. PPV (Pay-Per-View) and OTT (Over-The-Top Streaming) rights have distinct monetization implications. [ENUM-REF-CANDIDATE: exclusive|non_exclusive|regional|global|ppv|ott|free_to_air — 7 candidates stripped; promote to reference product]',
    `budget_type` STRING COMMENT 'Classification of the budget allocation by expenditure category for this tournament: OPEX (operating expenditure such as staffing, marketing, production) or CAPEX (capital expenditure such as venue infrastructure). Sourced from detection phase relationship data.',
    `budget_version` STRING COMMENT 'Version label of the budget cycle applicable to this tournament allocation (e.g., Original, Revised, Q1 Reforecast, Q2 Reforecast). Sourced directly from the detection phase relationship data. Allows FP&A to compare allocation amounts across planning cycles for the same tournament.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the tournament record was first created in the Sports Entertainment data platform. Supports audit trail, data lineage, and SOX financial controls compliance.',
    `edition_number` STRING COMMENT 'Sequential edition or iteration number of the tournament (e.g., 23rd FIFA World Cup, 75th NBA Playoffs). Enables historical trend analysis and year-over-year performance comparisons.',
    `edition_year` STRING COMMENT 'Calendar year associated with this tournament edition (e.g., 2026 for FIFA World Cup 2026). Used as a human-readable identifier for the edition in reporting and fan-facing content.',
    `eligibility_criteria` STRING COMMENT 'Narrative description of participant eligibility requirements including nationality restrictions, ranking thresholds, qualification pathway requirements, and CBA compliance conditions.',
    `end_date` DATE COMMENT 'Official calendar date on which the tournament concludes (final match or closing ceremony). Used for broadcast rights expiry, venue release, and post-event reconciliation.',
    `external_code` STRING COMMENT 'Externally recognized unique code or identifier assigned by the governing body or data provider (e.g., FIFA tournament ID, Opta competition code). Used for data exchange and integration with third-party systems.',
    `format_type` STRING COMMENT 'Structural competition format that defines how participants advance through the tournament. Drives bracket logic, scheduling, and elimination rules. [ENUM-REF-CANDIDATE: single_elimination|double_elimination|round_robin|group_stage_knockout|multi_stage|league_playoff|swiss — promote to reference product if additional formats are needed]. Valid values are `single_elimination|double_elimination|round_robin|group_stage_knockout|multi_stage|league_playoff`',
    `gdpr_applicable` BOOLEAN COMMENT 'Indicates whether GDPR (General Data Protection Regulation) data privacy obligations apply to this tournament based on host country jurisdiction or EU participant data processing. Triggers fan data privacy controls in Adobe Experience Platform.',
    `gender_category` STRING COMMENT 'Gender classification of the tournament competition (e.g., Mens World Cup, Womens NBA). Required for scheduling, eligibility, and regulatory compliance with governing body rules.. Valid values are `mens|womens|mixed|open`',
    `host_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code of the primary host nation for the tournament (e.g., USA, BRA, FRA). Used for regulatory compliance, broadcast rights geo-restrictions, and tax jurisdiction.. Valid values are `^[A-Z]{3}$`',
    `host_region` STRING COMMENT 'Geographic region or confederation where the tournament is hosted (e.g., North America, Europe, Asia-Pacific). Used for broadcast rights distribution, regional sponsorship packages, and fan engagement targeting.',
    `notes` STRING COMMENT 'Free-text operational notes or remarks about the tournament, including special conditions, governing body directives, or event-specific exceptions not captured in structured fields.',
    `official_website_url` STRING COMMENT 'URL of the official tournament website used for fan engagement, media accreditation, and digital content distribution. Integrated with Adobe Experience Platform for fan personalization.. Valid values are `^https?://.+`',
    `planned_amount` DECIMAL(18,2) COMMENT 'The original planned budget amount allocated to this specific tournament from this budget line for the applicable fiscal period. Sourced from detection phase relationship data. Belongs to the allocation relationship, not the tournament or budget record alone.',
    `prize_pool_amount` DECIMAL(18,2) COMMENT 'Total monetary prize pool allocated for distribution to tournament participants and winners, expressed in the tournaments base currency. Used for financial planning, sponsor negotiations, and athlete contract compliance.',
    `prize_pool_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the prize pool amount (e.g., USD, EUR, GBP). Required for multi-currency financial reporting and SAP S/4HANA FI integration.. Valid values are `^[A-Z]{3}$`',
    `qualification_method` STRING COMMENT 'Primary method by which participants earn entry into the tournament (e.g., direct qualification via league standings, playoff qualifier, wild card selection, invitation by governing body, ranking points accumulation).. Valid values are `direct_qualification|playoff_qualifier|wild_card|invitation|ranking_points|regional_qualifier`',
    `recurrence_type` STRING COMMENT 'Frequency at which this tournament recurs (e.g., annual for NBA Playoffs, quadrennial for FIFA World Cup, one-time for special events). Supports long-range event planning and broadcast rights negotiation cycles.. Valid values are `annual|biennial|quadrennial|one_time|irregular`',
    `registration_deadline` DATE COMMENT 'Final date by which teams or athletes must complete registration and eligibility verification to participate in the tournament. Enforced per governing body regulations.',
    `revised_amount` DECIMAL(18,2) COMMENT 'The most recently approved revised budget amount allocated to this tournament after reforecast cycles. Sourced from detection phase relationship data. Reflects mid-cycle adjustments specific to this tournament-budget pairing.',
    `seeding_methodology` STRING COMMENT 'Method used to assign seeds and bracket positions to participants (e.g., ranking-based using WAR or QBR metrics, committee selection, random draw). Governs competitive fairness and bracket integrity.. Valid values are `ranking_based|performance_based|random_draw|committee_selected|hybrid`',
    `short_name` STRING COMMENT 'Abbreviated or commonly used name for the tournament used in broadcast graphics, digital platforms, and fan-facing displays (e.g., World Cup 2026, NBA Playoffs).',
    `social_media_hashtag` STRING COMMENT 'Official social media hashtag designated for the tournament (e.g., #WorldCup2026, #NBAPlayoffs). Used for fan engagement tracking, UGC (User Generated Content) monitoring, and NPS (Net Promoter Score) sentiment analysis.. Valid values are `^#[A-Za-z0-9_]+$`',
    `sport_type` STRING COMMENT 'The sport or entertainment discipline associated with this tournament (e.g., Football, Basketball, Mixed Martial Arts, Tennis, Concert Series). [ENUM-REF-CANDIDATE: football|basketball|baseball|ice_hockey|soccer|tennis|mma|golf|esports|concert — promote to reference product]',
    `start_date` DATE COMMENT 'Official calendar date on which the tournament competition begins (first match or opening ceremony). Used for scheduling, broadcast rights windows, and ticketing activation.',
    `sustainability_certified` BOOLEAN COMMENT 'Indicates whether the tournament has achieved or is pursuing ISO 20121 Event Sustainability Management System certification. Supports ESG reporting and sponsor sustainability commitments.',
    `ticket_sales_enabled` BOOLEAN COMMENT 'Indicates whether public ticket sales are enabled for this tournament. When false, the tournament may be closed-door, invitation-only, or broadcast-only. Drives Ticketmaster/AXS inventory activation.',
    `tiebreaker_rules` STRING COMMENT 'Description of the rules applied to resolve tied standings or scores within the tournament (e.g., head-to-head record, goal difference, penalty shootout, sudden death overtime). Governed by the sanctioning body.',
    `total_matches_scheduled` STRING COMMENT 'Total number of matches or games scheduled across all rounds of the tournament (e.g., 64 matches for FIFA World Cup group + knockout stages). Used for venue scheduling, broadcast slot planning, and officiating resource allocation.',
    `total_participants` STRING COMMENT 'Maximum number of teams or individual athletes eligible to compete in the tournament (e.g., 32 teams for FIFA World Cup, 16 teams for NBA Playoffs). Defines bracket size and seeding structure.',
    `total_rounds` STRING COMMENT 'Total number of competitive rounds or stages in the tournament bracket (e.g., 7 rounds for NBA Playoffs, 6 rounds for FIFA World Cup knockout stage). Drives bracket generation and scheduling logic.',
    `tournament_name` STRING COMMENT 'Official full name of the tournament as sanctioned by the governing body (e.g., FIFA World Cup 2026, NBA Playoffs 2025, UFC Championship Series Season 3).',
    `tournament_status` STRING COMMENT 'Current lifecycle state of the tournament from announcement through post-event reconciliation. Drives operational workflows, ticketing availability, and broadcast scheduling.. Valid values are `announced|registration_open|in_progress|completed|cancelled|postponed`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the tournament record. Used for change data capture, incremental ETL processing, and audit trail compliance.',
    `var_enabled` BOOLEAN COMMENT 'Indicates whether VAR (Video Assistant Referee) or TMO (Television Match Official) technology is deployed for officiating decisions during this tournament. Relevant for football, rugby, and other applicable sports.',
    `variance_explanation` STRING COMMENT 'Narrative explanation provided by the budget owner describing the reason for planned vs. actual variance for this specific tournament-budget allocation. Sourced from detection phase relationship data. Belongs to the allocation relationship as it contextualizes the financial delta at the tournament level.',
    `wada_compliance_required` BOOLEAN COMMENT 'Indicates whether WADA (World Anti-Doping Agency) anti-doping testing protocols are mandatory for this tournament. Triggers PED (Performance Enhancing Drug) testing workflows and athlete eligibility verification.',
    CONSTRAINT pk_tournament PRIMARY KEY(`tournament_id`)
) COMMENT 'Master entity representing a structured competition format — knockout brackets, round-robin groups, double elimination, or multi-stage tournaments (e.g., FIFA World Cup, NBA Playoffs, UFC Championship Series). Captures tournament name, format type, number of rounds, seeding methodology, host region, prize pool amount, governing body, eligibility criteria, start/end dates, and tournament status. Distinct from season as tournaments have defined bracket structures and elimination logic.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`bracket` (
    `bracket_id` BIGINT COMMENT 'Unique surrogate identifier for the tournament bracket record. Primary key for the bracket data product within the event domain.',
    `broadcast_rights_window_id` BIGINT COMMENT 'Reference to the broadcast rights agreement governing media distribution of this brackets competition. Links to OTT, RSN, and DTC distribution channels for rights management and FCC compliance.',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Bracket title sponsorship deal traceability: bracket already references sponsor_id but cannot look up contractual terms. A deal_id FK enables bracket sponsorship fulfillment tracking, broadcast integr',
    `eligibility_certification_id` BIGINT COMMENT 'Foreign key linking to compliance.eligibility_certification. Business justification: Tournament brackets require verified eligibility certifications before draw and seeding are locked. The bracket eligibility clearance process — confirming all entrants hold valid certifications befo',
    `league_id` BIGINT COMMENT 'Reference to the governing league or competition body that owns and administers this bracket. Links to league governance rules, CBA provisions, and regulatory reporting requirements.',
    `media_rights_deal_id` BIGINT COMMENT 'Reference to the broadcast rights agreement governing media distribution of this brackets competition. Links to OTT, RSN, and DTC distribution channels for rights management and FCC compliance.',
    `playoff_bracket_id` BIGINT COMMENT 'Foreign key linking to league.playoff_bracket. Business justification: Tournament brackets that implement league playoff structures must reference the authoritative league.playoff_bracket record. This link supports playoff bracket synchronization, seeding validation, and',
    `season_id` BIGINT COMMENT 'Reference to the league season or competition year in which this bracket is active. Enables season-over-season bracket comparison and historical analysis.',
    `sponsor_id` BIGINT COMMENT 'Reference to the primary presenting sponsor associated with this bracket (e.g., Presented by [Brand]). Links to sponsorship activation and inventory allocation for naming rights and on-screen branding.',
    `tournament_id` BIGINT COMMENT 'Reference to the parent tournament or competition event that this bracket belongs to. Links bracket structure to the governing event entity.',
    `venue_id` BIGINT COMMENT 'Reference to the primary venue or facility where this brackets competition is hosted. Used for venue operations planning, ADA compliance checks, and OSHA safety assessments.',
    `advancement_rule` STRING COMMENT 'Rule governing how participants advance from one round to the next within this bracket. Determines winner progression logic used to fill subsequent bracket slots.. Valid values are `winner_advances|top_n_advance|aggregate_score|penalty_shootout|tiebreaker_points`',
    `age_category` STRING COMMENT 'Age division classification for the bracket (e.g., youth, junior, senior, masters). Ensures compliance with governing body eligibility rules and CBA age restrictions.. Valid values are `youth|junior|senior|masters|open`',
    `bracket_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this bracket within the tournament management system. Used in broadcast overlays, fan engagement platforms, and league governance communications.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `bracket_name` STRING COMMENT 'Human-readable display name for the bracket (e.g., Mens Singles Main Draw, Western Conference Playoffs Bracket). Used in broadcast overlays, fan engagement platforms, and digital content.',
    `bracket_status` STRING COMMENT 'Current lifecycle state of the bracket from initial draft through post-event reconciliation. Drives workflow routing in league governance, broadcast scheduling, and fan engagement platforms. [ENUM-REF-CANDIDATE: draft|announced|seeding_complete|in_progress|completed|cancelled|suspended — promote to reference product]',
    `bracket_type` STRING COMMENT 'Classification of the bracket format governing advancement rules. Determines how winners and losers progress through the draw. [ENUM-REF-CANDIDATE: single_elimination|double_elimination|round_robin|swiss|group_stage|repechage — promote to reference product if additional formats are required]. Valid values are `single_elimination|double_elimination|round_robin|swiss|group_stage|repechage`',
    `broadcast_overlay_enabled` BOOLEAN COMMENT 'Indicates whether real-time bracket visualization data is enabled for broadcast overlay graphics. When true, bracket progression data is streamed to broadcast production systems for on-screen display.',
    `bye_count` STRING COMMENT 'Number of bye assignments in the first round of the bracket, granted when total entrants do not fill a power-of-two draw. Byes automatically advance the assigned participant to the next round.',
    `consolation_bracket` BOOLEAN COMMENT 'Indicates whether a consolation or losers bracket exists alongside this main bracket, as in double-elimination formats. When true, loser advancement rules apply and a separate bracket reset may be triggered.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this bracket record was first created in the system. Audit trail field supporting SOX financial controls and data lineage requirements.',
    `current_round` STRING COMMENT 'The round number currently in progress within the bracket. Updated in real-time as results are confirmed and participants advance. Drives real-time bracket visualization for broadcast overlays and fan engagement platforms.',
    `draw_date` DATE COMMENT 'Calendar date on which the official bracket draw ceremony was or is scheduled to be conducted. Marks the transition from seeding_complete to announced status.',
    `draw_timestamp` TIMESTAMP COMMENT 'Precise date and time at which the official bracket draw was executed, including timezone offset. Used for broadcast scheduling and audit trail of bracket creation.',
    `end_date` DATE COMMENT 'Scheduled or actual calendar date on which the final match of this bracket is completed. Used for post-event reconciliation and season structure closure.',
    `fan_engagement_visible` BOOLEAN COMMENT 'Indicates whether this bracket is published and visible on fan engagement platforms (Adobe Experience Platform, DTC apps, OTT services). Controls public-facing bracket display and fan prediction features.',
    `gender_category` STRING COMMENT 'Gender classification of the competition bracket as defined by the governing body. Used for scheduling, broadcast rights segmentation, and compliance with IOC and governing body regulations.. Valid values are `men|women|mixed|open`',
    `governing_body_code` STRING COMMENT 'Code identifying the international or national governing body whose rules and regulations apply to this bracket. Determines applicable competition rules, anti-doping requirements, and dispute resolution via CAS. [ENUM-REF-CANDIDATE: FIFA|IOC|NFL|NBA|MLB|NHL|MLS|ATP|UFC|WADA — 10 candidates stripped; promote to reference product]',
    `last_result_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent match result that triggered a bracket slot update. Used for real-time bracket synchronization with broadcast overlays and fan engagement platforms.',
    `notes` STRING COMMENT 'Free-text field for league operations staff to record special conditions, governance decisions, protest outcomes, or CAS arbitration notes affecting this brackets structure or results.',
    `phase` STRING COMMENT 'Specific competition phase or stage this bracket represents within the overall tournament structure (e.g., qualifying, group stage, knockout rounds). [ENUM-REF-CANDIDATE: qualifying|group_stage|round_of_64|round_of_32|round_of_16|quarterfinal|semifinal|third_place|final — promote to reference product]',
    `prediction_game_enabled` BOOLEAN COMMENT 'Indicates whether fan bracket prediction and pickem games are activated for this bracket on fan engagement platforms. Drives fan engagement KPI tracking and NPS measurement.',
    `reset_rule` STRING COMMENT 'Rule defining whether and how the bracket resets in double-elimination formats when the losers bracket winner faces the undefeated winners bracket champion. Governs whether a grand final reset match is required.. Valid values are `no_reset|full_reset|partial_reset`',
    `result_source` STRING COMMENT 'Source system or process from which match results are ingested to update bracket slot progression. Includes VAR (Video Assistant Referee) and TMO (Television Match Official) review outcomes for result verification.. Valid values are `official_scoresheet|var_review|tmo_review|manual_entry|system_feed`',
    `seeding_locked` BOOLEAN COMMENT 'Indicates whether the seeding assignments for this bracket have been finalized and locked, preventing further modifications. Set to true after the official draw ceremony.',
    `seeding_method` STRING COMMENT 'Method used to assign seeding positions to participants in the bracket draw. Determines competitive fairness and scheduling of top seeds to avoid early high-profile matchups.. Valid values are `ranking_based|random_draw|committee_selection|performance_based|hybrid`',
    `slot_fill_method` STRING COMMENT 'Method by which future bracket slots are populated as results are confirmed. Automatic fills slots immediately upon result confirmation; manual requires league office intervention; pending_result holds slot until result is verified.. Valid values are `automatic|manual|pending_result`',
    `sport_type` STRING COMMENT 'The sport or entertainment discipline for which this bracket is structured (e.g., basketball, soccer, tennis, esports, mixed martial arts). Drives sport-specific advancement and scoring rules. [ENUM-REF-CANDIDATE: promote to reference product for full sport taxonomy]',
    `start_date` DATE COMMENT 'Scheduled calendar date on which competition within this bracket is set to begin. Used for fixture calendar generation and broadcast rights scheduling.',
    `third_place_match` BOOLEAN COMMENT 'Indicates whether this bracket includes a third-place playoff match between the two semifinal losers. Relevant for broadcast scheduling and ticketing inventory allocation.',
    `tiebreaker_rule` STRING COMMENT 'Description of the tiebreaker rule applied when participants are level on points or score at the end of regulation (e.g., away goals, penalty shootout, sudden death overtime, head-to-head record). Governs conditional scheduling of additional fixtures. [ENUM-REF-CANDIDATE: promote to reference product for full tiebreaker taxonomy]',
    `total_entrants` STRING COMMENT 'Number of teams, athletes, or participants entered into this bracket. May differ from total_slots when byes are assigned to fill power-of-two draw sizes.',
    `total_rounds` STRING COMMENT 'Total number of rounds in this bracket structure. Defines the depth of the bracket tree and is used to pre-generate slot positions and schedule future fixtures.',
    `total_slots` STRING COMMENT 'Total number of matchup slots in the bracket across all rounds. Determines the capacity of the draw and is used for seeding assignment and bye allocation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this bracket record was most recently modified. Supports change data capture, audit trail, and Silver Layer incremental processing on the Databricks Lakehouse.',
    `weight_class` STRING COMMENT 'Weight class designation for combat sports brackets (e.g., UFC lightweight, heavyweight). Null for non-combat sports. Governs participant eligibility and WADA weigh-in compliance requirements.',
    CONSTRAINT pk_bracket PRIMARY KEY(`bracket_id`)
) COMMENT 'Transactional entity capturing the bracket structure and real-time progression of a tournament — rounds, matchup slots, seeding positions, advancement rules, bye assignments, and results-driven slot filling. Tracks which fixture occupies each bracket slot, winner advancement logic, bracket reset rules for double-elimination formats, and conditional scheduling of future fixtures as results are confirmed. Enables real-time bracket visualization for broadcast overlays and fan engagement platforms.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`fixture_calendar` (
    `fixture_calendar_id` BIGINT COMMENT 'Unique surrogate identifier for the fixture calendar record. Primary key for the fixture_calendar data product in the event domain.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Fixture calendar approval is a formal scheduling governance process requiring CBA compliance sign-off and broadcast rights coordination. The approving employee must be traceable for league operations ',
    `calendar_id` BIGINT COMMENT 'Foreign key linking to event.event_calendar. Business justification: fixture_calendar is the published fixture schedule for a season/league, while event_calendar is the master entity defining the competitive season. A fixture_calendar belongs to exactly one event_calen',
    `cba_agreement_id` BIGINT COMMENT 'Foreign key linking to league.cba_agreement. Business justification: Fixture calendars must comply with CBA provisions governing rest days, travel schedules, and game frequency. Normalizing cba_reference_code to a proper FK supports CBA compliance auditing of the fixtu',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: Fixture calendars must comply with CBA scheduling obligations, international window mandates, and broadcast slot obligations. fixture_calendar has cba_compliant_flag and governing_body_reference (deno',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: Fixture calendars are published and distributed via specific digital touchpoints (app, web, API). fixture_calendar.distribution_channel is a denormalized representation of this; replacing with a prope',
    `governance_document_id` BIGINT COMMENT 'Foreign key linking to legal.governance_document. Business justification: Fixture calendars are approved under CBA and league governance document authority. fixture_calendar has cba_compliant_flag and governing_body_reference (denormalized text). Legal teams require direct ',
    `governing_body_id` BIGINT COMMENT 'Reference to the organisational unit or governing body responsible for authoring and approving this fixture calendar (e.g., league office, competition committee, touring promoter).',
    `league_id` BIGINT COMMENT 'Reference to the league or competition governing body that owns and publishes this fixture calendar (e.g., NFL, NBA, MLS, FIFA). Establishes the scheduling authority context.',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Fixture calendar broadcast rights governance: fixture calendars are published with broadcast rights constraints (blackout dates, broadcast slots) governed by a specific rights deal. primary_broadcast_',
    `scheduling_authority_governing_body_id` BIGINT COMMENT 'Reference to the organisational unit or governing body responsible for authoring and approving this fixture calendar (e.g., league office, competition committee, touring promoter).',
    `season_id` BIGINT COMMENT 'Reference to the competitive season or touring series cycle to which this fixture calendar belongs. Links the calendar container to its parent season structure.',
    `ada_compliance_reviewed_flag` BOOLEAN COMMENT 'Indicates whether the venue accessibility requirements under the Americans with Disabilities Act (ADA) have been reviewed and confirmed for all venues included in this fixture calendar.',
    `amendment_date` DATE COMMENT 'The date on which the most recent amendment to this fixture calendar was officially approved and re-published. Null for the initial publication version.',
    `amendment_reason` STRING COMMENT 'Free-text description of the reason for the most recent amendment to this fixture calendar (e.g., Venue unavailability at Wembley Stadium, Broadcast window conflict with Super Bowl, Weather postponement rescheduling). Populated only when version_number > 1.',
    `approval_date` DATE COMMENT 'The date on which the fixture calendar was formally approved by the scheduling authority or governing body prior to publication. Distinct from publication_date — approval may precede public release.',
    `blackout_dates` STRING COMMENT 'Comma-separated list of specific dates (yyyy-MM-dd) on which no fixtures may be scheduled due to broadcast exclusivity agreements, regulatory restrictions, competing major events, or governing body mandates. Consumed by scheduling engines and broadcast rights systems.',
    `broadcast_rights_region` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the primary broadcast rights territory for which this fixture calendar was constructed or is applicable. Drives RSN, OTT, and DTC distribution planning.. Valid values are `^[A-Z]{3}$`',
    `broadcast_slots_allocated` STRING COMMENT 'The number of broadcast slots (TV windows, OTT streams, PPV events) formally allocated to fixtures within this calendar. Used by broadcast rights and media distribution teams to validate coverage against RSN and DTC agreements.',
    `bye_week_count` STRING COMMENT 'The number of bye weeks (scheduled rest weeks with no fixtures) defined in this fixture calendar. Critical for NFL and other league formats where bye weeks are mandated by the CBA and affect broadcast scheduling.',
    `calendar_notes` STRING COMMENT 'Free-text operational notes associated with this fixture calendar, capturing scheduling caveats, special conditions, or communications to downstream teams (e.g., Subject to FIFA international window confirmation, Venue TBD for weeks 14-16).',
    `calendar_status` STRING COMMENT 'Current lifecycle state of the fixture calendar. Controls downstream visibility and consumption: draft calendars are internal only; published calendars are released to broadcast, ticketing, and venue operations; amended calendars have post-publication changes; suspended calendars are temporarily withheld; archived calendars are historical.. Valid values are `draft|published|amended|suspended|archived`',
    `calendar_type` STRING COMMENT 'Classification of the fixture calendar by competition or event format. Determines scheduling rules, broadcast rights windows, and ticketing configurations applicable to the calendar. [ENUM-REF-CANDIDATE: regular_season|pre_season|post_season|tournament|concert_tour|international_window|friendly — promote to reference product]',
    `cba_compliant_flag` BOOLEAN COMMENT 'Indicates whether this fixture calendar has been validated as compliant with the applicable Collective Bargaining Agreement (CBA) constraints, including maximum consecutive game limits, minimum rest days, and travel restrictions for players.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp at which this fixture calendar record was first created in the system. Audit trail field supporting data lineage, SOX financial controls, and GDPR data processing records.',
    `effective_from_date` DATE COMMENT 'The date from which this fixture calendar is operationally active and binding on all parties (leagues, venues, broadcasters, ticketing). Marks the start of the scheduled period covered by this calendar.',
    `effective_until_date` DATE COMMENT 'The date on which this fixture calendar ceases to be operationally active. Nullable for open-ended or rolling calendars. Marks the end of the scheduled period covered by this calendar.',
    `home_away_balance_flag` BOOLEAN COMMENT 'Indicates whether this fixture calendar enforces a balanced home/away fixture distribution for participating clubs or teams. True = balanced scheduling enforced; False = unbalanced or neutral-venue format.',
    `international_window_count` STRING COMMENT 'The number of FIFA or governing-body-mandated international fixture windows embedded in this calendar during which domestic league fixtures are suspended. Relevant for football/soccer leagues operating under FIFA calendar obligations.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp at which this fixture calendar record was most recently modified. Used for change detection by downstream broadcast, ticketing, and venue operations consumers, and for audit compliance.',
    `multi_sport_flag` BOOLEAN COMMENT 'Indicates whether this fixture calendar spans multiple sports disciplines (e.g., an Olympic Games calendar or a multi-sport festival). False for single-sport league calendars.',
    `neutral_venue_flag` BOOLEAN COMMENT 'Indicates whether fixtures in this calendar are played at neutral venues (neither teams home ground), as is common in tournament finals, international competitions, and All-Star events.',
    `ppv_event_count` STRING COMMENT 'The number of fixtures within this calendar designated as Pay-Per-View (PPV) events. Drives revenue forecasting, broadcast rights negotiations, and fan engagement planning for premium content.',
    `primary_timezone` STRING COMMENT 'The IANA timezone identifier (e.g., America/New_York, Europe/London) used as the reference timezone for all fixture scheduling times published in this calendar. Critical for broadcast scheduling and fan-facing communications.',
    `publication_date` DATE COMMENT 'The official date on which this version of the fixture calendar was released to the public and downstream systems (broadcast, ticketing, venue operations). Distinct from the internal creation timestamp.',
    `scheduling_format` STRING COMMENT 'The competition or event scheduling format that governs how fixtures are arranged within this calendar. Determines the structural rules for fixture sequencing and progression. [ENUM-REF-CANDIDATE: round_robin|single_elimination|double_elimination|group_stage|league_cup|touring|mixed — promote to reference product]',
    `season_end_date` DATE COMMENT 'The official end date of the competitive season or touring series covered by this fixture calendar. Defines the outer boundary for all scheduled fixtures within this calendar container.',
    `season_start_date` DATE COMMENT 'The official start date of the competitive season or touring series covered by this fixture calendar. Used for scheduling window calculations, broadcast rights activation, and ticketing on-sale planning.',
    `source_system_calendar_reference` STRING COMMENT 'The native identifier of this fixture calendar in the originating operational system (e.g., SAP S/4HANA SD scheduling object ID, Archtics calendar reference). Enables lineage tracing and reconciliation with the system of record.',
    `total_fixture_count` STRING COMMENT 'The total number of individual fixtures (matches, games, events) scheduled within this calendar. Used for capacity planning, broadcast slot allocation, and ticketing inventory sizing. This is a declared schedule count, not a derived aggregate.',
    `total_matchweek_count` STRING COMMENT 'The total number of matchweeks, game weeks, or scheduling rounds defined in this fixture calendar. Relevant for league formats with round-robin structures. Null for non-league formats such as concert tours.',
    `version_number` STRING COMMENT 'Monotonically incrementing integer version of the fixture calendar. Incremented each time the calendar is amended and re-published. Version 1 is the initial publication. Enables downstream consumers to detect and reconcile schedule changes.',
    CONSTRAINT pk_fixture_calendar PRIMARY KEY(`fixture_calendar_id`)
) COMMENT 'Master scheduling entity representing the published fixture calendar for a season, league, or touring series. Captures calendar name, publication date, version number, scheduling authority, blackout dates, bye weeks, international window dates, and calendar status (draft, published, amended). Manages the official release of fixture schedules to downstream consumers including broadcast, ticketing, and venue operations. Distinct from individual fixture records — this is the calendar container.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`match_result` (
    `match_result_id` BIGINT COMMENT 'Unique surrogate identifier for the match result record. Primary key for the match_result data product in the event domain Silver layer.',
    `after_action_report_id` BIGINT COMMENT 'Foreign key linking to security.after_action_report. Business justification: Match result records include protest_reference, doping_control_conducted, and VAR intervention flags that must be cross-referenced with the security after-action report for league governing body submi',
    `away_team_franchise_id` BIGINT COMMENT 'Reference to the away team or visiting-side participant in the fixture. Used for league standings, head-to-head analytics, and broadcast attribution.',
    `competition_tournament_id` BIGINT COMMENT 'Reference to the league, cup, or tournament competition governing this fixture. Enables competition-scoped standings and bracket progression.',
    `fixture_id` BIGINT COMMENT 'Reference to the scheduled fixture (event) for which this result is recorded. Links the outcome back to the pre-game fixture master record.',
    `franchise_id` BIGINT COMMENT 'Reference to the home team or home-side participant in the fixture. Used for league standings, head-to-head analytics, and broadcast attribution.',
    `notification_campaign_id` BIGINT COMMENT 'Foreign key linking to platform.notification_campaign. Business justification: Confirmed match results trigger post-match notification campaigns (result alerts, highlights available, next fixture promotions). Linking match_result to notification_campaign enables audit of which c',
    `official_id` BIGINT COMMENT 'Reference to the primary match official (referee, umpire, or head official) who officiated the match. Used for officiating performance analytics, assignment tracking, and governing body compliance.',
    `playoff_bracket_id` BIGINT COMMENT 'Foreign key linking to league.playoff_bracket. Business justification: Match results in playoff rounds must be linked to the playoff bracket to drive bracket advancement logic, update seeding, and trigger next-round scheduling. League playoff management systems depend on',
    `primary_match_franchise_id` BIGINT COMMENT 'Reference to the home team or home-side participant in the fixture. Used for league standings, head-to-head analytics, and broadcast attribution.',
    `referee_official_id` BIGINT COMMENT 'Reference to the primary match official (referee, umpire, or head official) who officiated the match. Used for officiating performance analytics, assignment tracking, and governing body compliance.',
    `season_id` BIGINT COMMENT 'Reference to the competitive season in which this match result occurred. Supports season-level standings aggregation and historical trend analysis.',
    `tertiary_match_winning_team_franchise_id` BIGINT COMMENT 'Reference to the team that won the match. Null for draws or no-result outcomes. Used for bracket progression in knockout competitions, playoff seeding, and broadcast winner attribution.',
    `tournament_id` BIGINT COMMENT 'Reference to the league, cup, or tournament competition governing this fixture. Enables competition-scoped standings and bracket progression.',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the match was played. Used for venue-level performance analytics and operational reporting.',
    `winning_team_franchise_id` BIGINT COMMENT 'Reference to the team that won the match. Null for draws or no-result outcomes. Used for bracket progression in knockout competitions, playoff seeding, and broadcast winner attribution.',
    `attendance` STRING COMMENT 'Official announced attendance figure (number of spectators present) for the match. Used for venue capacity utilization reporting, revenue reconciliation, and league attendance KPI tracking.',
    `away_score_final` STRING COMMENT 'Official final score (goals, points, runs, etc.) for the away team at the conclusion of regulation and any extra time/overtime/shootout. This is the authoritative scoreline used for standings and wagering settlement.',
    `away_score_regulation` STRING COMMENT 'Away team score at the end of regulation time only (excluding overtime, extra time, or shootout). Required for sports where regulation draws carry different standings points than overtime losses.',
    `broadcast_match_reference` STRING COMMENT 'External identifier assigned to this match result by the broadcast or media rights partner (e.g., RSN, OTT platform, Dalet Galaxy MAM system). Used to link match result data to broadcast highlight packages, content rights windows, and CDN distribution metadata.',
    `competition_stage` STRING COMMENT 'Stage within the competition at which this match was played. Determines standings impact (regular season points) vs. bracket elimination logic (playoffs/knockout). [ENUM-REF-CANDIDATE: regular_season|playoffs|knockout|group_stage|final|semifinal|quarterfinal|round_of_16|round_of_32 — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'UTC timestamp when this match result record was first created in the system. Supports audit trail, data lineage, and SOX financial controls for revenue-impacting result records.',
    `doping_control_conducted` BOOLEAN COMMENT 'Indicates whether WADA-mandated PED (Performance Enhancing Drug) doping control testing was conducted in connection with this match. Supports WADA compliance reporting and anti-doping program audit trails.',
    `home_score_final` STRING COMMENT 'Official final score (goals, points, runs, etc.) for the home team at the conclusion of regulation and any extra time/overtime/shootout. This is the authoritative scoreline used for standings and wagering settlement.',
    `home_score_regulation` STRING COMMENT 'Home team score at the end of regulation time only (excluding overtime, extra time, or shootout). Required for sports where regulation draws carry different standings points than overtime losses (e.g., NHL, MLS).',
    `kickoff_timestamp` TIMESTAMP COMMENT 'Precise UTC timestamp of the official match start (kickoff, tip-off, first pitch, puck drop, etc.). Distinct from match_date — provides sub-day precision for broadcast scheduling, SLA measurement, and wagering in-play event sequencing.',
    `margin_of_victory` STRING COMMENT 'Absolute difference between the winning and losing teams final scores (e.g., 3 goals, 14 points). Null for draws. Used for strength-of-schedule analytics, WAR (Wins Above Replacement) calculations, and wagering handicap settlement.',
    `match_date` DATE COMMENT 'Calendar date on which the match was played (local venue time). Used for fixture calendar reporting, standings date-range filtering, and broadcast scheduling alignment.',
    `match_duration_minutes` STRING COMMENT 'Total actual playing time in minutes from kickoff to final whistle, including stoppage time and overtime but excluding pre-match and half-time intervals. Used for broadcast scheduling, venue operations planning, and SLA compliance.',
    `match_outcome` STRING COMMENT 'Categorical result of the match from the perspective of home vs. away: home_win, away_win, draw, or no_result (abandoned/forfeited). Primary field for league standings points allocation and wagering market settlement.. Valid values are `home_win|away_win|draw|no_result`',
    `neutral_venue` BOOLEAN COMMENT 'Indicates whether the match was played at a neutral venue (neither teams home ground). Affects home/away advantage analytics, standings point allocation rules, and ticket revenue attribution.',
    `overtime_played` BOOLEAN COMMENT 'Indicates whether the match required overtime, extra time, or additional periods beyond regulation to determine a winner. Drives standings point allocation logic (e.g., NHL OTL point) and broadcast scheduling overrun management.',
    `period_scores_away` STRING COMMENT 'Pipe-delimited string of away team scores by period, quarter, half, set, or inning (e.g., 7|21|14|3 for NFL quarters). Enables granular in-game momentum analytics and broadcast segment attribution.',
    `period_scores_home` STRING COMMENT 'Pipe-delimited string of home team scores by period, quarter, half, set, or inning (e.g., 21|14|7|10 for NFL quarters, or 1|0|2 for NHL periods). Enables granular in-game momentum analytics and broadcast segment attribution.',
    `pitch_condition` STRING COMMENT 'Official assessment of the playing surface condition at the time of the match. Used for player welfare analytics, venue maintenance scheduling, and governing body compliance reporting.. Valid values are `excellent|good|fair|poor|unplayable`',
    `protest_reference` STRING COMMENT 'Official reference number of any formal protest or appeal lodged against this match result with the governing body or CAS (Court of Arbitration for Sport). Null if no protest filed. Supports legal and compliance tracking.',
    `result_confirmed_timestamp` TIMESTAMP COMMENT 'UTC timestamp at which the governing body or league operations officially confirmed and locked the match result. Triggers downstream processes: standings updates, wagering settlement, broadcast highlights release, and fantasy sports scoring.',
    `result_notes` STRING COMMENT 'Free-text field for official notes or annotations related to the match result, such as protest grounds, abandonment reasons, score correction explanations, or governing body directives. Supports compliance documentation and operational context.',
    `result_reference_code` STRING COMMENT 'Externally-known alphanumeric code assigned to this match result by the governing body or league operations system. Used for official reporting, wagering integrations, and broadcast metadata tagging. Example: NFL-2024-WK12-DAL-PHI-RESULT.. Valid values are `^[A-Z0-9-]{4,30}$`',
    `result_source_system` STRING COMMENT 'Identifies the originating system or feed from which the match result data was ingested. Supports data lineage, audit trail, and Silver layer quality validation. Values include SportsCode/Hudl performance analytics platform, governing body official data feeds, or manual entry.. Valid values are `sportscode|hudl|manual_entry|governing_body_feed|third_party_data`',
    `result_status` STRING COMMENT 'Current lifecycle state of the match result record. official = confirmed by governing body; under_review = VAR/TMO or disciplinary review pending; protested = formal protest lodged by a participant; forfeited = awarded due to forfeit; abandoned = match abandoned before completion; postponed_result = result deferred pending replay. Drives league standings inclusion and wagering settlement eligibility.. Valid values are `official|under_review|protested|forfeited|abandoned|postponed_result`',
    `shootout_played` BOOLEAN COMMENT 'Indicates whether the match was decided by a penalty shootout or shootout format (e.g., FIFA penalty shootout, NHL shootout). Distinct from overtime_played — a match can have overtime without a shootout.',
    `shootout_score_away` STRING COMMENT 'Number of successful shootout attempts by the away team during a penalty shootout. Null if shootout_played is false. Used for detailed shootout analytics and historical records.',
    `shootout_score_home` STRING COMMENT 'Number of successful shootout attempts by the home team during a penalty shootout. Null if shootout_played is false. Used for detailed shootout analytics and historical records.',
    `sport_type` STRING COMMENT 'Classification of the sport discipline for this match result. Determines the applicable scoring schema, period structure, and governing body rules. [ENUM-REF-CANDIDATE: football|basketball|baseball|ice_hockey|soccer|tennis|rugby|cricket|golf|mma — promote to reference product]',
    `stoppage_time_minutes` STRING COMMENT 'Total additional stoppage/injury time added by the referee across all periods. Relevant for soccer/football and rugby. Used for broadcast scheduling overrun management and officiating analytics.',
    `updated_timestamp` TIMESTAMP COMMENT 'UTC timestamp of the most recent modification to this match result record. Tracks amendments such as score corrections, VAR overturns, or protest resolutions.',
    `var_intervention` BOOLEAN COMMENT 'Indicates whether a Video Assistant Referee (VAR) or Television Match Official (TMO) intervention occurred during the match that affected the official result (e.g., goal disallowed, red card issued, try awarded). Supports officiating quality analytics and governing body review processes.',
    `var_intervention_count` STRING COMMENT 'Total number of VAR (Video Assistant Referee) or TMO (Television Match Official) review incidents during the match. Supports officiating quality analytics and governing body compliance reporting.',
    `weather_condition` STRING COMMENT 'Prevailing weather condition at the venue during the match. Used for performance analytics (weather impact on scoring), venue operations reporting, and broadcast production context. indoor applies to enclosed arenas. [ENUM-REF-CANDIDATE: clear|cloudy|rain|snow|fog|extreme_heat|indoor — 7 candidates stripped; promote to reference product]',
    CONSTRAINT pk_match_result PRIMARY KEY(`match_result_id`)
) COMMENT 'Transactional entity capturing the official outcome of a completed sports fixture — final scores, scorelines by period/quarter/half/set, overtime/shootout results, winning team/athlete, margin of victory, result status (official, under review, protested, forfeited), VAR/TMO intervention flag, and result confirmation timestamp. Serves as the SSOT for competitive outcomes used by league standings, broadcast highlights, and wagering integrations. Distinct from fixture (which is the scheduled event) — this is the recorded outcome.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`scoring_event` (
    `scoring_event_id` BIGINT COMMENT 'Unique surrogate identifier for each individual in-game scoring moment captured in the system. Primary key for the scoring_event data product.',
    `assist_athlete_athlete_profile_id` BIGINT COMMENT 'Reference to the athlete credited with the primary assist on this scoring event, where applicable (e.g., pass before a goal, assist before a basket). Nullable when no assist is recorded.',
    `athlete_profile_id` BIGINT COMMENT 'Reference to the athlete credited with the scoring event (goal scorer, touchdown passer/rusher, basket maker, run batter, etc.).',
    `fixture_id` BIGINT COMMENT 'Reference to the parent match or game in which this scoring event occurred. Links the scoring moment to its fixture context.',
    `franchise_id` BIGINT COMMENT 'Reference to the team that scored this scoring event. Determines which teams score is incremented.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to content.asset. Business justification: Scoring events (goals, touchdowns) are directly linked to highlight clips — a core content monetization workflow in sports entertainment. broadcast_clip_reference is a denormalized string; replacing i',
    `league_id` BIGINT COMMENT 'Reference to the league or governing competition body under whose rules this scoring event was recorded (e.g., NFL, NBA, MLB, NHL, MLS, FIFA). Supports multi-league analytics and league-specific rule application.',
    `live_feed_id` BIGINT COMMENT 'Foreign key linking to broadcast.live_feed. Business justification: Real-time broadcast production: scoring events must be linked to the live feed for instant replay cuing, live graphics overlay triggering, and real-time highlight extraction. Broadcast production team',
    `match_result_id` BIGINT COMMENT 'Reference to the parent match or game in which this scoring event occurred. Links the scoring moment to its fixture context.',
    `media_asset_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_asset. Business justification: Highlight clip production workflow: each scoring event must be linked to its broadcast media asset for replay packaging, highlight reels, and clip licensing. Sports broadcasters routinely tag scoring ',
    `primary_scoring_athlete_profile_id` BIGINT COMMENT 'Reference to the athlete credited with the scoring event (goal scorer, touchdown passer/rusher, basket maker, run batter, etc.).',
    `push_notification_id` BIGINT COMMENT 'Foreign key linking to platform.push_notification. Business justification: Scoring events (goals, touchdowns) trigger real-time push notifications to fans. Linking scoring_event to push_notification enables traceability of which score triggered which alert, supporting fan en',
    `season_id` BIGINT COMMENT 'Reference to the league season or competition season in which this scoring event occurred. Supports season-level aggregation and reporting.',
    `team_franchise_id` BIGINT COMMENT 'Reference to the team that scored this scoring event. Determines which teams score is incremented.',
    `venue_id` BIGINT COMMENT 'Reference to the venue or facility where this scoring event occurred. Supports venue-level scoring analytics, home advantage analysis, and venue operations reporting.',
    `away_score_after` STRING COMMENT 'The cumulative score of the away team immediately after this scoring event was recorded. Paired with home_score_after to represent the full score state at the moment of the event.',
    `body_part` STRING COMMENT 'The body part or implement used by the athlete to execute the scoring action (e.g., right foot, left foot, head for soccer; bat for baseball; club for golf). Supports detailed performance analytics and broadcast commentary. [ENUM-REF-CANDIDATE: right_foot|left_foot|head|right_hand|left_hand|body|bat|club|other — 9 candidates stripped; promote to reference product]',
    `competition_phase` STRING COMMENT 'The phase of the competition or tournament in which this scoring event occurred. Distinguishes regular season scoring from playoff or knockout stage scoring for statistical segmentation. [ENUM-REF-CANDIDATE: regular_season|playoffs|knockout|group_stage|final|semifinal|quarterfinal|wildcard|round_of_16|round_of_32 — promote to reference product]',
    `coordinate_x` DECIMAL(18,2) COMMENT 'The X-axis coordinate on the standardised pitch or field coordinate system representing the horizontal position from which the scoring action originated. Used for spatial heatmaps and performance analytics in SportsCode/Hudl.',
    `coordinate_y` DECIMAL(18,2) COMMENT 'The Y-axis coordinate on the standardised pitch or field coordinate system representing the vertical position from which the scoring action originated. Paired with coordinate_x for full spatial positioning.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this scoring event record was first created and ingested into the data platform. Supports data lineage, audit trails, and SLA compliance monitoring.',
    `data_quality_flag` STRING COMMENT 'Indicates the data quality status of this scoring event record. Clean means fully validated; under_review means flagged for investigation; corrected means the record was amended after initial ingestion; disputed means conflicting data from multiple sources.. Valid values are `clean|under_review|corrected|disputed`',
    `data_source` STRING COMMENT 'The originating data provider or system that supplied this scoring event record (e.g., Opta, Stats Perform, Sportradar, Hudl, manual entry by official scorer, broadcast feed). Supports data lineage, quality auditing, and source reconciliation. [ENUM-REF-CANDIDATE: opta|stats_perform|sportradar|hudl|manual|broadcast_feed|official_scorer — 7 candidates stripped; promote to reference product]',
    `event_status` STRING COMMENT 'Current lifecycle status of the scoring event record. Provisional indicates the event is pending official confirmation; confirmed means officially validated; overturned means disallowed after review; amended means corrected post-confirmation; voided means removed from official records.. Valid values are `provisional|confirmed|overturned|amended|voided`',
    `event_timestamp` TIMESTAMP COMMENT 'The precise real-world date and time at which the scoring event occurred, expressed in ISO 8601 format with timezone offset. Used for broadcast overlays, play-by-play timelines, and content production.',
    `external_event_code` STRING COMMENT 'Externally-known unique code or reference number for this scoring event as assigned by the official league data provider or broadcast system (e.g., Opta event ID, Stats Perform ID, Sportradar event ID). Used for cross-system reconciliation.',
    `home_score_after` STRING COMMENT 'The cumulative score of the home team immediately after this scoring event was recorded. Captures the score state for broadcast overlays, play-by-play reconstruction, and fan engagement platforms.',
    `hudl_event_reference` STRING COMMENT 'The native event identifier assigned by the SportsCode or Hudl performance analytics platform for this scoring event. Used for cross-system reconciliation between the lakehouse silver layer and the performance analytics system of record.',
    `is_confirmed` BOOLEAN COMMENT 'Indicates whether this scoring event has been officially confirmed and validated by the match officials or league data operations team. False for provisional or pending events awaiting VAR review or official confirmation.',
    `is_lead_change` BOOLEAN COMMENT 'Indicates whether this scoring event resulted in a change of lead between the two competing teams. True when the scoring team overtook the previously leading team. Key metric for broadcast drama and fan engagement analytics.',
    `is_own_goal` BOOLEAN COMMENT 'Indicates whether this scoring event was an own goal (scored by a player against their own team). Affects attribution logic and statistical reporting for the credited athlete.',
    `is_tie` BOOLEAN COMMENT 'Indicates whether this scoring event resulted in a tied score between the two competing teams. True when the score differential after the event equals zero.',
    `match_clock_seconds` STRING COMMENT 'Elapsed match clock time in seconds at the moment the scoring event occurred within the current period. Enables precise play-by-play positioning and broadcast overlay synchronisation.',
    `notes` STRING COMMENT 'Free-text field for additional contextual notes or commentary about this scoring event, as recorded by the official scorer, data operations team, or league officials. May include unusual circumstances, corrections rationale, or broadcast annotations.',
    `officiating_decision_code` STRING COMMENT 'Official code or reference assigned by the match officiating team or league operations to document any officiating decision associated with this scoring event (e.g., penalty awarded, foul called, offside check). Supports league governance and compliance reporting.',
    `period_number` STRING COMMENT 'The period, quarter, half, inning, or round number within the match in which the scoring event occurred (e.g., 1 = first half/quarter/period, 2 = second, etc.). Supports sport-agnostic period-level analytics.',
    `period_type` STRING COMMENT 'Classification of the period in which the scoring event occurred, distinguishing regular play from overtime, extra time, penalty shootout, or sudden death. Critical for statistical integrity and broadcast context.. Valid values are `regular|overtime|extra_time|penalty_shootout|sudden_death`',
    `pitch_zone` STRING COMMENT 'The designated zone or area of the playing field from which the scoring action was initiated (e.g., penalty area, midfield, three-point arc, red zone, paint area). Supports spatial analytics and performance analysis in SportsCode/Hudl. [ENUM-REF-CANDIDATE: penalty_area|six_yard_box|outside_box|three_point_arc|paint|mid_range|red_zone|end_zone|infield|outfield — promote to reference product]',
    `play_pattern` STRING COMMENT 'The tactical play pattern or situation from which the scoring event originated (e.g., open play, set piece, counter attack, fast break, corner, free kick). Supports tactical analysis and content production. [ENUM-REF-CANDIDATE: open_play|set_piece|counter_attack|fast_break|corner|free_kick|penalty|throw_in|other — 9 candidates stripped; promote to reference product]',
    `points_value` STRING COMMENT 'The number of points awarded to the scoring team as a result of this scoring event (e.g., 1 for a free throw, 2 for a basket, 3 for a three-pointer, 6 for a touchdown, 1 for a goal in soccer). Core quantitative fact of the scoring event.',
    `score_differential_after` STRING COMMENT 'The signed score differential (home minus away) immediately after this scoring event. Positive values indicate home team lead; negative values indicate away team lead; zero indicates a tie. Supports win probability and momentum analytics.',
    `scoring_method` STRING COMMENT 'The specific method by which the score was achieved (e.g., penalty kick, free kick, header, slam dunk, three-pointer, home run, touchdown pass, field goal, try, conversion). Sport-specific enumeration managed as a reference product. [ENUM-REF-CANDIDATE: penalty_kick|free_kick|header|open_play|slam_dunk|three_pointer|home_run|touchdown_pass|rushing_touchdown|field_goal|try|conversion|free_throw|layup|own_goal — promote to reference product]',
    `sequence_number` STRING COMMENT 'Sequential ordinal number of this scoring event within the match, ordered chronologically. The first score of the match is 1, the second is 2, etc. Enables ordered play-by-play reconstruction and broadcast timeline sequencing.',
    `sport_type` STRING COMMENT 'The sport discipline to which this scoring event belongs. Enables cross-sport analytics and correct interpretation of sport-specific scoring rules and methods. [ENUM-REF-CANDIDATE: football|basketball|baseball|ice_hockey|soccer|rugby|tennis|cricket|golf|mma — 10 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time at which this scoring event record was most recently modified in the data platform. Tracks amendments, corrections, and VAR-driven updates to the record.',
    `var_review_flag` BOOLEAN COMMENT 'Indicates whether this scoring event was subject to a Video Assistant Referee (VAR) or Television Match Official (TMO) review process. True when a review was initiated. Supports officiating analytics and broadcast commentary.',
    `var_review_outcome` STRING COMMENT 'The outcome of the VAR or TMO review for this scoring event. Upheld means the original decision stands; overturned means the scoring event was disallowed or modified; inconclusive means no definitive determination was reached. Null or not_reviewed when var_review_flag is false.. Valid values are `upheld|overturned|inconclusive|not_reviewed`',
    CONSTRAINT pk_scoring_event PRIMARY KEY(`scoring_event_id`)
) COMMENT 'Transactional entity capturing individual in-game scoring moments — goals, touchdowns, baskets, runs, points — with precise match clock time, period/quarter/half, athlete credited, assist attribution, scoring method (penalty, free kick, slam dunk, home run), VAR review flag, and score state after the event. Enables granular play-by-play data for broadcast overlays, content production, and fan engagement platforms. Feeds downstream content and broadcast domains.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`status_history` (
    `status_history_id` BIGINT COMMENT 'Unique surrogate identifier for each event lifecycle state transition record. Primary key of the event_status_history audit entity.',
    `approved_by_user_employee_id` BIGINT COMMENT 'Reference to the internal workforce member who formally approved this status transition, where approval is required by governance policy or governing body mandate. Null if no approval was required or if the change was system-automated.',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: Broadcast impact management: when a fixture status changes (postponement, cancellation), the specific broadcast schedule slot must be identified for rights holder notification, schedule amendment, and',
    `calendar_id` BIGINT COMMENT 'Reference to the fixture or live event whose lifecycle status changed. Core linkage to the event master record.',
    `employee_id` BIGINT COMMENT 'Reference to the internal workforce member or system account that initiated the status transition. Supports audit trail and accountability tracking.',
    `fixture_id` BIGINT COMMENT 'Foreign key linking to event.fixture. Business justification: event_status_history.event_id is a raw/legacy column referencing the specific fixture whose lifecycle state is being tracked. The entity description explicitly states it tracks every lifecycle state ',
    `incident_report_id` BIGINT COMMENT 'Foreign key linking to compliance.incident_report. Business justification: Event cancellations and postponements with force_majeure_declared=true or insurance_claim_flag=true must generate compliance incident reports for regulatory and insurance purposes. This FK links the s',
    `notification_campaign_id` BIGINT COMMENT 'Foreign key linking to platform.notification_campaign. Business justification: Event status changes (cancellation, postponement) trigger fan notification campaigns. event_status_history.notification_dispatched confirms a campaign was sent; linking to the specific notification_ca',
    `primary_status_employee_id` BIGINT COMMENT 'Reference to the internal workforce member or system account that initiated the status transition. Supports audit trail and accountability tracking.',
    `alternate_reschedule_date` DATE COMMENT 'A secondary proposed reschedule date offered when the primary proposed_reschedule_date is unavailable or under negotiation. Supports multi-option rescheduling decision workflows with venue, broadcast, and governing body stakeholders.',
    `approval_timestamp` TIMESTAMP COMMENT 'The date and time at which the status transition was formally approved by the authorized approver. Null if no approval was required. Supports SOX audit trail and governance compliance reporting.',
    `broadcast_impact_flag` BOOLEAN COMMENT 'Indicates whether this status transition has a material impact on broadcast rights obligations, RSN (Regional Sports Network) schedules, OTT (Over-The-Top Streaming) platform programming, or PPV (Pay-Per-View) commitments. Triggers broadcast partner notification workflows via Dalet Galaxy.',
    `change_category` STRING COMMENT 'High-level business category classifying the nature of the status transition. Enables aggregated reporting on postponement rates, cancellation frequencies, and reinstatement patterns across leagues and event types.. Valid values are `postponement|cancellation|reinstatement|reschedule_confirmation|status_correction|completion`',
    `change_source` STRING COMMENT 'Identifies the originating system or process that triggered the status transition — manual operator entry, automated rule engine, governing body data feed, broadcast system, ticketing platform, or API integration. Supports data lineage and audit.. Valid values are `manual|automated|governing_body_feed|broadcast_system|ticketing_system|api_integration`',
    `change_timestamp` TIMESTAMP COMMENT 'The precise date and time (with timezone offset) at which the status transition was recorded in the system. Serves as the EVENT_TIMESTAMP for this log entry and is the authoritative moment of state change for downstream near-real-time reactions.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this event_status_history record was first created in the Silver Layer data product. Serves as the RECORD_AUDIT_CREATED field for data lineage and audit purposes.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the estimated_financial_impact_amount (e.g., USD, EUR, GBP). Required for multi-currency financial impact reporting across global markets.. Valid values are `^[A-Z]{3}$`',
    `effective_timestamp` TIMESTAMP COMMENT 'The date and time at which the new status becomes operationally effective — which may differ from change_timestamp if the transition is pre-authorized or scheduled in advance (e.g., a cancellation announced 48 hours before the event). Supports bi-temporal data modeling.',
    `estimated_financial_impact_amount` DECIMAL(18,2) COMMENT 'Estimated gross financial impact (in base currency) of this status transition, encompassing projected ticket refunds, sponsor credits, broadcast fee adjustments, and venue cost liabilities. Used for EBITDA (Earnings Before Interest Taxes Depreciation and Amortization) impact forecasting in Workday Adaptive Planning.',
    `external_announcement_text` STRING COMMENT 'The official public-facing announcement text associated with this status change, as communicated to fans, media, and stakeholders. Stored for audit, brand consistency review, and regulatory record-keeping.',
    `financial_impact_flag` BOOLEAN COMMENT 'Indicates whether this status transition triggers a financial impact requiring downstream action — such as ticketing refund processing, sponsor credit notes, or broadcast rights fee adjustments. True = financial workflows must be initiated.',
    `force_majeure_declared` BOOLEAN COMMENT 'Indicates whether a force majeure clause has been formally invoked in connection with this status transition. Activates specific contractual protections for broadcast rights, sponsorship agreements, and venue contracts. Critical for legal and insurance claim processing.',
    `governing_body_approval_required` BOOLEAN COMMENT 'Indicates whether the status transition requires formal approval from the relevant governing body (e.g., FIFA, NFL League Office, NBA League Office) before it becomes effective. Drives compliance workflow routing.',
    `governing_body_approval_status` STRING COMMENT 'Current approval status from the relevant sports governing body for this status transition. Applicable when governing_body_approval_required is True. Tracks the regulatory sign-off lifecycle.. Valid values are `not_required|pending|approved|rejected|under_review`',
    `governing_body_reference_number` STRING COMMENT 'The official reference or case number assigned by the governing body (FIFA, NFL, NBA, etc.) to the directive or approval associated with this status change. Enables cross-referencing with governing body records for compliance and legal purposes.',
    `insurance_claim_flag` BOOLEAN COMMENT 'Indicates whether this status transition has triggered or is expected to trigger an event cancellation or postponement insurance claim. Drives financial reporting workflows in SAP S/4HANA FI/CO and legal documentation processes.',
    `internal_notes` STRING COMMENT 'Confidential internal commentary recorded by the operations team at the time of the status transition. May include negotiation context, legal considerations, or stakeholder communication strategy. Not for external distribution.',
    `new_status` STRING COMMENT 'The lifecycle status of the event after this transition was applied. Represents the current state at the time of this history record. [ENUM-REF-CANDIDATE: announced|scheduled|on_sale|postponed|rescheduled|cancelled|completed|suspended — promote to reference product]',
    `notification_dispatch_timestamp` TIMESTAMP COMMENT 'The date and time at which fan and stakeholder notifications were dispatched for this status change. Null if notification_dispatched is False. Supports SLA compliance measurement for fan communication obligations.',
    `notification_dispatched` BOOLEAN COMMENT 'Indicates whether fan, sponsor, and broadcast partner notifications were dispatched following this status transition. True = notifications sent; False = notifications pending or suppressed. Drives downstream fan engagement and CRM workflows in Adobe Experience Platform and Salesforce CRM.',
    `previous_status` STRING COMMENT 'The lifecycle status of the event immediately before this transition occurred. Enables before/after comparison and rollback analysis. [ENUM-REF-CANDIDATE: announced|scheduled|on_sale|postponed|rescheduled|cancelled|completed|suspended — promote to reference product]',
    `proposed_reschedule_date` DATE COMMENT 'The first proposed new date for the event following a postponement or cancellation decision. May be null if no reschedule date has been identified at the time of the status change. Supports rescheduling workflow initiation.',
    `reason_code` STRING COMMENT 'Standardized code identifying the primary business reason driving the status transition (e.g., weather, force majeure, broadcast conflict, governing body directive). Used for root-cause reporting and insurance/legal documentation. [ENUM-REF-CANDIDATE: weather|force_majeure|broadcast_conflict|governing_body_directive|venue_unavailability|safety_concern|team_request|public_health|logistical_failure — promote to reference product]',
    `reason_description` STRING COMMENT 'Free-text narrative providing additional context or detail beyond the reason_code. Captures nuanced circumstances such as specific weather event names, governing body directive reference numbers, or force majeure declarations.',
    `refund_trigger_flag` BOOLEAN COMMENT 'Specific flag indicating whether this status transition activates the ticketing refund workflow in Ticketmaster/AXS. Distinct from the broader financial_impact_flag — isolates the ticket refund obligation for PCI-DSS compliance tracking.',
    `reschedule_decision_deadline` DATE COMMENT 'The date by which a final rescheduling decision must be made, as mandated by governing body regulations, broadcast contracts, or venue availability windows. Drives escalation workflows if deadline is breached.',
    `rescheduling_workflow_status` STRING COMMENT 'Current state of the rescheduling decision and coordination workflow triggered by a postponement. Tracks progress from initial postponement through governing body approval, venue confirmation, and broadcast partner alignment. TBD (To Be Determined) indicates stakeholder alignment is ongoing.. Valid values are `not_required|pending|in_progress|confirmed|failed|tbd`',
    `source_system_reference` STRING COMMENT 'The originating systems transaction or record identifier for this status change event (e.g., Ticketmaster event ID, SAP document number, Salesforce record ID). Enables cross-system traceability and data lineage for the Silver Layer.',
    `sponsor_impact_flag` BOOLEAN COMMENT 'Indicates whether this status transition triggers sponsor and partnership management actions — such as activation cancellations, make-good provisions, or naming rights credit adjustments. Drives Salesforce CRM sponsor notification workflows.',
    `transition_sequence` STRING COMMENT 'Ordinal sequence number of this status transition within the full lifecycle history of the event. Enables chronological ordering of all status changes for a given event_id and supports lifecycle analytics.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time at which this event_status_history record was last modified in the Silver Layer. Supports incremental data processing, SCD tracking, and audit trail completeness.',
    `venue_impact_flag` BOOLEAN COMMENT 'Indicates whether this status transition requires venue operations changes — such as facility hold releases, HVAC (Heating Ventilation and Air Conditioning) schedule adjustments, BMS (Building Management System) updates, or staffing cancellations. Triggers venue operations workflows.',
    CONSTRAINT pk_status_history PRIMARY KEY(`status_history_id`)
) COMMENT 'Audit entity tracking every lifecycle state transition of a fixture — from announcement through completion or cancellation. Captures previous/new status, reason code (weather, force majeure, broadcast conflict, governing body directive), changed-by user, change timestamp, notification dispatch flag, proposed reschedule date(s), rescheduling workflow status, and financial impact flag for ticketing refund triggers. Serves as the complete postponement/rescheduling decision record and enables downstream systems to react to status changes in near-real-time.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`production_schedule` (
    `production_schedule_id` BIGINT COMMENT 'Unique surrogate identifier for the production schedule record. Primary key for the event-day run-of-show execution plan.',
    `briefing_id` BIGINT COMMENT 'Foreign key linking to security.security_briefing. Business justification: Production schedule includes a security_briefing_time cue in the run-of-show. The production coordinator must reference the formal security briefing record to confirm threat level, staffing readines',
    `production_id` BIGINT COMMENT 'Foreign key linking to broadcast.production. Business justification: Event-to-broadcast production coordination: the venue event production schedule (doors open, halftime, player walkout) must be synchronized with the broadcast production plan. Broadcast directors depe',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Production costs (broadcast setup, halftime production, venue setup) are allocated to cost centers. Finance teams require production schedule-to-cost-center linkage for operational cost tracking, prod',
    `crowd_management_plan_id` BIGINT COMMENT 'Foreign key linking to security.crowd_management_plan. Business justification: Halftime performer changeovers, gate open times, and post-event venue clearance in the production schedule must be coordinated with the crowd management plans gate activation counts, peak ingress win',
    `emergency_response_plan_id` BIGINT COMMENT 'Foreign key linking to security.emergency_response_plan. Business justification: Production schedule contains a weather_contingency_plan field and broadcast interruption cues that must reference the active emergency response plan. Broadcast suspension, evacuation announcement cu',
    `employee_id` BIGINT COMMENT 'Reference to the workforce member designated as the lead production coordinator responsible for owning and executing this run-of-show.',
    `fixture_id` BIGINT COMMENT 'Reference to the parent fixture or event for which this production schedule is the execution plan. Links the run-of-show to the event identity master.',
    `league_schedule_id` BIGINT COMMENT 'Foreign key linking to league.schedule. Business justification: Broadcast production schedules must align with the official league game schedule for kickoff time coordination, broadcast slot compliance, and sponsor activation windows. Production teams reference th',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Halftime and pre-show performer scheduling requires linking to the athlete/performers profile for NIL agreement verification, broadcast rights clearance, appearance fee processing, and rider fulfillm',
    `production_coordinator_employee_id` BIGINT COMMENT 'Reference to the workforce member designated as the lead production coordinator responsible for owning and executing this run-of-show.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to content.asset. Business justification: Production schedules reference a run-of-show document stored as a content asset in the DAM. run_of_show_document_url is a denormalized URL; replacing it with a proper FK to content.asset enables versi',
    `sla_policy_id` BIGINT COMMENT 'Foreign key linking to platform.sla_policy. Business justification: Production schedules for live broadcasts (is_broadcast_live, is_ppv) require platform SLA policies to guarantee uptime during broadcast go-live windows. Ops teams assign SLA policies to production sch',
    `sponsorship_activation_id` BIGINT COMMENT 'Foreign key linking to sponsorship.activation. Business justification: Sponsor activation window scheduling: production_schedule carries sponsor_activation_window_start and sponsor_activation_window_end. Production coordinators must reference the specific activation bein',
    `staffing_plan_id` BIGINT COMMENT 'Foreign key linking to security.security_staffing_plan. Business justification: Production schedule gate-open times, ob-truck arrival, and pre-show windows must align with the security staffing deployment timeline. Production coordinators reference the staffing plan to confirm se',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the event is being produced. Drives facility-specific logistics, stage configuration, and clearance timelines.',
    `wbs_element_id` BIGINT COMMENT 'Foreign key linking to finance.wbs_element. Business justification: Production schedules drive significant costs (OB trucks, staging, broadcast crew) tracked against WBS elements. Finance teams capture all production costs at the WBS level for event project accounting',
    `approval_timestamp` TIMESTAMP COMMENT 'Timestamp at which the production schedule received formal approval from the designated approving authority. Distinct from the schedule lock timestamp.',
    `approved_by` STRING COMMENT 'Name or identifier of the senior production official or league operations representative who formally approved the locked production schedule.',
    `broadcast_go_live_time` TIMESTAMP COMMENT 'Scheduled timestamp at which the broadcast feed goes live to air or OTT (Over-The-Top Streaming) platforms. Coordinated with the OB (Outside Broadcast) truck and network partners. Critical for FCC compliance and RSN (Regional Sports Network) scheduling.',
    `broadcast_network` STRING COMMENT 'Name of the primary broadcast network or OTT (Over-The-Top Streaming) platform carrying the live event (e.g., ESPN, NBC Sports, Amazon Prime Video, DAZN). Drives broadcast coordination and DRM (Digital Rights Management) enforcement.',
    `changeover_duration_minutes` STRING COMMENT 'Planned duration in minutes for the changeover of the playing surface or stage between the halftime show and the resumption of competition. Critical for league compliance with CBA timing rules.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp at which this production schedule record was first created in the system. Mandatory audit field for data lineage and compliance tracking.',
    `doors_open_time` TIMESTAMP COMMENT 'Scheduled timestamp at which venue doors open to the public. Drives fan ingress planning, concession staffing, and security deployment timelines.',
    `event_date` DATE COMMENT 'Calendar date on which the live event is scheduled to take place. Used for day-of logistics coordination, staffing scheduling, and broadcast go-live alignment.',
    `event_end_time` TIMESTAMP COMMENT 'Estimated timestamp for the conclusion of the main event. Used for post-event activity planning, venue clearance scheduling, and broadcast window management.',
    `event_start_time` TIMESTAMP COMMENT 'Scheduled timestamp for the official start of the main event (e.g., opening whistle, first pitch, curtain up). The principal real-world business event timestamp for this production schedule.',
    `event_type` STRING COMMENT 'Classification of the event being produced. Determines the production template, staffing model, and broadcast requirements. PPV (Pay-Per-View) events carry additional broadcast coordination requirements. [ENUM-REF-CANDIDATE: league_match|playoff_match|cup_final|concert|esports|ppv_event|exhibition — promote to reference product]',
    `halftime_duration_minutes` STRING COMMENT 'Planned duration in minutes of the halftime or intermission break. Governed by league CBA (Collective Bargaining Agreement) and broadcast commercial break requirements.',
    `halftime_stage_config` STRING COMMENT 'Stage layout configuration for the halftime or intermission performance. Determines field/court protection requirements, rigging points, and changeover time from competition surface. [ENUM-REF-CANDIDATE: center_stage|end_stage|thrust|in_the_round|field_full|court_full|no_stage — 7 candidates stripped; promote to reference product]',
    `halftime_start_time` TIMESTAMP COMMENT 'Scheduled timestamp for the start of the halftime or intermission break. Drives performer cue, stage crew deployment, and sponsor activation window execution.',
    `is_broadcast_live` BOOLEAN COMMENT 'Indicates whether the event is being broadcast live (True) or is a tape-delayed or pre-recorded production (False). Affects broadcast go-live coordination and OB truck scheduling.',
    `is_ppv` BOOLEAN COMMENT 'Indicates whether this event is distributed as a PPV (Pay-Per-View) broadcast. Triggers additional DRM controls, access entitlement validation, and revenue share reporting obligations.',
    `media_accreditation_deadline` TIMESTAMP COMMENT 'Deadline timestamp by which media representatives must complete accreditation and credential check-in at the venue. Drives press operations and broadcast partner access management.',
    `national_anthem_cue_time` TIMESTAMP COMMENT 'Scheduled timestamp for the national anthem performance cue. Broadcast-critical timing element coordinated with the OB truck director and league operations.',
    `ob_truck_arrival_time` TIMESTAMP COMMENT 'Scheduled timestamp for the OB (Outside Broadcast) truck to arrive at the venue for broadcast setup and signal testing. Drives broadcast production crew scheduling and venue loading dock coordination.',
    `player_walkout_time` TIMESTAMP COMMENT 'Scheduled timestamp for the athlete or team walkout onto the field, court, or stage. Broadcast-critical cue that triggers pre-match ceremony sequences and sponsor LED activations.',
    `post_event_start_time` TIMESTAMP COMMENT 'Scheduled timestamp for the commencement of post-event activities including trophy presentations, press conferences, fan meet-and-greet, and sponsor hospitality wrap-up.',
    `pre_show_start_time` TIMESTAMP COMMENT 'Scheduled timestamp for the commencement of pre-show entertainment programming (e.g., opening acts, fan activation zones, national anthem, player warm-up ceremonies).',
    `production_type` STRING COMMENT 'Classification of the production context. home and away apply to league fixtures; neutral_site for finals and showcase events; studio for non-live productions; virtual for esports or digital-only events.. Valid values are `home|away|neutral_site|studio|virtual`',
    `schedule_lock_timestamp` TIMESTAMP COMMENT 'Timestamp at which the production schedule was formally locked and frozen for game-day execution. No further edits are permitted after this point without an approved change request.',
    `schedule_name` STRING COMMENT 'Human-readable name or title for this production schedule (e.g., NBA Finals Game 5 – Chase Center Run-of-Show v3). Used for identification in planning tools and communications.',
    `schedule_reference_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this production schedule across operational systems. Used by event production teams, broadcast partners, and venue operations for cross-system coordination.. Valid values are `^PS-[A-Z0-9]{4,12}-[0-9]{4}$`',
    `schedule_status` STRING COMMENT 'Current lifecycle state of the production schedule. Drives workflow routing and edit permissions. locked indicates the schedule has been frozen for game-day execution. [ENUM-REF-CANDIDATE: draft|pending_approval|approved|locked|in_progress|completed|cancelled — promote to reference product]',
    `schedule_version` STRING COMMENT 'Monotonically incrementing version number of the production schedule. Incremented each time the schedule is revised and re-issued. Version 1 is the initial approved plan.',
    `security_briefing_time` TIMESTAMP COMMENT 'Scheduled timestamp for the pre-event security briefing with venue security, law enforcement liaisons, and event safety officers. Required for OSHA and ADA compliance documentation.',
    `sponsor_activation_window_end` TIMESTAMP COMMENT 'Scheduled end timestamp for sponsor activation activities. Marks the close of the contractual activation window for fulfilment reporting and ROI (Return on Investment) measurement.',
    `sponsor_activation_window_start` TIMESTAMP COMMENT 'Scheduled start timestamp for sponsor activation activities within the venue (e.g., branded fan zones, product sampling, LED board takeovers). Linked to sponsorship deal fulfilment obligations.',
    `technical_rider_notes` STRING COMMENT 'Free-text summary of the halftime or pre-show performers technical rider requirements including audio specifications, lighting rigs, pyrotechnics, video wall usage, and power requirements.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp at which this production schedule record was most recently modified. Used for change tracking, version audit, and downstream incremental data pipeline processing.',
    `venue_clearance_time` TIMESTAMP COMMENT 'Scheduled timestamp by which all fans, non-essential staff, and performers must have vacated the venue. Drives security staffing, transport coordination, and venue handback to facility management.',
    `venue_setup_start_time` TIMESTAMP COMMENT 'Scheduled timestamp for the commencement of pre-event venue setup activities including stage rigging, AV installation, field/court preparation, and sponsor activation builds.',
    `vip_hospitality_start_time` TIMESTAMP COMMENT 'Scheduled timestamp for the opening of VIP (Very Important Person) hospitality suites and premium experience areas. Drives catering, host staffing, and sponsor entertainment obligations.',
    `weather_contingency_plan` STRING COMMENT 'Designated contingency plan for adverse weather conditions applicable to outdoor or open-air venues. Drives communication protocols with fans, broadcasters, and league operations.. Valid values are `none|indoor_fallback|postpone|delay|cancellation_protocol`',
    CONSTRAINT pk_production_schedule PRIMARY KEY(`production_schedule_id`)
) COMMENT 'Operational entity managing the game-day/event-day production run-of-show for a fixture. Covers pre-event setup windows, doors-open coordination, pre-show entertainment, halftime/intermission programming (performer, duration, stage configuration, technical rider), post-event activities, and venue clearance timelines. Captures schedule version, production coordinator, broadcast go-live time, OB truck arrival, schedule lock timestamp, and sponsor activation windows. Serves as the execution plan distinct from fixture identity — owned by event production team.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`participant` (
    `participant_id` BIGINT COMMENT 'Unique surrogate identifier for each event participant record. Primary key for the event_participant data product in the Silver Layer lakehouse.',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Lineup management, broadcast feature flagging, appearance fee processing, and eligibility verification all require knowing which athlete_profile is the event participant. entity_id is polymorphic (ent',
    `calendar_id` BIGINT COMMENT 'Reference to the parent fixture or live event to which this participant is linked. Establishes the core association between participant and event.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Event participants carry appearance_fee_amount requiring cost center allocation for AP processing and talent cost tracking. Finance teams in sports entertainment allocate appearance fees to cost cente',
    `eligibility_certification_id` BIGINT COMMENT 'Foreign key linking to compliance.eligibility_certification. Business justification: Event participants (athletes, performers) must have verified eligibility certifications before participation is confirmed. event_participant has eligibility_status and eligibility_verified_date fields',
    `eligibility_status_id` BIGINT COMMENT 'Foreign key linking to athlete.eligibility_status. Business justification: Game-day eligibility verification is a mandatory compliance process: leagues must confirm each athletes authoritative eligibility_status record before allowing participation. Replaces the denormalize',
    `fixture_id` BIGINT COMMENT 'Foreign key linking to event.fixture. Business justification: event_participant.event_id is a raw/legacy column referencing the specific fixture to which an athlete, team, or performer is linked. event_participant is an association entity linking participants to',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: When event participants are franchises/teams, a direct franchise_id FK enables franchise-level participation reporting, eligibility verification, and revenue attribution. League operations track franc',
    `nil_agreement_id` BIGINT COMMENT 'Foreign key linking to athlete.nil_agreement. Business justification: Per-event NIL compliance verification requires knowing which specific nil_agreement governs an athletes appearance rights, broadcast usage, and in-venue activation for that event. The existing nil_ag',
    `replacement_participant_id` BIGINT COMMENT 'Reference to the event_participant record of the entity that replaced this participant following a withdrawal or disqualification. Enables lineage tracking of substitutions and replacements for broadcast and competition governance.',
    `season_id` BIGINT COMMENT 'Reference to the league season or competition season under which this participation record is governed. Supports season-level reporting and fixture calendar alignment.',
    `accreditation_code` STRING COMMENT 'Official accreditation or credential code issued to the participant for venue access and event operations purposes. Sourced from the venue access control system (Ticketmaster/AXS). Required for gate access, broadcast zone entry, and VIP area clearance.. Valid values are `^[A-Z0-9]{4,20}$`',
    `actual_end_time` TIMESTAMP COMMENT 'Actual date and time when the participants competition or performance concluded. Used for duration calculation, broadcast scheduling, and post-event reconciliation.',
    `actual_start_time` TIMESTAMP COMMENT 'Actual date and time when the participants competition or performance commenced. Compared against scheduled_start_time for operational punctuality reporting and broadcast SLA compliance.',
    `appearance_fee_amount` DECIMAL(18,2) COMMENT 'Contracted appearance fee or performance guarantee amount payable to the participant for this event, denominated in appearance_fee_currency. Confidential financial data. Used for event cost management, EBITDA reporting, and SAP S/4HANA FI/CO reconciliation.',
    `appearance_fee_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the appearance fee or performance guarantee payable to the participant for this event. Confidential financial data. Applicable primarily to entertainment performers and exhibition athletes.. Valid values are `^[A-Z]{3}$`',
    `broadcast_feature_flag` BOOLEAN COMMENT 'Indicates whether this participant has been designated as a featured participant for broadcast production purposes (e.g., pre-match spotlight, in-game feature segment, post-match interview). Consumed by Dalet Galaxy broadcast workflow and content production teams.',
    `competition_result` STRING COMMENT 'Official outcome of the event for this participant as determined by the officiating body. Win, loss, or draw for standard fixtures; no_contest for abandoned events; disqualified for rule violations; walkover for uncontested advancement. Populated post-event.. Valid values are `win|loss|draw|no_contest|disqualified|walkover`',
    `contract_type` STRING COMMENT 'Classification of the contractual arrangement under which the participant is engaged for this event. CBA (Collective Bargaining Agreement) player contracts are governed by league CBAs; guest_performer applies to entertainment acts; exhibition applies to non-competitive appearances; developmental applies to academy or minor league participants. Confidential business data.. Valid values are `standard_player|cba_player|guest_performer|exhibition|amateur|developmental`',
    `crm_contact_reference` STRING COMMENT 'Salesforce CRM contact or account identifier for the participant or their management entity. Enables fan engagement, sponsor activation, and NIL campaign targeting through Adobe Experience Platform and Salesforce CRM.. Valid values are `^[A-Z0-9]{10,20}$`',
    `eligibility_verified_date` DATE COMMENT 'Date on which the participants eligibility for this event was formally verified by the league compliance or event operations team. Supports audit trail requirements under governing body regulations.',
    `entity_reference` BIGINT COMMENT 'Reference to the athlete, team, performer, or competing entity participating in the event. Polymorphic identifier resolved by entity_type.',
    `entity_type` STRING COMMENT 'Discriminator indicating whether the participant is an individual athlete, a team, a musical performer, a support act, or a wildcard entry. Drives downstream routing to broadcast, ticketing, and fan engagement domains.. Valid values are `athlete|team|performer|act|wildcard_entry`',
    `entry_method` STRING COMMENT 'Method by which the participant qualified or was selected to participate in the event. Direct qualification indicates earned entry through league standings; wildcard indicates discretionary selection; invitation applies to exhibition and all-star events; playoff_seed applies to post-season competition; draft applies to league draft events; bid applies to hosted events. [ENUM-REF-CANDIDATE: direct_qualification|wildcard|invitation|playoff_seed|draft|bid|other — promote to reference product]. Valid values are `direct_qualification|wildcard|invitation|playoff_seed|draft|bid`',
    `home_venue_flag` BOOLEAN COMMENT 'Indicates whether the event is being held at the participants designated home venue. True for home fixtures; False for away or neutral venue fixtures. Drives ticketing allocation, fan engagement targeting, and revenue attribution.',
    `hudl_profile_code` STRING COMMENT 'Unique identifier linking this participant to their performance analytics profile in SportsCode/Hudl. Enables downstream performance video analysis, WAR (Wins Above Replacement), QBR (Quarterback Rating), and ERA (Earned Run Average) metric computation for this event.. Valid values are `^[A-Z0-9-]{4,30}$`',
    `is_captain_or_lead` BOOLEAN COMMENT 'Indicates whether the participant holds the captain designation (sports) or lead performer designation (entertainment) for this specific event. True when the participant is the designated captain or headlining lead.',
    `jersey_number` STRING COMMENT 'Official jersey or kit number assigned to the athlete or team representative for this specific event. Applicable to sports fixtures. Null for entertainment events. Sourced from league registration systems.',
    `lineup_confirmed` BOOLEAN COMMENT 'Indicates whether the submitted lineup has been officially confirmed and accepted by the league or event operations team. True when confirmed; False when pending or rejected.',
    `lineup_submission_timestamp` TIMESTAMP COMMENT 'Date and time when the official lineup, roster, or set list was formally submitted by the participants management or coaching staff to the league or event organiser. Critical for compliance with pre-match lineup deadlines mandated by governing bodies.',
    `media_rights_clearance_status` STRING COMMENT 'Status of media rights clearance for this participants appearance in the event. Cleared indicates full broadcast and digital distribution rights are confirmed; pending indicates rights are under negotiation; restricted indicates partial rights only; blocked indicates no broadcast rights. Consumed by content and broadcast domains for DRM (Digital Rights Management) enforcement.. Valid values are `cleared|pending|restricted|blocked`',
    `nationality_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the nationality of the participant or the country of registration for a team. Used for international competition eligibility, governing body reporting, and broadcast rights geo-targeting.. Valid values are `^[A-Z]{3}$`',
    `nil_agreement_active` BOOLEAN COMMENT 'Indicates whether the participant has an active NIL (Name, Image and Likeness) agreement in effect at the time of this event. Relevant for collegiate and amateur participants. Drives content rights, merchandise licensing, and sponsorship activation restrictions.',
    `notes` STRING COMMENT 'Free-text operational notes recorded by event operations staff regarding this participants involvement in the event. May include special requirements, late changes, officiating observations, or post-event reconciliation comments.',
    `participant_role` STRING COMMENT 'Designates the competitive or performance role of the participant within the event. For sports fixtures: home_team or away_team. For concerts and live experiences: headliner, support_act. Wildcard and neutral apply to tournament and exhibition contexts.. Valid values are `home_team|away_team|headliner|support_act|wildcard|neutral`',
    `participation_status` STRING COMMENT 'Current lifecycle status of the participants involvement in the event. Confirmed indicates full clearance; withdrawn indicates voluntary or involuntary removal; suspended reflects disciplinary action per league CBA or governing body ruling; TBD (To Be Determined) indicates pending confirmation; disqualified reflects post-event ruling; pending_review indicates an active compliance or eligibility review. [ENUM-REF-CANDIDATE: confirmed|withdrawn|suspended|tbd|disqualified|pending_review — promote to reference product]. Valid values are `confirmed|withdrawn|suspended|tbd|disqualified|pending_review`',
    `performance_slot_order` STRING COMMENT 'Sequential order in which the participant is scheduled to perform or compete within the event programme. For concerts: set list order. For multi-bout events: bout sequence. Null for single-match sports fixtures.',
    `ranking_points_earned` DECIMAL(18,2) COMMENT 'Official ranking or standing points awarded to the participant as a result of their performance in this event. Used to update league tables, world rankings, or tournament standings. Governed by the relevant league or governing body points allocation rules.',
    `record_created_timestamp` TIMESTAMP COMMENT 'Date and time when this event participant record was first created in the Silver Layer lakehouse. Supports audit trail, data lineage, and GDPR data subject request processing.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Date and time when this event participant record was most recently modified. Supports incremental data processing, change data capture, and audit trail requirements in the Databricks Silver Layer.',
    `scheduled_start_time` TIMESTAMP COMMENT 'Planned date and time when the participants competition bout, match, or performance set is scheduled to begin. Distinct from the overall event start time when multiple participants perform sequentially.',
    `score` STRING COMMENT 'Final score, points, or goals recorded for this participant in the event. Applicable to sports fixtures. Null for entertainment events. Sourced from official match data systems.',
    `seeding_rank` STRING COMMENT 'Numeric seeding rank assigned to the participant for tournament bracket placement or competition draw purposes. Lower values indicate higher seeding. Null for non-seeded events such as regular season fixtures or concerts.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this participant record was ingested into the Silver Layer. Supports data lineage, reconciliation, and master data management across SAP S/4HANA, Ticketmaster/AXS, Salesforce CRM, Dalet Galaxy, Archtics, and SportsCode/Hudl. [ENUM-REF-CANDIDATE: SAP_S4HANA|TICKETMASTER|SALESFORCE_CRM|SUCCESSFACTORS|DALET_GALAXY|ARCHTICS|HUDL|MANUAL — 8 candidates stripped; promote to reference product]',
    `travel_origin_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the country from which the participant is travelling to the event. Used for logistics planning, visa and work permit compliance, and international governing body reporting.. Valid values are `^[A-Z]{3}$`',
    `uniform_color_code` STRING COMMENT 'Designated uniform or kit color code for the participant in this event (e.g., HOME, AWAY, THIRD, ALTERNATE). Ensures broadcast production and officiating clarity. Governed by league uniform regulations.. Valid values are `^[A-Z]{3,10}$`',
    `withdrawal_reason` STRING COMMENT 'Categorised reason for participant withdrawal from the event. Populated only when participation_status is withdrawn or disqualified. Supports injury reporting, disciplinary tracking, and force majeure documentation. [ENUM-REF-CANDIDATE: injury|suspension|personal_reasons|scheduling_conflict|disqualification|force_majeure|other — promote to reference product]. Valid values are `injury|suspension|personal_reasons|scheduling_conflict|disqualification|force_majeure`',
    `withdrawal_timestamp` TIMESTAMP COMMENT 'Date and time when the participants withdrawal or disqualification was officially recorded. Null when participation_status is not withdrawn or disqualified. Used for downstream broadcast, ticketing, and fan notification workflows.',
    CONSTRAINT pk_participant PRIMARY KEY(`participant_id`)
) COMMENT 'Association entity linking athletes, teams, performers, or competing entities to a specific fixture. Captures participant role (home team, away team, headliner, support act, wildcard entry), seeding rank, participation status (confirmed, withdrawn, suspended, TBD), lineup submission timestamp, and captain/lead performer designation. Serves as the SSOT for who is participating in each event — consumed by broadcast, ticketing, content, and fan engagement domains.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`officiating_assignment` (
    `officiating_assignment_id` BIGINT COMMENT 'Unique surrogate identifier for each officiating assignment record in the Silver layer lakehouse. Primary key for this transactional entity.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Officiating assignments carry explicit fee amounts (officiating_fee_amount, expense_allowance_amount) that must be allocated to a cost center for AP processing and cost tracking. Finance teams in spor',
    `credential_id` BIGINT COMMENT 'Foreign key linking to security.credential. Business justification: Officials assigned to fixtures must have valid credentials issued for restricted zone access. Officiating_assignment must reference the credential record to enable pre-match credential verification wo',
    `eligibility_certification_id` BIGINT COMMENT 'Foreign key linking to compliance.eligibility_certification. Business justification: Officials must hold valid eligibility certifications (referee licensing, governing body certification) before assignment confirmation. certification_level and certification_expiry_date are denormalize',
    `employee_id` BIGINT COMMENT 'Reference to the officiating assessor or evaluator who reviewed and rated the officials performance for this fixture.',
    `fixture_id` BIGINT COMMENT 'Reference to the specific fixture or event to which the official is assigned. Links this assignment to the event master data.',
    `league_id` BIGINT COMMENT 'Reference to the league or competition governing body under whose jurisdiction this officiating assignment is made.',
    `official_id` BIGINT COMMENT 'Reference to the officiating assessor or evaluator who reviewed and rated the officials performance for this fixture.',
    `officiating_crew_id` BIGINT COMMENT 'Foreign key linking to league.officiating_crew. Business justification: Individual officiating assignments must be linked to the crew they belong to for crew-level performance evaluation, conflict-of-interest clearance, and officiating body reporting. League officiating d',
    `primary_officiating_official_id` BIGINT COMMENT 'Reference to the match official (referee, linesman, VAR operator, TMO, judge, or scorer) being assigned to the fixture.',
    `season_id` BIGINT COMMENT 'Reference to the competitive season within which this officiating assignment falls, supporting season-level officiating analytics and compliance reporting.',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the assigned fixture will take place, used for logistics planning, travel arrangements, and venue-specific officiating protocols.',
    `assignment_date` DATE COMMENT 'The calendar date on which the officiating assignment was formally issued by the governing body or league officiating department.',
    `assignment_method` STRING COMMENT 'The method by which the official was assigned to this fixture — manual selection by officiating coordinator, automated rotation algorithm, rotational schedule, direct appointment by governing body, or emergency replacement.. Valid values are `manual|automated|rotational|appointed|emergency`',
    `assignment_reference_number` STRING COMMENT 'Externally-known alphanumeric reference code for this officiating assignment, used in league governance communications, official notifications, and compliance audit trails.. Valid values are `^[A-Z]{2,6}-OFF-[0-9]{4}-[0-9]{6}$`',
    `assignment_status` STRING COMMENT 'Current lifecycle status of the officiating assignment, tracking the workflow from initial proposal through confirmation, acceptance, or withdrawal. Supports governance and scheduling workflows.. Valid values are `proposed|confirmed|accepted|declined|withdrawn|replaced`',
    `confirmation_date` DATE COMMENT 'The date on which the assigned official formally confirmed acceptance of the assignment. Null if not yet confirmed.',
    `conflict_of_interest_flag` BOOLEAN COMMENT 'Indicates whether a potential conflict of interest has been identified for this official in relation to the assigned fixture (e.g., prior affiliation with a competing team, financial interest). True = conflict identified; False = no conflict.',
    `conflict_of_interest_notes` STRING COMMENT 'Free-text description of the nature of the identified conflict of interest, if applicable. Populated only when conflict_of_interest_flag is True. Treated as confidential governance data.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this officiating assignment record was first created in the system, providing the audit trail creation marker.',
    `crew_chief_flag` BOOLEAN COMMENT 'Indicates whether this official is designated as the crew chief or lead referee for the fixture. True = crew chief; False = supporting official.',
    `disciplinary_incident_flag` BOOLEAN COMMENT 'Indicates whether a disciplinary incident or formal complaint was raised in connection with this officiating assignment. True = incident recorded; False = no incident. Triggers governance review workflow.',
    `expense_allowance_amount` DECIMAL(18,2) COMMENT 'The approved expense allowance payable to the official for travel, accommodation, and per diem costs associated with this assignment, per governing body policy.',
    `fee_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the officiating fee amount (e.g., USD, EUR, GBP). Supports multi-currency operations across global leagues.. Valid values are `^[A-Z]{3}$`',
    `fixture_competition_tier` STRING COMMENT 'The competition tier of the fixture to which the official is assigned, used to validate that the officials certification level meets the minimum requirement for the competition tier. [ENUM-REF-CANDIDATE: international|domestic_top_flight|domestic_second_tier|cup|playoff|friendly|exhibition — 7 candidates stripped; promote to reference product]',
    `fixture_date` DATE COMMENT 'The scheduled calendar date of the fixture to which the official is assigned. Denormalized from the fixture record to support assignment scheduling and conflict detection without requiring a join.',
    `fixture_kickoff_time` TIMESTAMP COMMENT 'The scheduled start date and time of the fixture, including timezone offset. Used for official arrival time planning, pre-match briefing scheduling, and SLA compliance.',
    `governing_body_code` STRING COMMENT 'Code identifying the sports governing body or league office responsible for this officiating assignment and the applicable officiating standards (e.g., FIFA, NFL, NBA, NHL, MLB, MLS). [ENUM-REF-CANDIDATE: FIFA|NFL|NBA|NHL|MLB|MLS|UFC|ATP|IOC|CAS — 10 candidates stripped; promote to reference product]',
    `notes` STRING COMMENT 'Free-text field for additional operational notes related to this officiating assignment, such as special instructions from the governing body, venue-specific protocols, or crew coordination details.',
    `notification_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the official was notified of the assignment, supporting SLA compliance tracking for officiating notification windows.',
    `official_role` STRING COMMENT 'The specific officiating role assigned to the official for this fixture (e.g., Referee, Assistant Referee, Fourth Official, VAR Operator, TMO, Linesman, Judge, Scorer, Video Review Official). [ENUM-REF-CANDIDATE: referee|assistant_referee|fourth_official|var_operator|tmo|linesman|judge|scorer|video_review_official|head_linesman|back_judge|umpire — promote to reference product]',
    `officiating_crew_size` STRING COMMENT 'The total number of officials assigned to the fixture as part of the officiating crew, including all roles (referee, assistants, VAR, TMO, etc.).',
    `officiating_fee_amount` DECIMAL(18,2) COMMENT 'The gross fee payable to the official for this assignment, as defined by the governing bodys officiating pay scale or collective bargaining agreement (CBA). Expressed in the leagues base currency.',
    `performance_rating` DECIMAL(18,2) COMMENT 'Numeric performance rating assigned to the official for this fixture by the officiating assessor or governing body evaluator, typically on a standardized scale (e.g., 1.00–10.00). Supports officiating quality management and career development.',
    `post_match_report_date` DATE COMMENT 'The date on which the post-match officiating report was submitted by the official. Null if not yet submitted.',
    `post_match_report_reference` STRING COMMENT 'Reference identifier or document number for the post-match officiating report submitted by the lead official after the fixture. Links to the report stored in the DAM or document management system.',
    `post_match_report_submitted_flag` BOOLEAN COMMENT 'Indicates whether the post-match officiating report has been submitted by the official following the fixture. True = submitted; False = pending. Supports compliance monitoring.',
    `pre_match_briefing_timestamp` TIMESTAMP COMMENT 'The scheduled date and time of the pre-match officiating crew briefing, where the lead referee reviews match protocols, VAR/TMO procedures, and competition-specific directives with the crew.',
    `replacement_reason` STRING COMMENT 'The reason an official was replaced or withdrew from this assignment. Populated only when assignment_status is replaced or withdrawn. Supports officiating continuity and governance reporting. [ENUM-REF-CANDIDATE: injury|illness|conflict_of_interest|scheduling_conflict|disciplinary|withdrawal|other — 7 candidates stripped; promote to reference product]',
    `tmo_enabled_flag` BOOLEAN COMMENT 'Indicates whether a Television Match Official (TMO) is active for this fixture, applicable in rugby and other sports using TMO review protocols.',
    `travel_origin_city` STRING COMMENT 'The city from which the official will travel to the fixture venue, used for logistics planning and travel cost estimation.',
    `travel_required_flag` BOOLEAN COMMENT 'Indicates whether the official requires travel arrangements (flights, accommodation) to attend the assigned fixture. Supports logistics and expense management.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this officiating assignment record was last modified, supporting change tracking and audit compliance.',
    `var_enabled_flag` BOOLEAN COMMENT 'Indicates whether Video Assistant Referee (VAR) technology is active for this fixture, determining whether a VAR operator role is required in the officiating crew.',
    `wada_compliance_verified_flag` BOOLEAN COMMENT 'Indicates whether the assigned officials WADA compliance status (anti-doping clearance) has been verified prior to the fixture. Applicable for international competitions. True = verified; False = not verified.',
    CONSTRAINT pk_officiating_assignment PRIMARY KEY(`officiating_assignment_id`)
) COMMENT 'Transactional entity managing the assignment of match officials — referees, linesmen, VAR operators, TMO (Television Match Official), judges, and scorers — to specific fixtures. Captures official role, assignment date, confirmation status, governing body certification level, conflict-of-interest flag, and post-match officiating report reference. Supports league governance, compliance with officiating standards (FIFA, NFL, NBA), and VAR/TMO review workflows.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`event_incident` (
    `event_incident_id` BIGINT COMMENT 'Unique surrogate identifier for each in-event incident record. Primary key for the event_incident data product in the Silver Layer lakehouse.',
    `athlete_athlete_profile_id` BIGINT COMMENT 'Identifier of the athlete directly involved in the incident (e.g., player receiving a red card, injured athlete). Null for non-athlete incidents such as crowd disturbances or equipment failures. Links to the athlete master data product.',
    `athlete_profile_id` BIGINT COMMENT 'Identifier of the athlete directly involved in the incident (e.g., player receiving a red card, injured athlete). Null for non-athlete incidents such as crowd disturbances or equipment failures. Links to the athlete master data product.',
    `contingent_worker_id` BIGINT COMMENT 'Foreign key linking to workforce.contingent_worker. Business justification: Event-day incidents frequently involve contracted security, temporary event staff, or freelance crew who are contingent workers. OSHA recordability and insurance claim processes require identifying th',
    `disciplinary_action_id` BIGINT COMMENT 'Foreign key linking to league.disciplinary_action. Business justification: Incident-to-disciplinary-ruling traceability is a named regulatory requirement. League integrity officers and governing bodies require a direct link from the originating incident record to the resulti',
    `employee_id` BIGINT COMMENT 'Identifier of the workforce member (security officer, medical staff, operations manager, referee, or event coordinator) who first reported or logged the incident. Links to the workforce/employee master data product.',
    `event_fixture_id` BIGINT COMMENT 'Identifier of the parent live sports or entertainment event during which this incident occurred. Links to the event master data product.',
    `fixture_id` BIGINT COMMENT 'Identifier of the parent live sports or entertainment event during which this incident occurred. Links to the event master data product.',
    `officiating_crew_id` BIGINT COMMENT 'Foreign key linking to league.officiating_crew. Business justification: VAR/TMO incidents and on-field incidents must be linked to the officiating crew responsible for the match. League officiating performance reviews and incident accountability reports require this link ',
    `reported_by_staff_employee_id` BIGINT COMMENT 'Identifier of the workforce member (security officer, medical staff, operations manager, referee, or event coordinator) who first reported or logged the incident. Links to the workforce/employee master data product.',
    `security_incident_id` BIGINT COMMENT 'Foreign key linking to security.security_incident. Business justification: Event incidents with security dimensions (pitch invasions, crowd disturbances, player altercations) must reference the corresponding security incident record for cross-domain regulatory reporting, ins',
    `venue_id` BIGINT COMMENT 'Identifier of the venue or facility where the incident took place. Supports venue operations reporting and ADA/OSHA compliance tracking.',
    `broadcast_delay_minutes` STRING COMMENT 'Duration in minutes that the live broadcast was delayed or interrupted as a result of this incident. Zero if no broadcast delay occurred. Supports RSN and OTT rights holder SLA reporting and FCC compliance.',
    `broadcast_impact` BOOLEAN COMMENT 'Indicates whether the incident caused a disruption to live broadcast operations (signal loss, unplanned cut-away, OB unit failure, broadcast delay). Triggers notification to broadcast rights holders and Dalet Galaxy media workflow.',
    `created_at` TIMESTAMP COMMENT 'Timestamp when this incident record was first created in the system. Audit trail field for data lineage, Silver Layer ingestion tracking, and compliance record retention.',
    `detected_at` TIMESTAMP COMMENT 'Timestamp when the incident was formally detected and logged by operations staff or automated monitoring systems. May differ from occurred_at when there is a reporting lag. Used to measure detection latency for SLA compliance.',
    `fan_impact_count` STRING COMMENT 'Estimated number of fans directly affected by the incident (e.g., evacuated, medically treated, displaced from seating). Used for post-event fan experience reporting, NPS impact analysis, and insurance liability assessment.',
    `field_surface_condition` STRING COMMENT 'Assessed condition of the playing surface or field at the time of the incident. Populated for field/surface condition change incidents and weather delays. Supports governing body match-day inspection reporting and player safety compliance. [ENUM-REF-CANDIDATE: playable|unplayable|waterlogged|frozen|damaged|under_repair|acceptable|not_applicable — 8 candidates stripped; promote to reference product]',
    `game_delay_duration_minutes` STRING COMMENT 'Total duration in minutes that the event or match was delayed or suspended as a direct result of this incident. Zero if no delay occurred. Critical for broadcast scheduling, insurance claims, and governing body reporting.',
    `incident_description` STRING COMMENT 'Free-text narrative description of the incident, capturing contextual details not covered by structured fields. Authored by the reporting operations staff member at time of logging. Used in post-event reports, insurance documentation, and governing body submissions.',
    `incident_status` STRING COMMENT 'Current lifecycle state of the incident record, tracking workflow from initial detection through resolution and post-event closure. Drives operational dashboards and compliance reporting completeness checks.. Valid values are `open|in_progress|resolved|closed|escalated`',
    `incident_type` STRING COMMENT 'Categorical classification of the incident nature. Covers the full spectrum of in-event operational incidents. [ENUM-REF-CANDIDATE: red_card|ejection|player_injury|crowd_disturbance|equipment_failure|weather_delay|power_outage|medical_emergency|field_condition_change|security_breach|fire_alarm|structural_concern|broadcast_failure|protest|other — promote to reference product]',
    `insurance_claim_reference` STRING COMMENT 'External reference number assigned by the insurance carrier for the claim associated with this incident. Populated once a claim is formally opened. Confidential business data used for financial reconciliation in SAP S/4HANA.',
    `insurance_claim_required` BOOLEAN COMMENT 'Indicates whether this incident is expected to generate an insurance claim (event cancellation, liability, workers compensation, medical). Triggers insurance documentation workflow and financial provisioning in SAP S/4HANA FI.',
    `location_section` STRING COMMENT 'Specific seating section, gate, or sub-area identifier within the venue zone where the incident occurred. Aligns with Archtics venue seating and inventory management section codes for precise spatial reporting.',
    `location_zone` STRING COMMENT 'Designated zone or area within the venue where the incident occurred (e.g., playing_field, north_stand, concourse_level_2, media_tribune, locker_room, parking_lot, broadcast_compound). Supports venue operations analysis and ADA/OSHA compliance mapping.',
    `match_clock_time_seconds` STRING COMMENT 'Elapsed match or event clock time in seconds at the moment the incident occurred. Enables precise temporal correlation with broadcast footage, VAR/TMO review, and performance analytics in SportsCode/Hudl. Null for non-competition events (concerts, ceremonies).',
    `match_period` STRING COMMENT 'Designated period or segment of the event during which the incident occurred. Supports competition governance reporting and broadcast clip indexing. full_event used for non-segmented live experiences such as concerts. [ENUM-REF-CANDIDATE: pre_match|1st_half|2nd_half|extra_time_1|extra_time_2|penalty_shootout|intermission|post_match|full_event — 9 candidates stripped; promote to reference product]',
    `media_coverage_flag` BOOLEAN COMMENT 'Indicates whether the incident received external media coverage (broadcast, digital, print). Triggers communications and PR response workflow. Supports reputation management and sponsor impact assessment.',
    `occurred_at` TIMESTAMP COMMENT 'Wall-clock timestamp (ISO 8601 with timezone offset) recording the precise real-world moment the incident was first observed or reported. Principal business event timestamp for the incident lifecycle. Distinct from match clock time.',
    `ped_related` BOOLEAN COMMENT 'Indicates whether the incident involves a suspected or confirmed Performance Enhancing Drug (PED) violation or related medical event. Triggers mandatory WADA reporting workflow and CAS arbitration tracking.',
    `precipitation_mm` DECIMAL(18,2) COMMENT 'Recorded precipitation level in millimetres at the time of the incident. Supports weather-delay documentation, field/surface condition assessment, and insurance claim substantiation.',
    `reference_number` STRING COMMENT 'Externally-known alphanumeric reference code assigned to the incident at time of occurrence, used for cross-system tracking, insurance documentation, and regulatory reporting. Format: INC-{YYYY}-{NNNNNN}.. Valid values are `^INC-[0-9]{4}-[0-9]{6}$`',
    `regulatory_report_submitted` BOOLEAN COMMENT 'Indicates whether the required regulatory report has been formally submitted to the relevant governing body or authority. Null when regulatory_reporting_required is False. Supports compliance audit and SLA tracking.',
    `regulatory_report_submitted_at` TIMESTAMP COMMENT 'Timestamp when the regulatory report was formally submitted to the governing body or authority. Null if not yet submitted. Used to verify compliance with mandatory reporting deadlines (e.g., OSHA 8-hour fatality reporting window).',
    `regulatory_reporting_required` BOOLEAN COMMENT 'Indicates whether this incident triggers a mandatory regulatory reporting obligation to an external governing body or regulatory authority (OSHA, FIFA, NFL, NBA, WADA, FCC, etc.). Drives automated compliance workflow routing in post-event reconciliation.',
    `resolution_notes` STRING COMMENT 'Free-text notes documenting the resolution actions taken, outcome achieved, and any follow-up actions required. Populated at incident closure. Supports post-event reconciliation, lessons-learned analysis, and insurance claim documentation.',
    `resolved_at` TIMESTAMP COMMENT 'Timestamp when the incident was operationally resolved and normal event operations resumed or the incident was formally closed. Null if incident remains open. Used to calculate response duration and SLA adherence.',
    `response_action_taken` STRING COMMENT 'Structured description of the primary operational response action executed in reaction to the incident (e.g., medical_evacuation, play_suspended, crowd_dispersal, equipment_replaced, power_restored, venue_section_cleared, VAR_review_initiated). [ENUM-REF-CANDIDATE: medical_evacuation|play_suspended|crowd_dispersal|equipment_replaced|power_restored|venue_section_cleared|var_review_initiated|match_abandoned|emergency_services_called|shelter_in_place — promote to reference product]',
    `response_team_type` STRING COMMENT 'Category of the primary response team deployed to address the incident. Supports post-event resource utilization analysis and emergency preparedness planning. [ENUM-REF-CANDIDATE: medical|security|fire_safety|technical|operations|governing_body|external_emergency_services|broadcast — 8 candidates stripped; promote to reference product]',
    `severity_level` STRING COMMENT 'Operational severity rating assigned to the incident at time of occurrence, driving escalation protocols, response resource allocation, and regulatory reporting obligations. Critical = life-safety or event-stopping; High = significant operational impact; Medium = notable but manageable; Low = minor; Informational = logged for record only.. Valid values are `critical|high|medium|low|informational`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this incident record originated or was ingested into the Silver Layer. Supports data lineage, reconciliation, and Silver Layer provenance tracking. [ENUM-REF-CANDIDATE: venue_ops|ticketmaster|salesforce_crm|sap_s4hana|manual_entry|broadcast_system|security_system — 7 candidates stripped; promote to reference product]',
    `subtype` STRING COMMENT 'Secondary classification providing granular detail within the incident type (e.g., within weather_delay: lightning, extreme_heat, heavy_rain, high_wind; within player_injury: concussion, fracture, laceration). [ENUM-REF-CANDIDATE: lightning|extreme_heat|heavy_rain|high_wind|concussion|fracture|laceration|cardiac|crowd_surge|pitch_invasion — promote to reference product]',
    `temperature_celsius` DECIMAL(18,2) COMMENT 'Recorded ambient air temperature in degrees Celsius at the venue at the time of the incident. Critical for heat-related medical incidents, weather-delay justification, and OSHA heat illness prevention compliance.',
    `updated_at` TIMESTAMP COMMENT 'Timestamp of the most recent update to this incident record. Supports change data capture (CDC) in the Databricks Silver Layer and audit trail maintenance for compliance reporting.',
    `var_tmo_outcome` STRING COMMENT 'Result of the Video Assistant Referee (VAR) or Television Match Official (TMO) review triggered by this incident. Null when var_tmo_review_triggered is False. Supports competition governance reporting and post-match analysis.. Valid values are `decision_upheld|decision_overturned|inconclusive|not_applicable`',
    `var_tmo_review_triggered` BOOLEAN COMMENT 'Indicates whether the incident triggered a Video Assistant Referee (VAR) or Television Match Official (TMO) review process. Applicable to football, rugby, and other sports with video review protocols. Supports competition governance and SportsCode/Hudl video analysis integration.',
    `weather_condition` STRING COMMENT 'Prevailing weather condition at the venue at the time the incident occurred. Mandatory for weather-related incidents (lightning, extreme heat, heavy rain); populated for all outdoor events. indoor_na for fully enclosed venues. Supports insurance documentation and governing body weather-delay reporting. [ENUM-REF-CANDIDATE: clear|cloudy|rain|heavy_rain|thunderstorm|lightning|snow|fog|extreme_heat|high_wind|hail|indoor_na — 12 candidates stripped; promote to reference product]',
    `wind_speed_kmh` DECIMAL(18,2) COMMENT 'Recorded wind speed in kilometres per hour at the venue at the time of the incident. Used for weather-delay justification, structural safety assessments, and insurance documentation.',
    CONSTRAINT pk_event_incident PRIMARY KEY(`event_incident_id`)
) COMMENT 'Transactional entity recording significant in-event incidents requiring operational response — red cards, ejections, injuries requiring stoppage, crowd disturbances, equipment failures, weather delays (lightning, extreme heat), power outages, medical emergencies, and field/surface condition changes. Captures incident type, match clock time, severity level, response action taken, weather conditions at time of incident, regulatory reporting obligation flag (OSHA, governing body), resolution timestamp, and game-delay duration if applicable. Supports post-event reporting, safety compliance, and insurance documentation.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`venue_assignment` (
    `venue_assignment_id` BIGINT COMMENT 'Unique surrogate identifier for the event-to-venue assignment record. Primary key for this association entity.',
    `approved_by_user_employee_id` BIGINT COMMENT 'Business user identifier of the person who formally confirmed or approved this venue assignment, triggering downstream venue operations and ticketing workflows. Supports dual-control and approval audit requirements.',
    `calendar_id` BIGINT COMMENT 'Reference to the fixture or live event being assigned to a venue. Links to the event master record.',
    `capacity_config_id` BIGINT COMMENT 'Foreign key linking to venue.capacity_config. Business justification: When assigning a venue to an event, a specific capacity configuration (fire-code-approved sellable capacity, seating mode, ADA compliance) must be selected. This drives ticketing inventory allocation,',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Venue assignments include rental_fee_amount and revenue_share_pct — costs requiring cost center allocation. Finance teams track venue rental costs per cost center for facilities expense reporting, bud',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: Venue-event assignments configure which digital touchpoint handles ticketing and fan check-in for that specific event at that venue. event_venue_assignment.ticketing_system_venue_code is a denormaliza',
    `emergency_response_plan_id` BIGINT COMMENT 'Foreign key linking to security.emergency_response_plan. Business justification: Venue assignment confirmation for an event — especially neutral sites — triggers selection of the applicable emergency response plan. Regulatory requirements for large public gatherings mandate that t',
    `employee_id` BIGINT COMMENT 'Business user identifier of the person who created this venue assignment record, sourced from the identity management system. Supports accountability and audit trail requirements under SOX financial controls.',
    `fixture_id` BIGINT COMMENT 'Foreign key linking to event.fixture. Business justification: event_venue_assignment.event_id is a raw/legacy column referencing the specific fixture for which a venue is being assigned. The entity description states it links a fixture to its assigned venue. T',
    `naming_right_id` BIGINT COMMENT 'Foreign key linking to sponsorship.naming_right. Business justification: Naming rights compliance at venue assignment: when a venue is assigned to an event, the active naming rights agreement must be referenced to enforce broadcast mention requirements, signage specificati',
    `primary_venue_employee_id` BIGINT COMMENT 'Business user identifier of the person who created this venue assignment record, sourced from the identity management system. Supports accountability and audit trail requirements under SOX financial controls.',
    `venue_id` BIGINT COMMENT 'Reference to the venue facility being assigned to host the event. Links to the venue master record.',
    `wbs_element_id` BIGINT COMMENT 'Foreign key linking to finance.wbs_element. Business justification: Venue rental costs (rental_fee_amount) for specific event assignments are captured against WBS elements in project accounting. Finance teams use this link to include venue costs in event-level WBS act',
    `ada_accessible_seat_count` STRING COMMENT 'Number of ADA-compliant accessible seats allocated for this event at this venue configuration. Used by ticketing domain to configure accessible inventory in Archtics and ensure compliance with ADA minimum accessible seating ratios.',
    `ada_compliant` BOOLEAN COMMENT 'Indicates whether ADA accessibility compliance has been formally confirmed for this event at this venue, including accessible seating, ramps, restrooms, and concession access. Required for regulatory compliance reporting and venue operations preparation.',
    `approved_capacity` STRING COMMENT 'Maximum number of attendees approved for this specific event at this venue, reflecting the capacity configuration type. May differ from the venues total rated capacity due to event-specific restrictions, safety requirements, or reduced-capacity mandates. Used by ticketing domain to cap inventory in Archtics and Ticketmaster/AXS.',
    `assignment_code` STRING COMMENT 'Externally-known business identifier for this venue assignment, used in operational communications, venue operations work orders, and ticketing system configuration (e.g., Archtics seating inventory setup). Format: EVA- followed by 4-12 alphanumeric characters.. Valid values are `^EVA-[A-Z0-9]{4,12}$`',
    `assignment_effective_date` DATE COMMENT 'Calendar date from which this venue assignment is operationally effective. Venue operations teams use this date to begin facility preparation scheduling, and ticketing teams use it to open inventory configuration in Archtics.',
    `assignment_expiry_date` DATE COMMENT 'Calendar date after which this venue assignment is no longer valid. Used for provisional or alternate assignments that have a defined validity window. Null for confirmed primary assignments with no expiry.',
    `assignment_notes` STRING COMMENT 'Free-text operational notes related to this venue assignment, capturing special conditions, exceptions, or instructions for venue operations, ticketing, and broadcast teams that are not captured in structured fields.',
    `assignment_status` STRING COMMENT 'Current lifecycle state of the venue assignment. proposed indicates initial planning stage; confirmed indicates venue is locked and ticketing/operations may proceed; provisional indicates conditional confirmation pending contract or regulatory approval; cancelled indicates the assignment has been voided; superseded indicates replaced by a newer assignment record.. Valid values are `proposed|confirmed|provisional|cancelled|superseded`',
    `broadcast_infrastructure_ready` BOOLEAN COMMENT 'Indicates whether the venues broadcast infrastructure (OB (Outside Broadcast) unit connections, fiber feeds, camera positions, commentary positions) has been confirmed as ready for this event. Used by broadcast operations and Dalet Galaxy workflow planning.',
    `change_history_flag` BOOLEAN COMMENT 'Indicates whether this venue assignment record has been modified or superseded since initial creation, signaling that a prior assignment existed for this event. Used for audit trail tracking and downstream notification to venue operations and ticketing teams of venue changes.',
    `change_reason` STRING COMMENT 'Free-text description of the reason for a venue assignment change, such as venue unavailability, weather conditions, safety concerns, league mandate, or contractual renegotiation. Populated when change_history_flag is True.',
    `confirmation_timestamp` TIMESTAMP COMMENT 'Date and time when the venue assignment was formally confirmed, triggering downstream venue operations preparation and ticketing inventory configuration in Archtics. Null if assignment is still in proposed or provisional state.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this venue assignment record was first created in the system. Supports audit trail requirements and data lineage tracking per SOX financial controls.',
    `designation_type` STRING COMMENT 'Indicates whether this venue is the primary assigned venue, an alternate venue held in reserve, a neutral-site venue (neither teams home ground, common in playoff or championship contexts), or a backup venue activated only if the primary is unavailable.. Valid values are `primary|alternate|neutral_site|backup`',
    `event_date` DATE COMMENT 'Scheduled calendar date of the event at this venue. Denormalized here to support venue operations scheduling and facility resource planning without requiring a join to the event master record.',
    `field_setup_type` STRING COMMENT 'Specifies the physical configuration of the playing surface, court, or stage for this event. Determines sightline mapping, seating kill zones, and production logistics. standard applies to normal league-regulation field/court layout; concert and stage variants apply to live entertainment events. [ENUM-REF-CANDIDATE: standard|concert_stage|in_the_round|end_stage|thrust_stage|custom|floor_only|half_house — promote to reference product]. Valid values are `standard|concert_stage|in_the_round|end_stage|thrust_stage|custom`',
    `ga_section_enabled` BOOLEAN COMMENT 'Indicates whether General Admission (GA) standing sections are enabled for this event at this venue. Affects ticketing inventory configuration, crowd management planning, and OSHA safety compliance for standing areas.',
    `gate_open_time` TIMESTAMP COMMENT 'Scheduled date and time when venue gates open to the public for this event. Used by venue operations, security staffing, and access control configuration in Ticketmaster/AXS gate scan systems.',
    `load_in_date` DATE COMMENT 'Date on which production equipment, staging, and event infrastructure begins loading into the venue. Critical for venue operations scheduling, HVAC (Heating Ventilation and Air Conditioning) activation, and BMS (Building Management System) configuration.',
    `load_out_date` DATE COMMENT 'Date by which all production equipment and event infrastructure must be removed from the venue. Used for venue turnaround scheduling and back-to-back event planning.',
    `media_rights_zone` STRING COMMENT 'Geographic media rights zone classification for this venue assignment, determining which RSN (Regional Sports Network), OTT (Over-The-Top Streaming), or broadcast network holds distribution rights for events at this venue. Used in broadcast rights management and content distribution.',
    `neutral_site_flag` BOOLEAN COMMENT 'Indicates whether this venue assignment represents a neutral-site event where neither competing team or performer has a home-ground advantage. Common in playoff games, championship events, bowl games, and international fixtures. Affects revenue-sharing, ticketing allocation, and broadcast rights.',
    `parking_capacity` STRING COMMENT 'Total number of parking spaces available at or designated for this venue for this event. Used in fan experience planning, transportation logistics, and ancillary revenue forecasting.',
    `rental_fee_amount` DECIMAL(18,2) COMMENT 'Contracted rental fee payable to the venue operator for hosting this event. Used in event P&L (Profit and Loss) analysis and financial planning in Workday Adaptive Planning. Classified as confidential due to commercial sensitivity.',
    `rental_fee_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the venue rental fee amount (e.g., USD, GBP, EUR). Required for multi-currency financial reporting and SAP S/4HANA FI integration.. Valid values are `^[A-Z]{3}$`',
    `revenue_share_pct` DECIMAL(18,2) COMMENT 'Percentage of event gross revenue contractually shared with the venue operator, covering concessions, parking, and ancillary revenue streams. Used in financial planning and EBITDA (Earnings Before Interest Taxes Depreciation and Amortization) modeling.',
    `scheduled_start_time` TIMESTAMP COMMENT 'Precise scheduled start date and time of the event at this venue, including timezone offset. Used by venue operations for gate opening scheduling, broadcast production (OB unit deployment), and fan communications.',
    `seating_manifest_version` STRING COMMENT 'Version identifier of the seating manifest (kill zones, accessible sections, GA (General Admission) areas, SRO (Standing Room Only) sections) configured in Archtics for this event-venue assignment. Tracks changes to seating layout between events at the same venue.',
    `security_level` STRING COMMENT 'Designated security threat level for this event at this venue, driving staffing levels, screening protocols, and law enforcement coordination. Levels align with internal security classification framework and OSHA venue safety requirements.. Valid values are `standard|elevated|high|critical`',
    `surface_type` STRING COMMENT 'Type of playing surface configured for this event at this venue. Relevant for athlete safety compliance, league regulations (e.g., NFL CBA surface requirements), and broadcast production planning. [ENUM-REF-CANDIDATE: natural_grass|artificial_turf|hardwood|ice|clay|grass|carpet|concrete|synthetic_clay — promote to reference product]',
    `sustainability_certification` STRING COMMENT 'ISO 20121 or equivalent sustainability certification status for this venue assignment, documenting environmental management compliance for the event. Supports ESG (Environmental Social Governance) reporting and league sustainability mandates.',
    `ticketing_system_venue_code` STRING COMMENT 'Venue identifier code as configured in the ticketing platform (Ticketmaster/AXS or Archtics) for this specific event assignment. Used to map seating inventory, price tiers, and access control zones to the correct venue configuration.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this venue assignment record was last modified. Used for change detection, incremental data pipeline processing, and audit trail compliance.',
    `venue_contract_reference` STRING COMMENT 'Reference number of the venue rental or usage contract governing this assignment. Links to the contract management system for financial terms, liability clauses, and cancellation provisions. Classified as confidential due to commercial sensitivity.',
    `vip_hospitality_enabled` BOOLEAN COMMENT 'Indicates whether VIP (Very Important Person) hospitality suites, premium clubs, and sponsor hospitality entitlements are activated for this event at this venue. Triggers hospitality operations preparation and sponsor entitlement fulfillment workflows.',
    `weather_contingency_plan` STRING COMMENT 'Reference identifier or description of the weather contingency plan applicable to this outdoor or partially-covered venue assignment. Includes rain delay protocols, lightning evacuation procedures, and postponement triggers.',
    CONSTRAINT pk_venue_assignment PRIMARY KEY(`venue_assignment_id`)
) COMMENT 'Association entity linking a fixture to its assigned venue, capturing venue confirmation status, primary/alternate venue designation, venue configuration type (full capacity, reduced capacity, neutral site), ADA compliance confirmation, field/court/stage setup type, and assignment change history flag. Enables venue operations domain to prepare facility resources and ticketing domain to configure seating inventory for the specific event.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`competition_round` (
    `competition_round_id` BIGINT COMMENT 'Unique surrogate identifier for a competition round record within the Sports Entertainment data platform. Primary key for the competition_round entity.',
    `calendar_id` BIGINT COMMENT 'Foreign key linking to event.event_calendar. Business justification: competition_round defines the rounds, stages, and phases within a season or tournament. While it already has a cross-domain season_id (league.season), the event_calendar is the event domains SSOT for',
    `conference_id` BIGINT COMMENT 'Foreign key linking to league.conference. Business justification: Competition rounds are scoped to conferences (e.g., AFC Championship Round). Normalizing conference_scope text to a proper FK supports conference-level scheduling reports, standings calculations, and ',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Round-level sponsorship deal management: competition rounds carry a round_sponsor_name (denormalized). Normalizing via deal_id enables fulfillment tracking, broadcast mention compliance, and revenue r',
    `fixture_calendar_id` BIGINT COMMENT 'Foreign key linking to event.fixture_calendar. Business justification: competition_round defines the rounds and phases within a season, and fixture_calendar is the published fixture schedule for that season. A competition_round belongs to a specific fixture_calendar publ',
    `league_id` BIGINT COMMENT 'Reference to the governing league or competition body that owns this round (e.g., NFL, NBA, FIFA, MLS). Enables cross-league reporting and governance.',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Round-level rights compliance: competition rounds are governed by specific media rights deals that determine broadcast windows, blackout rules, and PPV eligibility. Rights compliance teams need round-',
    `playoff_bracket_id` BIGINT COMMENT 'Foreign key linking to league.playoff_bracket. Business justification: Playoff bracket advancement tracking requires linking competition rounds to the specific playoff bracket they belong to. League operations use this for seeding updates, advancement rules enforcement, ',
    `season_id` BIGINT COMMENT 'Reference to the parent season to which this competition round belongs. Links the round to its governing season structure for standings and scheduling.',
    `tournament_id` BIGINT COMMENT 'Reference to the parent tournament to which this competition round belongs. Nullable when the round belongs to a regular season rather than a tournament bracket.',
    `venue_id` BIGINT COMMENT 'Foreign key linking to venue.venue. Business justification: Playoff and tournament round venue assignment is a core scheduling and broadcast operations process. Sports-entertainment operations assign specific venues to competition rounds (e.g., conference fina',
    `actual_end_date` DATE COMMENT 'Actual calendar date on which the last fixture of this round concluded. May differ from scheduled_end_date. Used for post-event reconciliation, standings finalization, and broadcast rights settlement.',
    `actual_start_date` DATE COMMENT 'Actual calendar date on which the first fixture of this round commenced. May differ from scheduled_start_date due to postponements, weather events, or force majeure. Used for post-event reconciliation and compliance reporting.',
    `advancement_rule` STRING COMMENT 'Business rule description governing how teams or athletes advance from this round to the next stage (e.g., Top 2 teams advance, Winner advances to Semi-Final, Best 4 wild card records qualify). Used by bracket progression logic and standings engines.',
    `age_category` STRING COMMENT 'Age group classification for the competition round (e.g., Senior, U23, U21, U18, Masters). Governs eligibility rules and is required for youth and age-restricted competitions.. Valid values are `senior|u23|u21|u18|u17|masters`',
    `broadcast_window_end` TIMESTAMP COMMENT 'End timestamp of the broadcast rights window for this competition round. Marks the expiry of live and near-live broadcast entitlements for OTT, RSN, and linear TV distribution.',
    `broadcast_window_start` TIMESTAMP COMMENT 'Start timestamp of the broadcast rights window for this competition round. Used by Dalet Galaxy and broadcast rights management to schedule OTT, RSN, and linear TV distribution slots.',
    `bye_week_flag` BOOLEAN COMMENT 'Indicates whether this round is designated as a bye week or rest round in which some or all teams do not compete. Common in NFL scheduling. Affects standings calculation and fixture generation logic.',
    `completed_fixture_count` STRING COMMENT 'Number of fixtures within this round that have been fully played and results confirmed. Used to track round completion progress and trigger standings recalculation workflows.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this competition round record was first created in the Sports Entertainment data platform. Used for audit trail, data lineage, and SOX compliance reporting.',
    `external_round_reference` STRING COMMENT 'Identifier for this competition round as assigned by an external governing body or source system (e.g., FIFA round ID, NFL schedule system ID, Ticketmaster event group ID). Used for cross-system reconciliation and API integration.',
    `fixture_count` STRING COMMENT 'Total number of fixtures (matches, games, bouts) scheduled within this competition round. Used for scheduling validation, broadcast slot planning, and venue operations capacity planning.',
    `gender_category` STRING COMMENT 'Gender category of the competition round (e.g., mens, womens, mixed, open). Required for multi-gender leagues and international competitions governed by FIFA, IOC, and ATP standards.. Valid values are `mens|womens|mixed|open`',
    `neutral_venue_flag` BOOLEAN COMMENT 'Indicates whether all fixtures in this round are played at a neutral venue rather than home/away venues (e.g., Super Bowl, FIFA World Cup Final, NBA All-Star Game). Affects ticketing allocation and venue operations planning.',
    `notes` STRING COMMENT 'Free-text operational notes or administrative remarks about this competition round, such as special scheduling considerations, venue exceptions, regulatory waivers, or broadcast anomalies. For internal use by league operations staff.',
    `overtime_rule` STRING COMMENT 'Rule governing how drawn or tied fixtures in this round are resolved beyond regulation time (e.g., extra time followed by penalty shootout in FIFA knockout rounds, overtime period in NHL, shootout in NHL regular season). Affects fixture duration planning and broadcast scheduling.. Valid values are `none|extra_time|golden_goal|penalty_shootout|overtime_period|shootout`',
    `points_for_draw` STRING COMMENT 'Number of competition points awarded to each team for a draw/tie in this round. Typically 1 in soccer/football formats; 0 in elimination formats. Drives standings calculation.',
    `points_for_loss` STRING COMMENT 'Number of competition points awarded to a team or athlete for a loss in this round. Typically 0, but some leagues award 1 point for an overtime/shootout loss (e.g., NHL). Drives standings calculation.',
    `points_for_win` STRING COMMENT 'Number of competition points awarded to a team or athlete for a win in this round. May vary by stage (e.g., 3 points in group stage, not applicable in knockout). Drives standings calculation.',
    `ppv_flag` BOOLEAN COMMENT 'Indicates whether fixtures in this round are distributed as Pay-Per-View (PPV) events rather than included in standard broadcast or subscription packages. Affects revenue recognition and fan access entitlement logic.',
    `round_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the competition round used in scheduling systems, broadcast feeds, and fixture APIs (e.g., NFL-2024-WK01, FIFA-WC-QF1, NBA-2024-R1). Unique within a season or tournament.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `round_name` STRING COMMENT 'Human-readable display name of the competition round as used in broadcast, ticketing, and fan-facing platforms (e.g., Week 1, Matchday 3, Quarter-Final, Wild Card Round, Conference Championship, Super Bowl, Group Stage Round 2).',
    `round_number` STRING COMMENT 'Sequential numeric position of this round within its parent season or tournament (e.g., 1 for Week 1, 3 for Matchday 3). Used for ordering, standings calculation, and bracket progression logic.',
    `round_status` STRING COMMENT 'Current lifecycle state of the competition round. Drives fixture scheduling workflows, standings publication, and broadcast planning. Transitions from scheduled → in_progress → completed, or to postponed/cancelled/suspended for disrupted rounds.. Valid values are `scheduled|in_progress|completed|postponed|cancelled|suspended`',
    `round_type` STRING COMMENT 'Format of competition within this round — whether fixtures are single-leg, two-legged (home and away), best-of series (e.g., NBA Playoffs best-of-7), round-robin, or elimination format. Governs fixture generation and advancement rules.. Valid values are `single_leg|two_leg|best_of_series|round_robin|single_elimination|double_elimination`',
    `scheduled_end_date` DATE COMMENT 'Calendar date on which the last fixture of this competition round is scheduled to conclude. Used for season calendar planning, broadcast rights windows, and standings publication timing.',
    `scheduled_start_date` DATE COMMENT 'Calendar date on which the first fixture of this competition round is scheduled to begin. Used for fixture calendar generation, broadcast scheduling, and fan-facing event listings.',
    `season_ticket_applicable_flag` BOOLEAN COMMENT 'Indicates whether season ticket holders entitlements apply to fixtures in this round. Some playoff or special event rounds may require separate ticket purchases even for season ticket holders.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this competition round record originated (e.g., SAP S/4HANA, Ticketmaster, Salesforce CRM, Dalet Galaxy). Supports data lineage tracking and Silver layer reconciliation in the Databricks Lakehouse. [ENUM-REF-CANDIDATE: SAP_S4HANA|TICKETMASTER|SALESFORCE|SUCCESSFACTORS|DALET|ADOBE_AEP|ARCHTICS|SHOPIFY|WORKDAY|HUDL|MANUAL — 11 candidates stripped; promote to reference product]',
    `sponsorship_activation_flag` BOOLEAN COMMENT 'Indicates whether dedicated sponsorship activations are planned for this competition round (e.g., title sponsorship of a playoff round, naming rights for a championship week). Triggers Salesforce CRM sponsorship workflow.',
    `stage_type` STRING COMMENT 'Classification of the competition stage this round belongs to, distinguishing regular season weeks from playoff brackets, group stages, knockout rounds, and championship finals. Drives standings calculation rules and bracket progression logic. [ENUM-REF-CANDIDATE: regular_season|group_stage|knockout|playoff|final|wildcard|conference_championship|all_star|preseason — promote to reference product]',
    `ticket_sale_end_date` DATE COMMENT 'Date on which ticket sales close for fixtures in this competition round. Used by Ticketmaster/AXS and Archtics to manage inventory cutoff and gate access configuration.',
    `ticket_sale_start_date` DATE COMMENT 'Date on which ticket sales open for fixtures in this competition round. Used by Ticketmaster/AXS and Archtics to configure on-sale windows and dynamic pricing rules.',
    `tiebreaker_rule` STRING COMMENT 'Description of the tiebreaker criteria applied when teams or athletes are level on points or wins at the end of this round (e.g., head-to-head record, goal difference, away goals, points differential). Critical for standings and bracket resolution.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this competition round record was last modified in the Sports Entertainment data platform. Used for change tracking, incremental data loads, and audit compliance.',
    `var_applicable_flag` BOOLEAN COMMENT 'Indicates whether Video Assistant Referee (VAR) technology is in use for fixtures in this competition round. Relevant for FIFA, MLS, and other football competitions. Affects match officiating logistics and broadcast production planning.',
    `wada_testing_required_flag` BOOLEAN COMMENT 'Indicates whether WADA-mandated Performance Enhancing Drug (PED) testing is required for athletes competing in this round. Triggers compliance workflows and athlete notification processes per WADA Anti-Doping Code.',
    CONSTRAINT pk_competition_round PRIMARY KEY(`competition_round_id`)
) COMMENT 'Reference entity defining the rounds, stages, and phases within a season or tournament — Week 1, Matchday 3, Quarter-Final, Semi-Final, Wild Card Round, Conference Championship, Super Bowl, Group Stage, Knockout Round. Captures round name, round number, stage type, parent season or tournament reference, scheduled start/end dates, and number of fixtures in the round. Enables fixture scheduling, standings calculation, and bracket progression logic.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`post_event_report` (
    `post_event_report_id` BIGINT COMMENT 'Unique surrogate identifier for the post-event reconciliation report record in the Silver Layer lakehouse.',
    `after_action_report_id` BIGINT COMMENT 'Foreign key linking to security.after_action_report. Business justification: Post-event report governing body submission and financial reconciliation depend on security after-action report data (incident counts, ejections, arrests, screening throughput). League operations form',
    `asset_id` BIGINT COMMENT 'Foreign key linking to content.asset. Business justification: Post-event reports reference the archived broadcast asset for governing body submission and compliance verification. content_archival_status on post_event_report tracks archival state; a direct FK to ',
    `audience_rating_id` BIGINT COMMENT 'Foreign key linking to broadcast.audience_rating. Business justification: Post-event reporting and rights compliance: post-event reports formally cite official audience measurement records for governing body submissions and rights fee reconciliation. Sports rights contracts',
    `calendar_id` BIGINT COMMENT 'Reference to the parent event fixture for which this post-event report is produced. Links to the event master record.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Post-event financial reconciliation (financial_reconciliation_status) requires mapping event costs to a cost center for period-end close. Finance teams use post-event reports to finalize cost center a',
    `fixture_id` BIGINT COMMENT 'Foreign key linking to event.fixture. Business justification: post_event_report.event_id is a raw/legacy column referencing the specific fixture for which the post-event reconciliation report is produced. The entity description states it captures the official p',
    `game_result_id` BIGINT COMMENT 'Foreign key linking to league.game_result. Business justification: Post-event reports must reference the certified game result for governing body submission, financial reconciliation, and compliance sign-off. League operations require this link to validate that repor',
    `insurance_claim_id` BIGINT COMMENT 'Foreign key linking to legal.insurance_claim. Business justification: Post-event reports documenting incidents, revenue loss, and financial impact are the primary source documents for insurance claims. Risk management teams link post-event reports to active claims for l',
    `notification_campaign_id` BIGINT COMMENT 'Foreign key linking to platform.notification_campaign. Business justification: Post-event report completion triggers fan notification campaigns (final attendance, highlights available, next event promotion). Linking enables audit of which campaign was dispatched per post-event r',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Post-event P&L reporting requires mapping each events financial summary to a profit center. Finance teams use post-event reports to record event-level profitability against profit center targets and ',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Post-event reports are formally submitted to governing bodies as regulatory filings (attendance, financial, safety). governing_body_submission_status and governing_body_reference_number are denormaliz',
    `regulatory_license_id` BIGINT COMMENT 'Foreign key linking to legal.regulatory_license. Business justification: Post-event reports submitted to governing bodies must reference the regulatory license under which the event was conducted. License number is required on governing body submission forms. Compliance of',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Post-event reports contain gross_gate_revenue, merchandise_gross_revenue, and concession_gross_revenue that must be reconciled against revenue stream actuals. Finance teams use this link to close out ',
    `roi_report_id` BIGINT COMMENT 'Foreign key linking to sponsorship.roi_report. Business justification: Post-event financial reconciliation: post_event_report carries sponsorship_fulfillment_status and financial reconciliation fields. Linking to roi_report enables cross-referencing the operational event',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Post-event compliance reporting requires a traceable employee sign-off for governing body submission and internal audit. The existing signoff_official_name is a denormalized text field; replacing it w',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the event was held, used for venue operations reconciliation and facility management reporting.',
    `venue_manifest_id` BIGINT COMMENT 'Foreign key linking to ticketing.venue_manifest. Business justification: post_event_report records capacity_utilization_pct and final_attendance against the venues approved capacity. The venue_manifest version active for that event defines total_sellable_capacity and tota',
    `wbs_element_id` BIGINT COMMENT 'Foreign key linking to finance.wbs_element. Business justification: Post-event financial reconciliation closes out the WBS element created for the fixture. Finance teams use post-event report data (gross revenues, attendance, incident costs) to finalize WBS actuals an',
    `away_team_score` STRING COMMENT 'Final official score of the away/visiting team at the conclusion of the event including any overtime or extra time. Null for non-competitive events such as concerts.',
    `broadcast_channel_count` STRING COMMENT 'Total number of distinct broadcast channels (linear TV, OTT, RSN, IPTV, PPV) on which this event was distributed. Used for media rights compliance and CPM/GRP reporting.',
    `broadcast_viewership_estimate` BIGINT COMMENT 'Estimated total broadcast viewership figure across all distribution channels (linear TV, OTT, IPTV, RSN) for this event. Used for CPM calculations, GRP reporting, and broadcast rights valuation.',
    `capacity_utilization_pct` DECIMAL(18,2) COMMENT 'Final attendance expressed as a percentage of total venue capacity. Key KPI for venue operations, sponsorship fulfillment reporting, and league performance benchmarking.',
    `compliance_checklist_complete` BOOLEAN COMMENT 'Indicates whether all mandatory compliance checklist items (OSHA safety, ADA accessibility, GDPR data handling, PCI-DSS payment processing, WADA anti-doping protocols) have been completed and signed off for this event.',
    `concession_gross_revenue` DECIMAL(18,2) COMMENT 'Total gross food and beverage concession revenue recorded at the event venue via POS systems. Feeds into SAP S/4HANA FI/CO financial reconciliation and venue operations reporting.',
    `content_archival_status` STRING COMMENT 'Status of post-event content archival workflow in Dalet Galaxy Digital Asset Management (DAM) system. Tracks whether broadcast recordings, highlight packages, and UGC have been ingested and archived per DRM and IP rights obligations.. Valid values are `pending|in_progress|archived|failed`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this post-event report record was first created in the system, typically triggered immediately after event conclusion. Supports audit trail and data lineage.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which gross gate revenue and other monetary figures on this report are denominated (e.g., USD, GBP, EUR).. Valid values are `^[A-Z]{3}$`',
    `event_date` DATE COMMENT 'Calendar date on which the live event took place. Used as the principal business event date for financial reconciliation, regulatory submissions, and season calendar alignment.',
    `event_delay_minutes` STRING COMMENT 'Total duration in minutes by which the event start was delayed from the scheduled kick-off/start time. Zero if no delay occurred. Used for broadcast SLA compliance and insurance claims.',
    `event_end_timestamp` TIMESTAMP COMMENT 'Precise date and time the event concluded including any overtime, extra time, or encores. Used for broadcast rights window reconciliation and venue operations closeout.',
    `event_start_timestamp` TIMESTAMP COMMENT 'Precise date and time the event commenced (first whistle, opening act, puck drop, tip-off). Used for broadcast scheduling reconciliation and production debrief.',
    `final_attendance` STRING COMMENT 'Official final attendance figure representing the total number of spectators present at the event, as certified by venue operations and gate scan reconciliation from Ticketmaster/AXS and Archtics systems.',
    `financial_reconciliation_status` STRING COMMENT 'Status of the downstream financial reconciliation process in SAP S/4HANA FI/CO triggered by this post-event report sign-off. Tracks gate revenue, merchandise, and F&B revenue close.. Valid values are `pending|in_progress|reconciled|exception|closed`',
    `governing_body_submission_timestamp` TIMESTAMP COMMENT 'Timestamp when the post-event report was formally submitted to the relevant governing body (e.g., FIFA, NFL League Office, NBA League Office). Null if not yet submitted.',
    `gross_gate_revenue` DECIMAL(18,2) COMMENT 'Total gross revenue collected from ticket sales at the gate for this event, before deductions for taxes, promoter fees, or revenue sharing. Sourced from Ticketmaster/AXS and SAP S/4HANA SD module. Used in financial reconciliation and EBITDA reporting.',
    `home_team_score` STRING COMMENT 'Final official score of the home team at the conclusion of the event including any overtime or extra time. Null for non-competitive events such as concerts.',
    `incident_count` STRING COMMENT 'Total number of security, safety, or operational incidents recorded during the event. Includes crowd management events, medical responses, and facility incidents. Feeds into OSHA compliance reporting and venue safety reviews.',
    `major_incident_flag` BOOLEAN COMMENT 'Indicates whether one or more major incidents (requiring escalation, emergency services, or regulatory notification) occurred during the event. Triggers mandatory OSHA and governing body notification workflows.',
    `merchandise_gross_revenue` DECIMAL(18,2) COMMENT 'Total gross merchandise sales revenue recorded at the event venue (POS and e-commerce via Shopify Plus), before deductions. Feeds into SAP S/4HANA SD and financial reconciliation.',
    `net_gate_revenue` DECIMAL(18,2) COMMENT 'Net gate revenue after deduction of applicable taxes, facility fees, and revenue-sharing obligations per the CBA or league distribution rules. Used in SAP S/4HANA FI/CO financial close.',
    `nps_score` DECIMAL(18,2) COMMENT 'Net Promoter Score (NPS) measured from post-event fan surveys via Adobe Experience Platform, ranging from -100 to +100. Key KPI for fan engagement and experience design benchmarking.',
    `officiating_report_reference` STRING COMMENT 'Reference identifier linking to the official match officiating report (referee report, VAR/TMO review log). Used for competition governance, disciplinary proceedings, and CAS arbitration.',
    `ppv_buys` STRING COMMENT 'Total number of Pay-Per-View (PPV) purchases recorded for this event across all distribution platforms. Applicable for PPV-designated events such as UFC, boxing, and premium sports fixtures.',
    `production_debrief_notes` STRING COMMENT 'Free-text production debrief narrative capturing key operational observations, technical issues, broadcast production notes, and lessons learned from the event. Sourced from Dalet Galaxy broadcast workflow and event operations teams.',
    `report_number` STRING COMMENT 'Externally-known business identifier for the post-event report, formatted as PER-{YYYY}-{NNNNNN}. Used in governing body submissions, regulatory filings, and cross-system references.. Valid values are `^PER-[0-9]{4}-[0-9]{6}$`',
    `report_status` STRING COMMENT 'Current lifecycle state of the post-event report from initial draft through governing body approval and archival. Drives downstream financial reconciliation and content archival workflows.. Valid values are `draft|submitted|under_review|approved|rejected|archived`',
    `report_type` STRING COMMENT 'Classification of the event type for which this report is generated, distinguishing league matches, cup fixtures, concerts, championships, and other live experience categories. [ENUM-REF-CANDIDATE: league_match|cup_fixture|concert|championship|exhibition|playoff|all_star — promote to reference product]',
    `result_summary` STRING COMMENT 'Official final result summary of the event (e.g., final score, match outcome, winner declaration). For sports fixtures: final score line. For concerts: set completion status. Sourced from competition governance records.',
    `signoff_timestamp` TIMESTAMP COMMENT 'Timestamp when the authorized official (e.g., General Manager, Event Director) formally signed off on the completed post-event report, triggering downstream financial reconciliation and regulatory submission workflows.',
    `sponsorship_fulfillment_status` STRING COMMENT 'Status of sponsor contractual obligations fulfillment for this event (e.g., signage display, broadcast integrations, hospitality entitlements). Triggers sponsorship ROI reporting and Salesforce CRM updates.. Valid values are `pending|fulfilled|partially_fulfilled|not_fulfilled|disputed`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this post-event report record. Tracks iterative updates through the review and approval lifecycle.',
    `vip_hospitality_count` STRING COMMENT 'Total number of Very Important Person (VIP) hospitality guests hosted at the event, including sponsor hospitality entitlements and premium suite occupants. Used for sponsorship fulfillment verification.',
    `wada_compliance_status` STRING COMMENT 'Status of World Anti-Doping Agency (WADA) anti-doping testing compliance for this event. Applicable for professional sports fixtures subject to WADA protocols. Null or not_applicable for non-sport events.. Valid values are `not_applicable|compliant|testing_conducted|violation_reported|under_review`',
    `weather_condition_code` STRING COMMENT 'Standardized weather condition code at event time for structured analytics and insurance reporting. Complements the free-text weather summary. [ENUM-REF-CANDIDATE: clear|cloudy|rain|snow|fog|extreme_heat|extreme_cold|storm|indoor — 9 candidates stripped; promote to reference product]',
    `weather_summary` STRING COMMENT 'Narrative summary of weather conditions during the event (e.g., temperature, precipitation, wind). Relevant for outdoor venues, event delay documentation, and insurance claims.',
    CONSTRAINT pk_post_event_report PRIMARY KEY(`post_event_report_id`)
) COMMENT 'Transactional entity capturing the official post-event reconciliation record and formal closure document for each fixture. Includes final attendance figure, gross gate revenue, broadcast viewership estimate, incident summary count, officiating report reference, weather summary, production debrief notes, governing body submission status, report sign-off timestamp, and compliance checklist completion. Triggers downstream financial reconciliation, regulatory submissions (governing body match reports), content archival workflows, and sponsorship fulfillment confirmation.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`weather_contingency` (
    `weather_contingency_id` BIGINT COMMENT 'Unique surrogate identifier for a weather contingency planning record associated with an outdoor or weather-sensitive event.',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: Weather delay broadcast management: weather contingency plans must identify the specific broadcast schedule slot affected for broadcaster notification, delay management, and insurance claims. broadcas',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Weather delay and cancellation decisions in sports-entertainment carry significant liability, insurance, and fan communication consequences. The decision authority must be a traceable named employee (',
    `emergency_response_plan_id` BIGINT COMMENT 'Foreign key linking to security.emergency_response_plan. Business justification: Weather contingency lightning clearance, dome closure decisions, and evacuation triggers are governed by thresholds defined in the emergency response plan. The decision authority for weather delays mu',
    `fixture_id` BIGINT COMMENT 'Reference to the scheduled fixture or live event for which this weather contingency plan applies.',
    `notification_campaign_id` BIGINT COMMENT 'Foreign key linking to platform.notification_campaign. Business justification: Weather contingencies trigger fan notification campaigns (delay alerts, cancellation notices, reschedule announcements). weather_contingency.fan_notification_dispatched confirms a campaign was sent; l',
    `staff_plan_id` BIGINT COMMENT 'Reference to the venue at which the event is scheduled, used to determine applicable weather thresholds and contingency protocols.',
    `venue_id` BIGINT COMMENT 'Reference to the venue at which the event is scheduled, used to determine applicable weather thresholds and contingency protocols.',
    `escalated_weather_contingency_id` BIGINT COMMENT 'Self-referencing FK on weather_contingency (escalated_weather_contingency_id)',
    `actual_delay_duration_minutes` STRING COMMENT 'Actual duration of the weather-related delay in minutes, recorded after the delay is resolved. Used for broadcast SLA reconciliation, insurance claims, and post-event reporting.',
    `broadcast_delay_minutes` STRING COMMENT 'Duration in minutes by which the live broadcast was delayed due to weather contingency. Used for SLA reconciliation with broadcast partners and RSN (Regional Sports Network) agreements.',
    `broadcast_impact_flag` BOOLEAN COMMENT 'Indicates whether the weather contingency event has a material impact on the broadcast schedule, requiring coordination with broadcast partners and network operations.',
    `contingency_decision_timestamp` TIMESTAMP COMMENT 'Date and time at which the formal contingency action decision (delay, suspension, cancellation, etc.) was officially made by the authorized decision-maker.',
    `contingency_notes` STRING COMMENT 'Free-text operational notes capturing additional context about the weather contingency event, including on-site observations, decision rationale, and coordination actions taken.',
    `contingency_reference_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this weather contingency plan record, used in cross-system communications and fan notifications.. Valid values are `^WC-[A-Z0-9]{6,12}$`',
    `contingency_status` STRING COMMENT 'Current lifecycle state of the weather contingency plan: draft (being prepared), active (monitoring in progress), triggered (contingency action invoked), resolved (event proceeded or concluded), cancelled (plan voided).. Valid values are `draft|active|triggered|resolved|cancelled`',
    `contingency_type` STRING COMMENT 'Classification of the contingency action type applicable to this plan: delay (event start pushed), suspension (in-progress event halted), cancellation (event called off), dome_closure (retractable roof closed), venue_change (alternate venue activated), evacuation (fan safety evacuation). [ENUM-REF-CANDIDATE: delay|suspension|cancellation|dome_closure|venue_change|evacuation — promote to reference product if additional types emerge]. Valid values are `delay|suspension|cancellation|dome_closure|venue_change|evacuation`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time at which this weather contingency record was first created in the system, serving as the audit creation trail.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to the estimated_financial_impact_amount field (e.g., USD, GBP, EUR).. Valid values are `^[A-Z]{3}$`',
    `delay_trigger_threshold_minutes` STRING COMMENT 'Minimum delay duration in minutes that constitutes a formal weather delay event, used to distinguish brief holds from reportable delays for broadcast, ticketing, and insurance purposes.',
    `dome_closure_applicable` BOOLEAN COMMENT 'Indicates whether the venue has a retractable roof or dome that can be closed as a weather contingency measure, enabling dome closure as a valid contingency action type.',
    `dome_closure_decision_timestamp` TIMESTAMP COMMENT 'Date and time at which the official decision to close the retractable roof or dome was made. Null if dome closure was not applicable or not invoked.',
    `estimated_financial_impact_amount` DECIMAL(18,2) COMMENT 'Estimated gross financial impact of the weather contingency event in the events operating currency, encompassing lost gate revenue, refunds, broadcast penalties, and operational costs.',
    `fan_communication_channel` STRING COMMENT 'Primary channel used to communicate weather contingency status to fans in attendance and ticket holders (e.g., sms, push_notification, pa_announcement, digital_signage, social_media, email).. Valid values are `sms|push_notification|pa_announcement|digital_signage|social_media|email`',
    `fan_notification_dispatched` BOOLEAN COMMENT 'Indicates whether a fan-facing weather contingency notification has been dispatched through the designated communication channel.',
    `fan_notification_timestamp` TIMESTAMP COMMENT 'Date and time at which the fan-facing weather contingency notification was dispatched. Null if notification has not yet been sent.',
    `forecast_condition` STRING COMMENT 'Textual description of the forecasted weather condition at event time (e.g., Clear, Partly Cloudy, Thunderstorm, Heavy Rain, Blizzard, High Winds).',
    `forecast_lightning_probability_pct` DECIMAL(18,2) COMMENT 'Forecasted probability of lightning activity within the venue radius during the event window, expressed as a percentage (0–100). Lightning is a primary trigger for event suspension under safety protocols.',
    `forecast_precipitation_mm` DECIMAL(18,2) COMMENT 'Forecasted total precipitation accumulation at the venue during the event window, expressed in millimetres.',
    `forecast_retrieved_timestamp` TIMESTAMP COMMENT 'Date and time at which the most recent weather forecast data was retrieved from the forecast provider for this contingency record.',
    `forecast_source` STRING COMMENT 'Name or identifier of the meteorological data provider supplying forecasts for this contingency plan (e.g., AccuWeather, The Weather Company, National Weather Service).',
    `forecast_temperature_c` DECIMAL(18,2) COMMENT 'Forecasted ambient air temperature at the venue at event start time, expressed in degrees Celsius.',
    `forecast_wind_gust_kmh` DECIMAL(18,2) COMMENT 'Forecasted peak wind gust speed at the venue at event time, expressed in kilometres per hour. Gust thresholds may independently trigger contingency actions.',
    `forecast_wind_speed_kmh` DECIMAL(18,2) COMMENT 'Forecasted sustained wind speed at the venue at event time, expressed in kilometres per hour. Used to evaluate structural safety and field-of-play conditions.',
    `governing_body_notification_required` BOOLEAN COMMENT 'Indicates whether the applicable governing body (e.g., FIFA, NFL, NBA, MLB, NHL) must be formally notified of the weather contingency action per competition rules.',
    `governing_body_notified_timestamp` TIMESTAMP COMMENT 'Date and time at which the governing body was formally notified of the weather contingency action. Null if notification is not required or has not yet been sent.',
    `insurance_claim_applicable` BOOLEAN COMMENT 'Indicates whether the weather contingency outcome meets the threshold for filing an event cancellation or weather-related insurance claim.',
    `insurance_claim_reference` STRING COMMENT 'Reference number assigned to the weather-related insurance claim filed with the insurer. Populated only when insurance_claim_applicable is true and a claim has been initiated.',
    `lightning_clearance_minutes` STRING COMMENT 'Required wait time in minutes after the last detected lightning strike before event play or fan re-entry is permitted, per venue safety protocol.',
    `monitoring_start_timestamp` TIMESTAMP COMMENT 'Date and time at which active weather monitoring for this event commenced, typically 72–96 hours before scheduled event start.',
    `plan_version` STRING COMMENT 'Incremental version number of the weather contingency plan, incremented each time the plan is revised prior to or during the event.',
    `precipitation_threshold_mm` DECIMAL(18,2) COMMENT 'Precipitation accumulation threshold in millimetres per hour at or above which field-of-play conditions are deemed unplayable and contingency action is triggered.',
    `refund_policy_applicable` BOOLEAN COMMENT 'Indicates whether the weather contingency outcome triggers the applicable ticket refund or exchange policy per the events terms and conditions.',
    `refund_trigger_condition` STRING COMMENT 'Specific condition under which ticket refunds are triggered for this weather contingency event (e.g., cancellation, delay_exceeds_threshold, postponement, partial_completion).. Valid values are `cancellation|delay_exceeds_threshold|postponement|partial_completion`',
    `reschedule_date` DATE COMMENT 'Proposed or confirmed rescheduled date for the event if the weather contingency results in postponement. Null if cancellation is final or rescheduling has not been determined.',
    `temperature_max_threshold_c` DECIMAL(18,2) COMMENT 'Maximum ambient temperature in degrees Celsius above which event cancellation, suspension, or heat-safety protocols are triggered per governing body or venue safety policy.',
    `temperature_min_threshold_c` DECIMAL(18,2) COMMENT 'Minimum ambient temperature in degrees Celsius below which event cancellation, suspension, or modified operations are triggered per governing body or venue safety policy.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time at which this weather contingency record was most recently modified, supporting audit trail and data lineage requirements.',
    `wind_speed_threshold_kmh` DECIMAL(18,2) COMMENT 'Sustained wind speed threshold in kilometres per hour at or above which event cancellation or suspension is mandated per venue and governing body safety protocols.',
    CONSTRAINT pk_weather_contingency PRIMARY KEY(`weather_contingency_id`)
) COMMENT 'Weather monitoring and contingency planning records for outdoor events — forecast tracking, delay triggers, cancellation thresholds, dome closure decisions, and fan communication protocols.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`broadcast_window` (
    `broadcast_window_id` BIGINT COMMENT 'Unique surrogate identifier for the broadcast window record. Primary key for the event.broadcast_window data product.',
    `production_id` BIGINT COMMENT 'Foreign key linking to broadcast.production. Business justification: Broadcast window-to-production coordination: each event broadcast window must be linked to its broadcast production plan for pre-show/post-show scheduling, crew assignment, and technical setup coordin',
    `broadcast_rights_window_id` BIGINT COMMENT 'Reference to the overarching broadcast rights window agreement under which this fixture broadcast slot is governed. Links to the broadcast.broadcast_rights_window product.',
    `channel_id` BIGINT COMMENT 'Reference to the primary broadcast channel (network or OTT platform) assigned to air this fixture. Links to the broadcast.channel product.',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: Broadcast windows are delivered through specific digital touchpoints (streaming app, web player). Operations need this link for geo-restriction enforcement, DRM policy application, and rights complian',
    `fixture_id` BIGINT COMMENT 'Reference to the fixture (match or live event) that this broadcast window is assigned to. Links the broadcast window to its parent event.',
    `license_permit_id` BIGINT COMMENT 'Foreign key linking to compliance.license_permit. Business justification: Broadcast windows must be backed by valid broadcast licenses and FCC/regulatory permits per territory. broadcast_window has blackout_applicable and drm_policy_code fields. This FK supports broadcast ',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to the media rights deal under which this fixtures broadcast rights are granted.',
    `regulatory_license_id` BIGINT COMMENT 'Foreign key linking to legal.regulatory_license. Business justification: Each broadcast window in a territory must be covered by a valid broadcast regulatory license for that jurisdiction. Broadcast compliance teams verify license coverage per territory/window before trans',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Broadcast windows carry rights_fee_amount representing broadcast revenue. Finance teams map broadcast windows to broadcast revenue streams for rights fee recognition, deferred revenue scheduling, and ',
    `sla_policy_id` BIGINT COMMENT 'Foreign key linking to platform.sla_policy. Business justification: Each broadcast window (live stream) requires a specific platform SLA policy governing uptime, CDN failover, and response times. sla_policy.is_broadcast_critical exists for this purpose; linking enable',
    `split_from_broadcast_window_id` BIGINT COMMENT 'Self-referencing FK on broadcast_window (split_from_broadcast_window_id)',
    `ad_break_count` STRING COMMENT 'Number of scheduled advertising breaks within this broadcast window. Drives ad inventory allocation, CPM (Cost Per Mille) revenue planning, and sponsor activation scheduling.',
    `ad_inventory_seconds` STRING COMMENT 'Total available advertising inventory in seconds within this broadcast window. Used for ad sales, CPM revenue forecasting, and sponsor fulfillment tracking.',
    `alternate_commentary_language_code` STRING COMMENT 'ISO 639-1/639-2 language code for a secondary or alternate commentary track (e.g., Spanish-language feed on an English-primary broadcast). Supports multi-language broadcast packages.. Valid values are `^[a-z]{2,3}$`',
    `blackout_applicable` BOOLEAN COMMENT 'Indicates whether broadcast blackout rules apply to this window in the specified territory. When true, the broadcast.blackout_rule product governs which sub-regions or zip codes are blacked out to protect local ticket sales or competing rights holders.',
    `broadcast_end_timestamp` TIMESTAMP COMMENT 'Expected end time of the broadcast window, including post-match coverage, analysis segments, and sign-off. Used for scheduling adjacent programming and managing broadcast slot duration.',
    `broadcast_format` STRING COMMENT 'Technical broadcast quality format for this window (SD = Standard Definition, HD = High Definition, 4K = Ultra HD, 8K = Super Hi-Vision, VR = Virtual Reality, AR = Augmented Reality). Drives production equipment requirements and CDN delivery specifications.. Valid values are `SD|HD|4K|8K|VR|AR`',
    `broadcast_kickoff_timestamp` TIMESTAMP COMMENT 'The contractually mandated or broadcaster-driven start time for the fixture as required by the broadcast window. May differ from the venue-local scheduled start time due to broadcast scheduling constraints (e.g., network prime-time requirements).',
    `broadcast_rights_region` STRING COMMENT 'The geographic market or territory in which this digital touchpoint is licensed to distribute this fixture. Belongs to the distribution record because the same fixture may have different licensed regions per touchpoint.',
    `commentary_language_code` STRING COMMENT 'ISO 639-1/639-2 language code for the primary commentary track delivered in this broadcast window (e.g., en, es, fr, pt). Determines commentary crew assignment and audio feed routing.. Valid values are `^[a-z]{2,3}$`',
    `confirmation_timestamp` TIMESTAMP COMMENT 'Timestamp when this broadcast window assignment was formally confirmed by the broadcaster and the rights holder. Marks the transition from draft/provisional to confirmed status.',
    `coverage_status` STRING COMMENT 'Operational lifecycle status of this fixtures coverage under this deal. Tracks whether the rights coverage is scheduled, confirmed by both parties, currently live, completed post-broadcast, or under dispute.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this broadcast window record was first created in the system. Audit trail field for data lineage and compliance purposes.',
    `dalet_schedule_reference` STRING COMMENT 'Source system identifier from Dalet Galaxy Media Asset Management and Broadcast Workflow platform for this broadcast window schedule entry. Enables bi-directional reconciliation between the lakehouse and the operational broadcast scheduling system.',
    `digital_streaming_included` BOOLEAN COMMENT 'Indicates whether the broadcast window rights package includes simultaneous or catch-up digital/OTT streaming rights in addition to linear broadcast. Drives DTC and OTT platform activation.',
    `drm_policy_code` STRING COMMENT 'Code referencing the Digital Rights Management (DRM) policy applied to this broadcast window for digital and OTT distribution. Governs content protection, geo-restriction enforcement, and stream encryption requirements.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `exclusivity_type` STRING COMMENT 'Defines whether the rights granted under this deal for this specific fixture are exclusive to the licensee within the territory, or shared with other rights holders. May differ per fixture even within the same deal.',
    `expected_viewership` BIGINT COMMENT 'Projected audience size (number of viewers) for this broadcast window in the specified territory. Used for CPM pricing, sponsor valuation, and rights fee benchmarking. Sourced from historical ratings and audience research.',
    `geo_restriction_applicable` BOOLEAN COMMENT 'Indicates whether geographic blackout or content restriction rules are enforced for this specific fixture-touchpoint combination. Distinct from the touchpoint-level geo_restriction_enabled flag, which is a capability indicator rather than a per-fixture enforcement decision.',
    `highlights_rights_included` BOOLEAN COMMENT 'Indicates whether the broadcast window rights package includes the right to broadcast post-event highlights clips. Relevant for news programs, digital platforms, and social media distribution rights.',
    `is_exclusive` BOOLEAN COMMENT 'Indicates whether this broadcast window grants exclusive rights to the primary broadcaster in the specified territory, preventing simultaneous broadcast by competing networks or platforms.',
    `is_free_to_air` BOOLEAN COMMENT 'Indicates whether this broadcast window is distributed on a free-to-air (FTA) basis, accessible to all viewers without subscription or pay-per-view purchase. Relevant for regulatory compliance in markets with FTA obligations for major sporting events.',
    `is_ppv` BOOLEAN COMMENT 'Indicates whether this broadcast window is distributed as a Pay-Per-View (PPV) event, requiring individual consumer purchase rather than standard subscription or free-to-air access.',
    `kickoff_constraint_reason` STRING COMMENT 'Reason code explaining why the broadcast-driven kickoff time was set, particularly when it differs from the venue-preferred or league-default time. Supports scheduling governance and CBA compliance review. [ENUM-REF-CANDIDATE: broadcaster_prime_time|network_scheduling|rights_agreement|league_mandate|venue_curfew|international_window|other — promote to reference product]',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this broadcast window record was most recently modified. Supports incremental data loading, change detection, and audit trail requirements.',
    `local_kickoff_timestamp` TIMESTAMP COMMENT 'Territory-specific local start time for the broadcast, accounting for the time zone of the target broadcast market. Distinct from the venue-local kickoff and the broadcaster-mandated kickoff timestamp.',
    `local_timezone` STRING COMMENT 'IANA timezone identifier for the target broadcast territory (e.g., America/New_York, Europe/London). Used to derive local broadcast times for scheduling, EPG (Electronic Programme Guide) listings, and fan-facing communications.',
    `notes` STRING COMMENT 'Free-text operational notes for this broadcast window, capturing special production instructions, broadcaster-specific requirements, or scheduling exceptions not captured in structured fields.',
    `platform_rights` STRING COMMENT 'Comma-separated list of platforms (e.g., linear_tv, ott, mobile, ppv) entitled to carry this specific fixture under this deal. Captures the intersection of deal-level platform rights and fixture-level eligibility (e.g., a PPV-eligible fixture activates ppv rights; a non-PPV fixture does not).',
    `post_show_end_timestamp` TIMESTAMP COMMENT 'Scheduled end time for post-match broadcast coverage (interviews, analysis, highlights recap). Defines the full broadcast slot duration for rights and scheduling purposes.',
    `pre_show_start_timestamp` TIMESTAMP COMMENT 'Scheduled start time for pre-match broadcast coverage (warm-up shows, analyst panels, player arrivals). Determines when the broadcast feed must be live ahead of kickoff.',
    `primary_broadcaster_name` STRING COMMENT 'Name of the primary broadcaster or network holding the rights to air this fixture in the assigned territory (e.g., ESPN, Sky Sports, beIN Sports). Operational reference for production coordination and rights management.',
    `production_type` STRING COMMENT 'Classification of the production methodology for this broadcast window. OB Truck = Outside Broadcast (on-site production vehicle); Studio = studio-based production; Remote = remote production from a central facility; Hybrid = combination; Virtual = fully virtual/cloud production.. Valid values are `ob_truck|studio|remote|hybrid|virtual`',
    `rights_fee_allocation` DECIMAL(18,2) COMMENT 'The portion of the total deal value (in USD) allocated to this specific fixture under this media rights deal. Used for per-fixture revenue recognition, reporting, and rights accounting. Belongs to the fixture-deal combination, not to either entity alone.',
    `rights_fee_amount` DECIMAL(18,2) COMMENT 'Contractual rights fee amount payable by the broadcaster for this specific broadcast window assignment. Commercially sensitive financial data used for revenue recognition and rights deal performance tracking.',
    `rights_fee_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the broadcast rights fee amount (e.g., USD, GBP, EUR). Required for multi-currency financial reporting and SAP S/4HANA FI integration.. Valid values are `^[A-Z]{3}$`',
    `schedule_conflict_flag` BOOLEAN COMMENT 'Indicates whether this broadcast window has a detected scheduling conflict with another fixture or broadcast slot on the same channel or in the same territory. Triggers scheduling review workflow.',
    `slot_duration_minutes` STRING COMMENT 'Total allocated broadcast slot duration in minutes, including pre-show, match/event, and post-show coverage. Used for EPG scheduling, ad inventory planning, and broadcaster contractual slot compliance.',
    `sublicense_permitted` BOOLEAN COMMENT 'Indicates whether the primary broadcaster is contractually permitted to sublicense this broadcast window to third-party networks or platforms within the territory. Governs rights chain management and sublicense agreement creation.',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the specific territory in which this media rights deal covers this fixture. A single fixture may have different deals active in different territories simultaneously.',
    `territory_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the primary broadcast territory for this window. Governs rights enforcement, blackout rules, and geo-targeted distribution. Use WLD for worldwide rights.. Valid values are `^[A-Z]{3}$`',
    `territory_region` STRING COMMENT 'Sub-national or multi-country regional designation for the broadcast territory (e.g., Northeast US, Western Europe, APAC). Used when rights are granted at a regional rather than national level, particularly for RSN and international distribution.',
    `window_name` STRING COMMENT 'Human-readable label for this broadcast window assignment (e.g., Sunday Night Football - Week 12, UEFA Champions League Final - Prime Slot). Used in scheduling dashboards and production briefs.',
    `window_reference_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this broadcast window assignment, used for cross-system reconciliation with Dalet Galaxy and broadcast scheduling systems.. Valid values are `^[A-Z0-9_-]{3,40}$`',
    `window_status` STRING COMMENT 'Current lifecycle state of the broadcast window assignment. Drives downstream production scheduling, rights enforcement, and fan communication workflows.. Valid values are `draft|confirmed|live|completed|cancelled|suspended`',
    `window_type` STRING COMMENT 'Classification of the broadcast window by distribution modality. Linear = traditional TV; OTT = Over-The-Top streaming; PPV = Pay-Per-View; RSN = Regional Sports Network; International = cross-border rights slot; Delayed = tape-delay broadcast; Highlights = clip/summary rights only. [ENUM-REF-CANDIDATE: linear|ott|ppv|rsn|international|delayed|highlights — promote to reference product]',
    CONSTRAINT pk_broadcast_window PRIMARY KEY(`broadcast_window_id`)
) COMMENT 'Association entity linking fixtures to their assigned broadcast windows and production requirements — capturing primary broadcaster, kickoff time constraints driven by broadcast, and territory-specific start times.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`attendance_record` (
    `attendance_record_id` BIGINT COMMENT 'Unique surrogate identifier for each official attendance record associated with a completed live sports or entertainment event.',
    `calendar_id` BIGINT COMMENT 'Reference to the fixture or live event for which this attendance record was captured. Links to the event.fixture master record.',
    `capacity_config_id` BIGINT COMMENT 'Foreign key linking to venue.capacity_config. Business justification: Attendance reconciliation and sellout determination require comparing actual attendance against the fire-code-approved capacity configuration active for that event. Regulatory reporting to governing b',
    `fan_profile_id` BIGINT COMMENT 'Foreign key linking this attendance record to the fans golden identity record in fan_profile.',
    `fixture_id` BIGINT COMMENT 'Foreign key linking to event.fixture. Business justification: attendance_record.event_id is a raw/legacy column referencing the specific fixture for which attendance was recorded. Normalizing to fixture_id FK establishes the direct relationship between attendanc',
    `occupancy_snapshot_id` BIGINT COMMENT 'Foreign key linking to security.occupancy_snapshot. Business justification: Attendance reconciliation process compares official ticketing-based attendance_record against security occupancy_snapshot sensor data. Governing body reporting requires formal reconciliation between t',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Attendance records are submitted to governing bodies as mandatory regulatory filings in professional sports leagues. attendance_record has governing_body_reported_flag and governing_body_reference_num',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Attendance records (paid_attendance, tickets_sold) drive gate revenue recognition. Finance teams reconcile attendance actuals against gate revenue stream forecasts and use this link for revenue recogn',
    `season_id` BIGINT COMMENT 'Reference to the league season or competition calendar year in which this event occurred. Supports season-level attendance aggregation and reporting.',
    `venue_id` BIGINT COMMENT 'Reference to the venue at which the event was held. Used to cross-reference approved capacity and seating configuration from venue master data.',
    `venue_manifest_id` BIGINT COMMENT 'Foreign key linking to ticketing.venue_manifest. Business justification: attendance_record reconciles approved_capacity, tickets_sold, and turnstile_count. venue_manifest defines the exact sellable capacity configuration (total_sellable_capacity, total_ada_seat_count, kill',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Attendance verification is a governing body compliance requirement in sports-entertainment; the verifying employee must be traceable for regulatory submission and audit. The existing verified_by plain',
    `amended_attendance_record_id` BIGINT COMMENT 'Self-referencing FK on attendance_record (amended_attendance_record_id)',
    `ada_accessible_attendance` STRING COMMENT 'Number of spectators who entered using ADA-designated accessible seating or accommodation tickets. Required for ADA compliance reporting and venue accessibility audits.',
    `amendment_flag` BOOLEAN COMMENT 'Indicates whether this attendance record has been amended after initial submission, for example following a dispute resolution, scanner recount, or governing body correction request.',
    `amendment_reason` STRING COMMENT 'Description of the reason for amending the attendance record after initial submission. Required for audit trail and governing body compliance when figures are revised post-submission.',
    `amendment_timestamp` TIMESTAMP COMMENT 'Date and time when the most recent amendment to this attendance record was made. Supports audit trail and version history for compliance and dispute resolution.',
    `approved_capacity` STRING COMMENT 'Maximum number of spectators permitted in the venue for this specific event as approved by local authorities and venue management. May differ from total venue capacity due to configuration, ADA requirements, or safety restrictions.',
    `attendance_classification` STRING COMMENT 'Categorical classification of the events attendance performance relative to approved capacity. Used for league benchmarking, sponsor reporting, and broadcast rights valuation. [ENUM-REF-CANDIDATE: sellout|near_sellout|strong|average|below_average|poor — promote to reference product if additional tiers are required]. Valid values are `sellout|near_sellout|strong|average|below_average|poor`',
    `attendance_type` STRING COMMENT 'Classification of how the fan attended the fixture — physically in-venue, via PPV stream, virtual broadcast, hospitality package, or complimentary access. Determines loyalty point multipliers and CRM segmentation.',
    `broadcast_announced_attendance` STRING COMMENT 'Official attendance figure announced during the live broadcast of the event. May differ from the final verified figure due to timing of announcement versus final gate close. Relevant for broadcast compliance and media reporting.',
    `capacity_utilization_pct` DECIMAL(18,2) COMMENT 'Percentage of approved venue capacity represented by the official paid attendance figure. Calculated as (paid_attendance / approved_capacity) * 100. Core KPI for venue operations, sponsorship valuation, and league reporting.',
    `check_in_timestamp` TIMESTAMP COMMENT 'The date and time the fan physically checked in or scanned their ticket at the venue for this fixture. Used for operational reporting, loyalty point triggering, and fan experience analytics.',
    `comp_tickets_used` STRING COMMENT 'Number of complimentary (non-revenue) tickets that were scanned and used for entry. Includes sponsor comps, media credentials, VIP passes, and player/staff allocations.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this attendance record was first created in the system, typically at gates-close or post-event reconciliation initiation.',
    `data_source` STRING COMMENT 'Identifies the primary operational system from which attendance figures were sourced. Supports data lineage, reconciliation, and audit trail requirements. Values: ticketmaster, axs, archtics, manual, combined.. Valid values are `ticketmaster|axs|archtics|manual|combined`',
    `engagement_score` DECIMAL(18,2) COMMENT 'A computed or captured score representing the fans level of engagement during this specific fixture attendance (e.g., app interactions, social shares, in-venue purchases). Belongs to the attendance instance, not the fans overall profile.',
    `event_date` DATE COMMENT 'Calendar date on which the live event took place. Used as the principal business event date for attendance reporting, season scheduling analysis, and regulatory filings.',
    `ga_attendance` STRING COMMENT 'Number of spectators who entered via General Admission (GA) tickets, representing unreserved standing or open seating areas. Relevant for crowd management, safety compliance, and SRO (Standing Room Only) capacity monitoring.',
    `gates_close_timestamp` TIMESTAMP COMMENT 'Date and time at which venue entry gates were officially closed and final turnstile counts were locked. Represents the principal business event timestamp for attendance finalization.',
    `governing_body_reported_flag` BOOLEAN COMMENT 'Indicates whether the official attendance figures for this event have been submitted to the relevant sports governing body (e.g., NFL, NBA, FIFA, NHL, MLS). Required for league compliance and official record-keeping.',
    `governing_body_submission_timestamp` TIMESTAMP COMMENT 'Date and time when the official attendance record was submitted to the relevant sports governing body. Supports compliance audit trails and SLA tracking for post-event reporting obligations.',
    `group_ticket_count` STRING COMMENT 'Number of entries attributed to group ticket sales (typically 10+ tickets sold as a block to organizations, schools, or corporate groups). Supports group sales performance reporting.',
    `loyalty_points_earned` BIGINT COMMENT 'The number of loyalty program points awarded to the fan for attending this specific fixture. Varies by ticket category, attendance type, and event tier. Cannot reside on fan_profile (which holds the running balance) or fixture (which is event-level).',
    `media_credential_count` STRING COMMENT 'Number of credentialed media personnel (press, broadcast, photographers) who accessed the venue for this event. Tracked separately from spectator attendance for accreditation and broadcast compliance.',
    `no_show_count` STRING COMMENT 'Number of tickets sold or issued for which no corresponding entry scan was recorded. Calculated as tickets sold plus comp tickets issued minus turnstile count. Key metric for venue operations and fan engagement analysis.',
    `notes` STRING COMMENT 'Free-text field for operational notes related to this attendance record, such as unusual circumstances, partial venue closures, security incidents affecting entry, or special event configurations that impacted attendance figures.',
    `paid_attendance` STRING COMMENT 'Official count of spectators who entered the venue on a paid ticket basis. This is the primary figure reported to governing bodies and used in official league attendance statistics.',
    `reconciliation_status` STRING COMMENT 'Status of the post-event reconciliation process comparing ticketing system scan counts against box office sales records and comp ticket issuances. Tracks whether figures have been balanced and signed off.. Valid values are `pending|in_progress|reconciled|variance_identified|escalated`',
    `record_reference_code` STRING COMMENT 'Externally-known alphanumeric business identifier for this attendance record, used in official league submissions, governing body filings, and post-event reconciliation reports.. Valid values are `^ATT-[A-Z0-9]{6,20}$`',
    `record_status` STRING COMMENT 'Current lifecycle status of the attendance record. Tracks progression from initial draft capture through governing body verification and final official publication. [ENUM-REF-CANDIDATE: draft|submitted|verified|disputed|final|amended — promote to reference product if additional statuses are required]. Valid values are `draft|submitted|verified|disputed|final|amended`',
    `resale_ticket_count` STRING COMMENT 'Number of entries attributed to tickets purchased through secondary market or official resale channels. Supports secondary market analysis and revenue leakage assessment.',
    `season_ticket_holder_count` STRING COMMENT 'Number of entries attributed to season ticket holders for this event. Used to measure season ticket utilization rates and inform renewal and fan engagement strategies.',
    `seat_section` STRING COMMENT 'The venue section or zone where the fan was seated or stood for this fixture. Belongs to the attendance record, not the fan profile or fixture master, as it varies per attendance instance.',
    `sellout_flag` BOOLEAN COMMENT 'Indicates whether the event achieved a sellout, defined as paid attendance reaching or exceeding 100% of approved capacity. Used in league marketing, broadcast negotiations, and sponsor reporting.',
    `ticket_category` STRING COMMENT 'The commercial category of the ticket used by the fan for this specific fixture. Determines pricing tier, access rights, and loyalty point earn rate for this attendance instance.',
    `ticketing_system_event_code` STRING COMMENT 'Native event identifier from the source ticketing platform (Ticketmaster / AXS or Archtics) used to reconcile attendance figures against ticket sales and access control scan records.',
    `tickets_sold` STRING COMMENT 'Total number of paid tickets sold for the event across all sales channels (box office, online, mobile, resale). Represents the commercial demand figure prior to event day.',
    `turnstile_count` STRING COMMENT 'Actual number of unique ticket scans recorded at venue entry points via access control systems. Represents the physical headcount of spectators who passed through gates, distinct from paid attendance.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this attendance record was most recently modified, such as during amendment, dispute resolution, or governing body verification.',
    `variance_count` STRING COMMENT 'Numerical difference between tickets sold (plus comps issued) and actual turnstile scan count. A non-zero variance triggers reconciliation review. Positive value indicates more tickets issued than scans; negative indicates scan anomalies.',
    `variance_reason` STRING COMMENT 'Free-text or coded explanation for any material variance between tickets issued and turnstile count. Common reasons include scanner malfunction, duplicate scan prevention, late entry, or system outage.',
    `verification_timestamp` TIMESTAMP COMMENT 'Date and time when the attendance figures were officially verified and approved by the designated venue or league official. Marks the transition from submitted to verified status.',
    `vip_attendance` STRING COMMENT 'Number of spectators who entered via VIP hospitality credentials, premium suite access, or club-level passes. Used for premium experience reporting and sponsor hospitality fulfillment tracking.',
    `weather_condition` STRING COMMENT 'Recorded weather condition at the venue during the event. Used to contextualize attendance figures, particularly for outdoor venues where weather materially affects turnout. [ENUM-REF-CANDIDATE: clear|cloudy|rain|heavy_rain|snow|fog|extreme_heat|storm|postponed_weather — promote to reference product]',
    `weather_impact_flag` BOOLEAN COMMENT 'Indicates whether adverse weather conditions were recorded as a contributing factor to attendance shortfall or no-show rates for this event. Supports force majeure analysis and insurance claim documentation.',
    CONSTRAINT pk_attendance_record PRIMARY KEY(`attendance_record_id`)
) COMMENT 'Official attendance figures and capacity utilization records for completed events — paid attendance, actual turnstile count, no-shows, comp tickets used, and capacity percentage.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`pricing` (
    `pricing_id` BIGINT COMMENT 'Unique surrogate identifier for each event pricing configuration record. Primary key for the event_pricing data product.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Ticket pricing approval is a formal revenue governance process in sports-entertainment requiring an auditable employee approval chain. The existing approved_by plain-text field is a denormalized emplo',
    `digital_touchpoint_id` BIGINT COMMENT 'Foreign key linking to platform.digital_touchpoint. Business justification: Event pricing configurations (dynamic pricing, PPV pricing) are applied per digital touchpoint. Revenue teams configure touchpoint-specific pricing tiers and A/B test pricing models per channel. This ',
    `fixture_id` BIGINT COMMENT 'Reference to the specific fixture or live event for which this pricing configuration applies. Links pricing strategy to the event identity master.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Franchise-level ticket pricing authority and revenue reporting require linking event pricing configurations to the home franchise. Franchise revenue sharing calculations and pricing strategy audits de',
    `league_id` BIGINT COMMENT 'Reference to the league or governing competition body associated with this pricing record. Supports league-level pricing rule inheritance and reporting.',
    `ppv_package_id` BIGINT COMMENT 'Foreign key linking to broadcast.ppv_package. Business justification: Integrated PPV pricing strategy: event pricing configurations for PPV fixtures must reference the broadcast PPV package to ensure in-venue and broadcast PPV pricing are coordinated. Revenue management',
    `price_tier_id` BIGINT COMMENT 'Foreign key linking to ticketing.price_tier. Business justification: event_pricing configures pricing for a specific fixture using a price_tier definition (face value, service fee, tax rate). Revenue managers link event_pricing to the applicable price_tier to enforce t',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Ticket pricing configurations feed directly into gate revenue stream forecasting. Finance teams link pricing tiers to revenue streams for dynamic pricing analytics, gate revenue budgeting, and actual-',
    `season_id` BIGINT COMMENT 'Reference to the competitive season or entertainment season under which this pricing configuration is governed. Enables season-level pricing policy aggregation.',
    `tax_jurisdiction_id` BIGINT COMMENT 'Foreign key linking to finance.tax_jurisdiction. Business justification: Ticket sales are subject to entertainment taxes varying by jurisdiction. tax_jurisdiction has ticket_sales_taxable_flag and entertainment_tax_rate_pct specifically for this. Finance teams require this',
    `superseded_pricing_id` BIGINT COMMENT 'Self-referencing FK on pricing (superseded_pricing_id)',
    `approval_timestamp` TIMESTAMP COMMENT 'The date and time at which this pricing configuration was formally approved by the designated authority. Supports SOX audit trail and financial controls documentation.',
    `base_ticket_price` DECIMAL(18,2) COMMENT 'The floor or reference ticket price for this pricing tier before any multipliers, dynamic adjustments, or promotional discounts are applied. Represents the minimum sellable price per seat in this configuration.',
    `config_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this pricing configuration within the ticketing system (e.g., Ticketmaster / AXS or Archtics). Used for cross-system reconciliation and audit.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `config_name` STRING COMMENT 'Human-readable name describing this pricing configuration (e.g., Playoff Tier A Dynamic, Regular Season GA Standard). Used in reporting dashboards and operational communications.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this pricing configuration record was first created in the system. Supports audit trail, data lineage, and GDPR data retention compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to all monetary amounts in this pricing record (e.g., USD, GBP, EUR). Supports multi-market pricing for international events.. Valid values are `^[A-Z]{3}$`',
    `day_of_week` STRING COMMENT 'Day of the week on which the event is scheduled. Day-of-week is a primary demand driver in pricing models — weekend events typically command premium pricing versus midweek fixtures. [ENUM-REF-CANDIDATE: Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday — 7 candidates stripped; promote to reference product]',
    `demand_signal_source` STRING COMMENT 'The system or data source providing real-time demand signals to the dynamic pricing engine. Determines which platforms sales velocity, search interest, or fan engagement data drives price adjustments.. Valid values are `ticketmaster|axs|internal_crm|adobe_aep|manual`',
    `dynamic_pricing_enabled` BOOLEAN COMMENT 'Indicates whether dynamic (demand-based) pricing is activated for this event pricing configuration. When true, the ticketing platform (Ticketmaster / AXS) will algorithmically adjust prices within the base-to-max range based on real-time demand signals.',
    `dynamic_pricing_model` STRING COMMENT 'The algorithmic model type used when dynamic pricing is enabled. Demand-based adjusts on real-time sales velocity; time-based adjusts based on proximity to event date; inventory-based adjusts on remaining seat availability; hybrid combines multiple signals.. Valid values are `demand_based|time_based|inventory_based|hybrid`',
    `early_bird_cutoff_date` DATE COMMENT 'The last date on which early bird pricing is available for this event. Purchases made on or before this date qualify for the early bird discount rate. Supports advance sales revenue recognition strategy.',
    `early_bird_discount_pct` DECIMAL(18,2) COMMENT 'Percentage discount applied to the base ticket price for purchases made on or before the early_bird_cutoff_date. Incentivizes advance ticket purchases to improve cash flow predictability.',
    `event_classification` STRING COMMENT 'Classification of the event type driving the pricing strategy. Playoff and championship events typically carry higher multipliers. Aligns with fixture classification in the event domain.. Valid values are `regular_season|playoff|championship|exhibition|concert|special_event`',
    `facility_fee_amount` DECIMAL(18,2) COMMENT 'Per-ticket facility or venue surcharge applied to support venue operations, maintenance, and ADA compliance improvements. Separate from the base ticket price and service fee.',
    `group_discount_pct` DECIMAL(18,2) COMMENT 'Percentage discount applied to the base ticket price for qualifying group sales purchases. Expressed as a positive value (e.g., 15.00 = 15% discount). Applicable when group_sales_min_qty threshold is met.',
    `group_sales_min_qty` STRING COMMENT 'Minimum number of tickets required to qualify for group sales pricing under this configuration. Group pricing typically offers a discount to incentivize bulk purchases from organizations, schools, and corporate clients.',
    `inventory_allocation_pct` DECIMAL(18,2) COMMENT 'Percentage of total venue capacity allocated to this pricing tier configuration. The sum of all tier allocations for a given fixture should equal 100%. Managed in Archtics seat manifest.',
    `max_ticket_price` DECIMAL(18,2) COMMENT 'The ceiling price for this pricing tier. In dynamic pricing models, the ticket price will not exceed this cap regardless of demand signals. Protects against fan price gouging and reputational risk.',
    `max_tickets_per_transaction` STRING COMMENT 'Maximum number of tickets a single purchaser may buy in one transaction under this pricing configuration. Limits scalping and ensures equitable fan access. Enforced at point of sale in Ticketmaster / AXS.',
    `multiplier` DECIMAL(18,2) COMMENT 'Multiplicative factor applied to the base ticket price to derive the adjusted price for this configuration. A value of 1.0000 represents no adjustment; values above 1.0 represent a premium uplift (e.g., 1.25 = 25% premium for playoff games).',
    `notes` STRING COMMENT 'Free-text field for revenue management staff to document special conditions, exceptions, or contextual rationale for this pricing configuration (e.g., Reduced pricing for community outreach game, Elevated due to international broadcast demand).',
    `off_sale_timestamp` TIMESTAMP COMMENT 'The exact date and time at which ticket sales under this pricing configuration are closed. After this timestamp, no new purchases are permitted at this price tier. Supports inventory management and gate reconciliation.',
    `on_sale_timestamp` TIMESTAMP COMMENT 'The exact date and time at which tickets under this pricing configuration become available for public purchase. Aligns with Ticketmaster / AXS on-sale event scheduling. Critical for fan communications and marketing campaign timing.',
    `ppv_flag` BOOLEAN COMMENT 'Indicates whether this event pricing configuration applies to a Pay-Per-View (PPV) broadcast product rather than (or in addition to) in-venue ticketing. PPV pricing is governed by separate broadcast rights and revenue share agreements.',
    `ppv_price` DECIMAL(18,2) COMMENT 'The consumer-facing price for the Pay-Per-View (PPV) broadcast purchase of this event. Applicable only when ppv_flag is true. Governed by broadcast rights agreements and FCC regulations.',
    `presale_enabled` BOOLEAN COMMENT 'Indicates whether a presale window is activated for this pricing configuration, allowing select fan segments (e.g., CRM loyalty members, credit card holders, season ticket holders) to purchase before the general public on-sale.',
    `presale_end_timestamp` TIMESTAMP COMMENT 'The exact date and time at which the presale window closes. After this timestamp, remaining presale inventory rolls into the general public on-sale pool.',
    `presale_start_timestamp` TIMESTAMP COMMENT 'The exact date and time at which the presale window opens for eligible purchasers. Applicable only when presale_enabled is true. Drives CRM campaign scheduling in Salesforce and Adobe Experience Platform.',
    `price_adjustment_ceiling_pct` DECIMAL(18,2) COMMENT 'Maximum percentage by which the dynamic pricing engine may increase the base ticket price (e.g., 50.00 means prices may rise up to 50% above base). Caps upward price movement to protect fan experience and brand equity.',
    `price_adjustment_floor_pct` DECIMAL(18,2) COMMENT 'Minimum percentage by which the dynamic pricing engine may reduce the base ticket price (expressed as a negative-capable percentage, e.g., -20.00 means prices may drop up to 20% below base). Prevents excessive discounting.',
    `pricing_status` STRING COMMENT 'Current lifecycle status of this pricing configuration. Draft indicates pending approval; Active indicates live and applied to ticket inventory; Suspended indicates temporarily halted; Expired indicates past effective window; Cancelled indicates permanently withdrawn.. Valid values are `draft|active|suspended|expired|cancelled`',
    `pricing_tier` STRING COMMENT 'Categorical tier classification for this pricing configuration. Tiers include General Admission (GA), Standing Room Only (SRO), Standard, Premium, Very Important Person (VIP), and Platinum. Drives seat manifest segmentation in Archtics. [ENUM-REF-CANDIDATE: standard|premium|vip|ga|sro|platinum|hospitality|suite — promote to reference product]. Valid values are `standard|premium|vip|ga|sro|platinum`',
    `revenue_share_pct` DECIMAL(18,2) COMMENT 'Percentage of gross ticket revenue from this pricing tier shared with the venue operator, league, or other contractual revenue-sharing partners. Feeds into SAP S/4HANA CO controlling and financial settlement processes.',
    `rivalry_flag` BOOLEAN COMMENT 'Indicates whether this fixture is designated as a rivalry matchup (e.g., derby, classic, historic rivalry). Rivalry designation typically triggers a positive pricing multiplier uplift in dynamic pricing models.',
    `season_ticket_applicable` BOOLEAN COMMENT 'Indicates whether this event is included in season ticket packages. When true, season ticket holders receive access at their contracted rate rather than the general public pricing tier.',
    `service_fee_amount` DECIMAL(18,2) COMMENT 'Fixed service or convenience fee charged per ticket in addition to the face value price. Represents ticketing platform processing charges passed to the consumer. Governed by PCI-DSS for payment processing.',
    `strategy_type` STRING COMMENT 'The overarching pricing strategy applied to this configuration. Fixed means a static price; Dynamic means algorithmically adjusted; Tiered means structured price bands; Variable means manually adjusted; Promotional means a time-limited discounted offer.. Valid values are `fixed|dynamic|tiered|variable|promotional`',
    `tax_rate_pct` DECIMAL(18,2) COMMENT 'Applicable tax rate percentage applied to ticket sales under this pricing configuration. Varies by jurisdiction and event type. Used for financial reporting and SAP S/4HANA FI tax determination.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time at which this pricing configuration record was most recently modified. Tracks the last change event for audit, reconciliation, and Silver layer incremental processing.',
    CONSTRAINT pk_pricing PRIMARY KEY(`pricing_id`)
) COMMENT 'Event-level pricing strategy and tier configuration linking fixture characteristics (rivalry, playoff, day-of-week) to pricing multipliers and dynamic pricing activation rules.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`event`.`event_type` (
    `event_type_id` BIGINT COMMENT 'Primary key for event_type',
    `parent_event_type_id` BIGINT COMMENT 'Self-referencing FK on event_type (parent_event_type_id)',
    `broadcast_network` STRING COMMENT 'Primary broadcast or streaming network partner for events of this type (e.g., USA Network, FOX, Peacock, WWE Network). Null for non-broadcast events.',
    `event_type_category` STRING COMMENT 'High-level classification of the event type into major business categories (wrestling, concert, live event, pay-per-view, television, digital, other).',
    `event_type_code` STRING COMMENT 'Short alphanumeric code uniquely identifying the event type (e.g., WWE_RAW, SMACKDOWN, WRESTLEMANIA, CONCERT, LIVE_EVENT). Used as a business key for integration and reporting.',
    `content_rating` STRING COMMENT 'Standard content rating classification for events of this type, following broadcast and entertainment industry standards (G, PG, PG-13, TV-14, TV-MA).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this event type record was first created in the system. Used for audit and data lineage tracking.',
    `event_type_description` STRING COMMENT 'Detailed description of the event type, including its purpose, format, and distinguishing characteristics.',
    `effective_end_date` DATE COMMENT 'Date when this event type was retired or discontinued. Null for currently active event types.',
    `effective_start_date` DATE COMMENT 'Date when this event type became active and available for scheduling. Used for historical tracking and lifecycle management.',
    `format` STRING COMMENT 'Delivery format of the event type: live (in-person only), broadcast (televised), streaming (digital platform), or hybrid (multiple channels).',
    `international_distribution` BOOLEAN COMMENT 'Indicates whether events of this type are distributed internationally (true) or are domestic-only (false).',
    `is_broadcast` BOOLEAN COMMENT 'Indicates whether events of this type are broadcast on television or streaming platforms (true) or are live-only (false).',
    `is_pay_per_view` BOOLEAN COMMENT 'Indicates whether events of this type are premium pay-per-view offerings (true) or standard programming (false).',
    `is_ticketed` BOOLEAN COMMENT 'Indicates whether events of this type require ticket sales (true) or are non-ticketed (false, e.g., free digital events).',
    `league_affiliation` STRING COMMENT 'Name of the professional league or brand associated with this event type (e.g., WWE, NXT, AEW). Null for non-league events like concerts.',
    `merchandise_applicable` BOOLEAN COMMENT 'Indicates whether events of this type typically include merchandise sales opportunities (true) or not (false).',
    `event_type_name` STRING COMMENT 'Full human-readable name of the event type (e.g., Monday Night Raw, SmackDown, WrestleMania, Concert, Live Event).',
    `production_complexity` STRING COMMENT 'Relative complexity of production logistics for events of this type: low (minimal setup), medium (standard production), high (advanced staging/effects), premium (flagship events with maximum production value).',
    `recording_required` BOOLEAN COMMENT 'Indicates whether events of this type must be recorded for archive, replay, or content library purposes (true) or are ephemeral live-only experiences (false).',
    `requires_venue` BOOLEAN COMMENT 'Indicates whether events of this type require a physical venue (true) or can be virtual/digital-only (false).',
    `revenue_model` STRING COMMENT 'Primary revenue generation model for events of this type: ticket sales, sponsorship, broadcast rights, merchandise, or hybrid (multiple streams).',
    `season_applicable` BOOLEAN COMMENT 'Indicates whether events of this type are organized into seasons (true) or are standalone/ad-hoc (false).',
    `sort_order` STRING COMMENT 'Numeric value used to control the display order of event types in user interfaces and reports. Lower values appear first.',
    `sponsorship_tier` STRING COMMENT 'Standard sponsorship tier classification for events of this type, indicating the level of sponsor engagement and investment opportunity.',
    `event_type_status` STRING COMMENT 'Current lifecycle status of the event type. Active types are currently in use; inactive types are temporarily suspended; retired types are no longer used; planned types are under development.',
    `target_audience` STRING COMMENT 'Primary demographic or fan segment targeted by events of this type (e.g., family-friendly, adult-oriented, premium subscribers, general public).',
    `tournament_applicable` BOOLEAN COMMENT 'Indicates whether events of this type can be part of tournament brackets or elimination structures (true) or are standalone matches/shows (false).',
    `typical_capacity_range` STRING COMMENT 'Expected audience capacity range for events of this type (e.g., 5000-10000, 15000-20000, 50000+). Used for venue selection and revenue forecasting.',
    `typical_duration_minutes` STRING COMMENT 'Standard or expected duration of events of this type, measured in minutes. Used for scheduling and venue planning.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this event type record was last modified. Used for audit and change tracking.',
    CONSTRAINT pk_event_type PRIMARY KEY(`event_type_id`)
) COMMENT 'Master reference table for event_type. Referenced by event_type_id.';

